// ── INLINE HTML SANITIZER ──────────────────────────────────────
// Zero-dependency sanitizer for AI chat output.
// Strips all tags except the explicit allowlist before dangerouslySetInnerHTML.
const sanitizeHtml = (html) => {
  // Use the browser's own DOM parser — available in all modern browsers
  const doc = new DOMParser().parseFromString(html, "text/html");
  const allowed = { strong: ["style"], em: [], code: ["style"] };
  const clean = (node) => {
    node.childNodes.forEach(child => {
      if (child.nodeType === Node.ELEMENT_NODE) {
        const tag = child.tagName.toLowerCase();
        if (!allowed[tag]) {
          // Replace disallowed element with its text content only
          child.replaceWith(document.createTextNode(child.textContent));
        } else {
          // Strip any attributes not on the allowlist for this tag
          [...child.attributes].forEach(attr => {
            if (!allowed[tag].includes(attr.name)) child.removeAttribute(attr.name);
          });
          clean(child);
        }
      } else if (child.nodeType === Node.ELEMENT_NODE) {
        clean(child);
      }
    });
  };
  clean(doc.body);
  return doc.body.innerHTML;
};

