// Build public URL for firm-assets bucket (bucket is public, no signing needed)
const getFirmAssetUrl = (storagePath) => {
  if (!storagePath) return null;
  // storagePath format: "firm-assets/firmId/logo.png"
  const [bucket, ...rest] = storagePath.split("/");
  return `${SUPABASE_URL}/storage/v1/object/public/${bucket}/${rest.join("/")}`;
};

const sb = {
  getToken() {
    try {
      const raw = localStorage.getItem("ahud_session");
      if(raw){ const parsed=JSON.parse(raw); if(parsed?.access_token) return parsed.access_token; }
    } catch(e){}
    return SUPABASE_ANON_KEY;
  },
  getHeaders() {
    return { "Content-Type":"application/json", "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${this.getToken()}`, "Prefer":"return=representation" };
  },
  handleExpiry(text) {
    try {
      const parsed = JSON.parse(text);
      if(parsed?.message === "JWT expired" || parsed?.code === "PGRST303") {
        localStorage.removeItem("ahud_session");
        // Fire a custom event instead of hard-reloading — lets the UI show a graceful banner
        window.dispatchEvent(new CustomEvent("ahud_session_expired"));
      }
    } catch(e){}
  },
  async get(path) { const r=await fetch(`${SUPABASE_URL}/rest/v1/${path}`,{headers:this.getHeaders()}); if(!r.ok){ const t=await r.text(); this.handleExpiry(t); throw new Error(t); } return r.json(); },
  async uploadFile(bucket, path, file) {
    const r=await fetch(`${SUPABASE_URL}/storage/v1/object/${bucket}/${path}`,{
      method:"POST",
      headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${this.getToken()}`, "Content-Type":file.type },
      body:file
    });
    if(!r.ok) throw new Error(await r.text());
    // Return storage path only — never a public URL (buckets are private)
    return `${bucket}/${path}`;
  },
  async getSignedUrl(storagePath, expiresIn=300) {
    // storagePath format: "bucket-name/path/to/file"
    const [bucket, ...rest] = storagePath.split("/");
    const filePath = rest.join("/");
    const r=await fetch(`${SUPABASE_URL}/storage/v1/object/sign/${bucket}/${filePath}`,{
      method:"POST",
      headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${this.getToken()}`, "Content-Type":"application/json" },
      body:JSON.stringify({ expiresIn })
    });
    if(!r.ok) throw new Error(await r.text());
    const { signedURL } = await r.json();
    return `${SUPABASE_URL}${signedURL}`;
  },
  async post(path,body) { const r=await fetch(`${SUPABASE_URL}/rest/v1/${path}`,{method:"POST",headers:this.getHeaders(),body:JSON.stringify(body)}); if(!r.ok){ const t=await r.text(); this.handleExpiry(t); throw new Error(t); } return r.json(); },
  async patch(path,body) { const r=await fetch(`${SUPABASE_URL}/rest/v1/${path}`,{method:"PATCH",headers:{...this.getHeaders(),"Prefer":"return=representation"},body:JSON.stringify(body)}); if(!r.ok){ const t=await r.text(); this.handleExpiry(t); throw new Error(t); } return r.json(); },
  async del(path) { const r=await fetch(`${SUPABASE_URL}/rest/v1/${path}`,{method:"DELETE",headers:this.getHeaders()}); if(!r.ok){ const t=await r.text(); this.handleExpiry(t); throw new Error(t); } },
};

