  async updateTaskStatus(taskId,status) { const u={status}; if(status==="completed") u.completed_date=new Date().toISOString().split("T")[0]; return sb.patch(`workflow_tasks?id=eq.${taskId}`,u); },
  async updatePhaseField(phaseId,fields) { return sb.patch(`workflow_phases?id=eq.${phaseId}`,fields); },
  async launchWorkflow(payload) {
    // Step 1: Create instance
    const [instance]=await sb.post("workflow_instances",{firm_id:payload.firm_id,template_id:payload.templateId,advisor_name:payload.advisorName,advisor_user_id:payload.advisorUserId||null,start_date:payload.startDate,target_date:payload.targetDate||null,notes:payload.notes||null,aum_millions:payload.aum||null,status:"active",mission_type:payload.missionType||"Advisor Onboarding"});

    // Step 2: Batch insert assigned users + all phases in parallel
    const sortedPhases = payload.phases.slice().sort((a,b)=>a.order-b.order);
    const [phases] = await Promise.all([
      sb.post("workflow_phases", sortedPhases.map((p,i)=>({workflow_instance_id:instance.id,phase_template_id:p.templateId,name:p.name,sequence_order:p.order,status:"not_started",start_date:i===0?payload.startDate:null,auto_start:i===0,sla_days:null,ops_note:null}))),
      payload.assignedUsers?.length ? sb.post("workflow_instance_users", payload.assignedUsers.map(uid=>({workflow_instance_id:instance.id,user_id:uid}))) : Promise.resolve([]),
    ]);

    // Map phase templateId -> created phase id
    const phaseIdMap={};
    sortedPhases.forEach((p,i)=>{ phaseIdMap[p.templateId]=phases[i]?.id; });

    // Step 3: Batch insert all tasks in one call
    const allTaskRows=[];
    const taskMeta=[]; // track templateId + index for dependency wiring
    for(const phaseData of sortedPhases){
      const phaseId=phaseIdMap[phaseData.templateId];
      for(const taskData of (phaseData.tasks||[]).slice().sort((a,b)=>a.order-b.order)){
        taskMeta.push({ templateId:taskData.templateId, dependsOnTemplateId:taskData.dependsOnTemplateId||null, dependsOnTemplateIds:taskData.dependsOnTemplateIds||[] });
        const isPhaseOne = sortedPhases[0]?.templateId === phaseData.templateId;
        const hasNoDeps = !taskData.dependsOnTemplateId && !(taskData.dependsOnTemplateIds||[]).length;
        const initialStatus = isPhaseOne && hasNoDeps ? "ready" : "not_started";
        const initialDueDate = isPhaseOne && hasNoDeps && payload.startDate && taskData.slaDays
          ? addDays(payload.startDate, taskData.slaDays)
          : (taskData.dueDate||null);
        const ownerTypesArr = taskData.ownerTypes || [taskData.ownerType||"ops"];
        allTaskRows.push({workflow_instance_id:instance.id,workflow_phase_id:phaseId,task_template_id:taskData.templateId,name:taskData.name,sequence_order:taskData.order,status:initialStatus,assigned_to:specialistAssignedTo,due_date:initialDueDate,requires_upload:taskData.requiresUpload,advisor_visible:taskData.advisorVisible,owner_type:taskData.ownerType||"ops",owner_types:ownerTypesArr,sla_days:taskData.slaDays??2,notes:taskData.notes||null});
      }
    }
    const createdTasks = await sb.post("workflow_tasks", allTaskRows);

    // Step 4: Wire dependencies — match by task_template_id in response (not array index, order not guaranteed)
    const taskIdMap={};
    createdTasks.forEach(t=>{ if(t.task_template_id) taskIdMap[t.task_template_id]=t.id; });
    const depPatches=[];
    for(const m of taskMeta){
      if(!taskIdMap[m.templateId]) continue;
      const taskId = taskIdMap[m.templateId];
      if(m.dependsOnTemplateId && taskIdMap[m.dependsOnTemplateId]){
        depPatches.push(sb.patch(`workflow_tasks?id=eq.${taskId}`,{depends_on_task_id:taskIdMap[m.dependsOnTemplateId]}));
      }
      const allDepIds = [...new Set([...(m.dependsOnTemplateIds||[]),...(m.dependsOnTemplateId?[m.dependsOnTemplateId]:[])])].filter(tid=>taskIdMap[tid]);
      for(const depTemplateId of allDepIds){
        depPatches.push(sb.post("workflow_task_dependencies",{ task_id:taskId, depends_on_id:taskIdMap[depTemplateId] }).catch(()=>{}));
      }
    }
    if(depPatches.length) await Promise.all(depPatches);

    return instance;
  },
