const fmtDate = (d) => { if(!d) return "—"; const dt=new Date(d.includes("T")?d:d+"T12:00:00"); return isNaN(dt)?d:dt.toLocaleDateString("en-US",{month:"short",day:"numeric"}); };
const fmtDateFull = (d) => { if(!d) return "—"; return new Date(d+"T12:00:00").toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}); };
const addDays = (dateStr,days) => { const d=new Date(dateStr+"T12:00:00"); d.setDate(d.getDate()+days); return d.toISOString().split("T")[0]; };
const calcPct = (tasks) => { if(!tasks?.length) return 0; return Math.round(tasks.filter(t=>t.status==="completed").length/tasks.length*100); };
const isOverdue = (t) => { if(!t.due_date||t.status==="completed") return false; return new Date(t.due_date)<new Date(); };
const normalizeInstance = (raw) => ({
  ...raw,
  mission_type: raw.mission_type || raw.template_mission_type || "advisor_onboarding",
  assignedUsers:(raw.workflow_instance_users||[]).map(x=>x.user_id),
  phases:(raw.workflow_phases||[]).sort((a,b)=>a.sequence_order-b.sequence_order).map(p=>({
    ...p, tasks:(p.workflow_tasks||[]).sort((a,b)=>a.sequence_order-b.sequence_order).map(t=>({...t,files:t.task_files||[],template_forms:t.template_forms||[]}))
  }))
});

// Build a flat map of task_template_id → {description, template_forms, required_form_id} for quick lookup
const buildTemplateTaskMap = (templates) => {
  const map = {};
  for(const tmpl of (templates||[])){
    for(const phase of (tmpl.phase_templates||[])){
      for(const task of (phase.task_templates||[])){
        map[task.id] = { description: task.description||null, template_forms: task.task_template_forms||[], required_form_id: task.required_form_id||null };
      }
    }
  }
  return map;
};

// Stamp template-sourced description + forms + required_form_id onto live task objects
const enrichInstancesWithTemplates = (instances, templates) => {
  const tmap = buildTemplateTaskMap(templates);
  return instances.map(inst=>({
    ...inst,
    phases: inst.phases.map(p=>({
      ...p,
      tasks: p.tasks.map(t=>{
        const td = t.task_template_id ? (tmap[t.task_template_id]||{}) : {};
        return { ...t, template_description: td.description||null, template_forms: td.template_forms||t.template_forms||[], required_form_id: td.required_form_id||t.required_form_id||null };
      })
    }))
  }));
};

