// firmRoleConfigs: array from firm_role_configs table, loaded at app start
// Falls back to DEFAULT_ROLE_SCREENS if firm hasn't configured roles
const getNav = (role, features = {}, firmRoleConfigs = []) => {
  // Find firm-specific config for this role
  const firmConfig = firmRoleConfigs.find(c => c.role_key === role);
  const permittedScreens = firmConfig
    ? firmConfig.permitted_screens
    : (DEFAULT_ROLE_SCREENS[role] || DEFAULT_ROLE_SCREENS.ops);

  // Super admin always gets everything regardless of config
  if (role === "super_admin") {
    return ALL_NAV_ITEMS;
  }

  // Filter ALL_NAV_ITEMS to permitted screens, preserving order
  return ALL_NAV_ITEMS.filter(item => permittedScreens.includes(item.id));
};

