// ── SOUND ENGINE (optional) ────────────────────────────────────
const useSoundEnabled = () => {
  // Default on; persist preference to localStorage
  const [on, setOn] = useState(() => {
    try { const v = localStorage.getItem("ahud_sound"); return v === null ? true : v === "1"; }
    catch(e) { return true; }
  });
  const setOnPersist = useCallback((v) => {
    setOn(v);
    try { localStorage.setItem("ahud_sound", v ? "1" : "0"); } catch(e){}
  }, []);
  const play = useCallback((type) => {
    if (!on) return;
    try {
      const ctx = new (window.AudioContext||window.webkitAudioContext)();
      const o = ctx.createOscillator();
      const g = ctx.createGain();
      o.connect(g); g.connect(ctx.destination);
      if (type==="task") { o.frequency.setValueAtTime(880,ctx.currentTime); o.frequency.exponentialRampToValueAtTime(1320,ctx.currentTime+0.12); g.gain.setValueAtTime(0.08,ctx.currentTime); g.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+0.3); }
      else if (type==="phase") { o.frequency.setValueAtTime(660,ctx.currentTime); o.frequency.exponentialRampToValueAtTime(990,ctx.currentTime+0.2); g.gain.setValueAtTime(0.12,ctx.currentTime); g.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+0.5); }
      else if (type==="mission") { o.frequency.setValueAtTime(440,ctx.currentTime); o.frequency.exponentialRampToValueAtTime(880,ctx.currentTime+0.4); g.gain.setValueAtTime(0.15,ctx.currentTime); g.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+1.2); }
      o.start(); o.stop(ctx.currentTime+1.5);
    } catch(e){}
  },[on]);
  return { on, setOn: setOnPersist, play };
};

