// ── SUPPORT SYSTEM ─────────────────────────────────────────────

const TICKET_STATUSES = {
  submitted:          { label:"SUBMITTED",          color:"#60a5fa", bg:"#60a5fa18" },
  under_review:       { label:"UNDER REVIEW",       color:"#e09d3a", bg:"#e09d3a18" },
  in_progress:        { label:"IN PROGRESS",        color:"#c084fc", bg:"#c084fc18" },
  no_action_required: { label:"NO ACTION REQUIRED", color:"#6b7280", bg:"#6b728018" },
  duplicate:          { label:"DUPLICATE",          color:"#6b7280", bg:"#6b728018" },
  released:           { label:"RELEASED",           color:"#3dba7a", bg:"#3dba7a18" },
};

const SEVERITY_META = {
  low:      { label:"LOW",      color:"#60a5fa", glow:"#60a5fa22", icon:"◌" },
  medium:   { label:"MEDIUM",   color:"#e09d3a", glow:"#e09d3a22", icon:"◈" },
  high:     { label:"HIGH",     color:"#f97316", glow:"#f9731622", icon:"⚑" },
  critical: { label:"CRITICAL", color:"#d44f42", glow:"#d44f4222", icon:"⚠" },
};

const TICKET_MODULES = ["AWACS", "Audit Log", "Briefing", "CRM", "Dev Channel", "Firm Scorecard", "HUD Intelligence", "Jump Inbox", "Onboarding", "Projects", "Queue", "Requests", "Support", "Templates", "User Management", "Vault", "Other"];

const VIEW_TO_MODULE = {
  awacs:         "AWACS",
  missions:      "Onboarding",
  requests:      "Requests",
  queue:         "Queue",
  vault:         "Vault",
  guide:         "HUD Guide",
  templates:     "Templates",
  users:         "User Management",
  projects:      "Projects",
  jump:          "Jump Inbox",
  audit:         "Audit Log",
  executive:     "Firm Scorecard",
  ai:            "HUD Intelligence",
  briefing:      "Briefing",
  crm:           "CRM",
  support:       "Support",
  admin_support: "Support",
  dev_channel:   "Dev Channel",
};

const SEVERITY_KEYWORDS = {
  critical: ["crash","lost","deleted","missing data","can't login","data loss","gone","disappeared","corrupt","broke everything"],
  high:     ["broken","can't","cannot","doesn't work","won't","fails","error","blank","frozen","stuck","not loading","wrong data"],
  medium:   ["slow","weird","incorrect","unexpected","strange","not showing","missing","off","glitch"],
  low:      ["suggestion","would be nice","could","maybe","minor","cosmetic","typo","slight"],
};

const detectSeverity = (text) => {
  const lower = text.toLowerCase();
  for(const [sev, words] of Object.entries(SEVERITY_KEYWORDS)){
    if(words.some(w => lower.includes(w))) return sev;
  }
  return null;
};

const detectType = (text) => {
  const lower = text.toLowerCase();
  // Only multi-word unambiguous phrases — avoids false positives on common words
  const enhancementPhrases = ["would be nice","would be great","feature request","please add","could we add","can we add","enhancement request","new feature","it would help","suggestion:","requesting a"];
  if(enhancementPhrases.some(w => lower.includes(w))) return "enhancement";
  return null;
};

// Global breadcrumb buffer — records last 8 significant user actions
const breadcrumbBuffer = { items: [] };
const pushBreadcrumb = (action, detail="") => {
  breadcrumbBuffer.items.push({
    time: new Date().toLocaleTimeString("en-US",{hour12:false}),
    action,
    detail: detail.length > 60 ? detail.slice(0,60)+"…" : detail,
  });
  if(breadcrumbBuffer.items.length > 8) breadcrumbBuffer.items.shift();
};

// ── SEVERITY SELECTOR ─────────────────────────────────────────
const SeveritySelector = ({ value, onChange, autoSuggested }) => {
  const levels = ["low","medium","high","critical"];
  return (
    <div>
      <div style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", ...MONO, fontWeight:700, marginBottom:6 }}>
        SEVERITY {autoSuggested && <span style={{ color:SEVERITY_META[value]?.color, marginLeft:6 }}>— AUTO-DETECTED</span>}
      </div>
      <div style={{ display:"flex", gap:0, border:`1px solid ${T.border2}`, overflow:"hidden" }}>
        {levels.map((lvl,i) => {
          const meta = SEVERITY_META[lvl];
          const active = value === lvl;
          return (
            <button key={lvl} onClick={() => onChange(lvl)}
              style={{
                flex:1, padding:"7px 4px", border:"none",
                borderRight: i < levels.length-1 ? `1px solid ${T.border2}` : "none",
                background: active ? meta.glow : "transparent",
                color: active ? meta.color : T.text3,
                cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight: active ? 700 : 400,
                letterSpacing:"0.08em", transition:"all 0.15s",
                boxShadow: active ? `inset 0 0 0 1px ${meta.color}44` : "none",
              }}
              onMouseEnter={e=>{ if(!active){ e.currentTarget.style.background=meta.glow; e.currentTarget.style.color=meta.color; }}}
              onMouseLeave={e=>{ if(!active){ e.currentTarget.style.background="transparent"; e.currentTarget.style.color=T.text3; }}}>
              <div style={{ fontSize:11, marginBottom:1 }}>{meta.icon}</div>
              {meta.label}
            </button>
          );
        })}
      </div>
    </div>
  );
};

// ── BUG REPORT MODAL ──────────────────────────────────────────
const BugReportModal = ({ currentUser, users, currentView, onClose, onSubmitted, firmId }) => {
  const [type, setType]           = useState("bug");
  const [userPickedType, setUserPickedType] = useState(false);
  const [title, setTitle]         = useState("");
  const [description, setDesc]    = useState("");
  const [steps, setSteps]         = useState("");
  const [severity, setSeverity]   = useState("medium");
  const [autoSev, setAutoSev]     = useState(false);
  const [module, setModule]       = useState(VIEW_TO_MODULE[currentView?.toLowerCase()] || "Other");
  const [files, setFiles]         = useState([]);
  const [screenshot, setScreenshot] = useState(null);
  const [screenshotting, setScreenshotting] = useState(false);
  const [duplicates, setDuplicates] = useState([]);
  const [saving, setSaving]       = useState(false);
  const [step, setStep]           = useState("form"); // "form" | "duplicates" | "done"
  const fileRef = useRef();
  const [showContext, setShowContext] = useState(false);
  // Drag state
  const [pos, setPos] = useState(null); // null = default anchor, {x,y} = dragged
  const dragRef = useRef({ dragging:false, startX:0, startY:0, origX:0, origY:0 });
  const modalRef = useRef();

  const onDragStart = (e) => {
    if(e.button !== 0) return;
    const rect = modalRef.current?.getBoundingClientRect();
    if(!rect) return;
    dragRef.current = { dragging:true, startX:e.clientX, startY:e.clientY, origX:rect.left, origY:rect.top };
    const onMove = (e) => {
      if(!dragRef.current.dragging) return;
      const dx = e.clientX - dragRef.current.startX;
      const dy = e.clientY - dragRef.current.startY;
      setPos({ x: dragRef.current.origX + dx, y: dragRef.current.origY + dy });
    };
    const onUp = () => {
      dragRef.current.dragging = false;
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    e.preventDefault();
  };

  // Auto-capture screenshot on mount — hide modal first so it doesn't cover the app
  useEffect(() => {
    const capture = async () => {
      setScreenshotting(true);
      try {
        const html2canvas = (await import("https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.esm.min.js").catch(()=>null))?.default;
        if(!html2canvas) return;
        // Hide all floating UI (modal, devchat, etc.) before capture
        const floaters = document.querySelectorAll("[data-devchat-ui], [data-modal-ui]");
        floaters.forEach(el => { el.style.visibility = "hidden"; });
        if(modalRef.current) modalRef.current.style.visibility = "hidden";
        await new Promise(r => setTimeout(r, 80)); // let paint flush
        const canvas = await html2canvas(document.body, { scale:0.6, useCORS:true, logging:false, backgroundColor:"#0a0c0f" });
        canvas.toBlob(blob => { if(blob) setScreenshot(blob); }, "image/png", 0.8);
        if(modalRef.current) modalRef.current.style.visibility = "";
        floaters.forEach(el => { el.style.visibility = ""; });
      } catch(e){ /* non-critical */ }
      finally{ setScreenshotting(false); }
    };
    capture();
  }, []);

  // Real-time severity + type auto-detection
  useEffect(() => {
    const text = title + " " + description;
    if(text.trim().length < 8) return;
    const suggestedSev = detectSeverity(text);
    if(suggestedSev && suggestedSev !== severity){ setSeverity(suggestedSev); setAutoSev(true); }
    if (!userPickedType) {
      const suggestedType = detectType(text);
      if(suggestedType && suggestedType !== type) setType(suggestedType);
    }
  }, [title, description]);

  // Duplicate detection
  useEffect(() => {
    if(title.length < 20) { setDuplicates([]); return; }
    const check = async () => {
      try {
        const tickets = await api.getTickets();
        const words = title.toLowerCase().split(/\s+/).filter(w=>w.length>4);
        if(words.length < 2) { setDuplicates([]); return; }
        const matches = (tickets||[]).filter(t =>
          t.status !== "released" &&
          words.filter(w => t.title?.toLowerCase().includes(w)).length >= 2
        ).slice(0,3);
        setDuplicates(matches);
      } catch(e){}
    };
    const timer = setTimeout(check, 800);
    return () => clearTimeout(timer);
  }, [title]);

  const handleSubmit = async () => {
    if(!title.trim()) return;
    setSaving(true);
    try {
      const browserInfo = `${navigator.userAgent.split(")")[0].split("(")[1]||navigator.userAgent}`;
      const viewportInfo = `${window.innerWidth}x${window.innerHeight}`;
      const [ticket] = await api.createTicket({
        firm_id: firmId,
        submitted_by: currentUser.id,
        ticket_type: type,
        severity,
        affected_module: module,
        title: title.trim(),
        description: description.trim()||null,
        steps_to_reproduce: steps.trim()||null,
        app_version: APP_VERSION,
        current_view: currentView||null,
        browser_info: browserInfo,
        viewport_info: viewportInfo,
        breadcrumbs: breadcrumbBuffer.items.length > 0 ? breadcrumbBuffer.items : null,
      });

      // Upload auto-screenshot
      if(screenshot && ticket){
        try {
          const url = await api.uploadSupportFile(currentUser.id, "screenshot.png", screenshot);
          await api.createTicketAttachment({ ticket_id:ticket.id, uploaded_by:currentUser.id, file_name:"Auto Screenshot", file_url:url, is_screenshot:true });
        } catch(e){}
      }
      // Upload additional files
      for(const f of files){
        try {
          const url = await api.uploadSupportFile(currentUser.id, f.name, f);
          await api.createTicketAttachment({ ticket_id:ticket.id, uploaded_by:currentUser.id, file_name:f.name, file_url:url, is_screenshot:false });
        } catch(e){}
      }
      // Notify super admins
      const admins = users.filter(u=>u.is_super_admin && u.id!==currentUser.id);
      for(const a of admins){
        await api.createNotification({ user_id:a.id, type:"new_ticket", body:`${currentUser.name} submitted a ${type}: "${title.trim()}"`, link_type:"support", link_id:ticket.id }).catch(()=>{});
      }
      // Reset form for next report — stay open so user can file more
      setTitle(""); setDesc(""); setSteps(""); setSeverity("medium"); setAutoSev(false);
      setFiles([]); setScreenshot(null); setDuplicates([]); setUserPickedType(false);
      setModule(VIEW_TO_MODULE[currentView?.toLowerCase()] || "Other");
      setStep("submitted_flash");
      setTimeout(() => setStep("form"), 3000);
      if(onSubmitted) onSubmitted(ticket);
    } catch(e){ alert("Submission failed: "+e.message); }
    finally{ setSaving(false); }
  };

  const inputS = { background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"7px 10px", fontSize:SZ.body, outline:"none", width:"100%", boxSizing:"border-box", ...RAJDHANI };
  const labelS = { fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", ...MONO, fontWeight:700, marginBottom:5, display:"block" };

  // No full-page done screen — form stays open with an inline flash banner

  const _isMobile = typeof window !== "undefined" && window.innerWidth < 768;
  const modalStyle = pos
    ? { position:"fixed", left:pos.x, top:pos.y, width: _isMobile ? "100%" : 480, maxHeight:"92vh" }
    : _isMobile
      ? { position:"fixed", left:0, right:0, bottom:60, height:"80vh" }
      : { position:"fixed", right:0, bottom:0, width:480, height:"92vh" };

  return (
    <div style={{ position:"fixed", inset:0, zIndex:9998, pointerEvents:"none" }}>
      <div ref={modalRef} data-modal-ui onClick={e=>e.stopPropagation()}
        style={{ ...modalStyle, background:T.bg1, border:`1px solid ${T.border2}`, borderBottom: pos?"1px solid "+T.border2:"none",
          display:"flex", flexDirection:"column", pointerEvents:"all",
          clipPath:"polygon(0 0,calc(100% - 12px) 0,100% 12px,100% 100%,0 100%)",
          animation: pos ? "none" : "slideUpIn 0.2s ease-out" }}>
        <style>{`@keyframes slideUpIn{from{transform:translateY(30px);opacity:0}to{transform:translateY(0);opacity:1}}`}</style>

        {/* Header — drag handle */}
        <div onMouseDown={onDragStart} style={{ padding:"14px 18px 12px", borderBottom:`1px solid ${T.border1}`, flexShrink:0, cursor:"grab", userSelect:"none" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
            <div style={{ display:"flex", alignItems:"center", gap:8 }}>
              <span style={{ fontSize:16, color:T.blue }}>⚑</span>
              <span style={{ fontSize:SZ.body, fontWeight:700, color:T.text0, ...MONO, letterSpacing:"0.08em" }}>REPORT AN ISSUE</span>
              <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, opacity:0.5 }}>⠿ DRAG</span>
            </div>
            <button onClick={onClose} onMouseDown={e=>e.stopPropagation()} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:SZ.sub }}>✕</button>
          </div>
          {/* Type toggle */}
          <div style={{ display:"flex", gap:0, marginTop:10, border:`1px solid ${T.border2}`, overflow:"hidden" }}>
            {[["bug","⚠ BUG REPORT"],["enhancement","◈ ENHANCEMENT"]].map(([t,lbl])=>(
              <button key={t} onClick={()=>{ setType(t); setUserPickedType(true); }}
                style={{ flex:1, padding:"6px", background:type===t?(t==="bug"?`${T.red}18`:T.blueGlow):"transparent",
                  border:"none", borderRight:t==="bug"?`1px solid ${T.border2}`:"none",
                  color:type===t?(t==="bug"?T.red:T.blue):T.text3,
                  cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:type===t?700:400, letterSpacing:"0.08em", transition:"all 0.1s" }}>
                {lbl}
              </button>
            ))}
          </div>
        </div>

        {/* Body */}
        <div style={{ flex:1, overflowY:"auto", padding:"14px 18px", display:"flex", flexDirection:"column", gap:12 }}>

          {/* Submitted flash banner */}
          {step === "submitted_flash" && (
            <div style={{ background:T.greenDim, border:`1px solid ${T.green}44`, padding:"10px 14px", display:"flex", alignItems:"center", gap:10 }}>
              <span style={{ color:T.green, fontSize:16 }}>◈</span>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:SZ.small, fontWeight:700, color:T.green, ...MONO }}>SUBMITTED — form cleared for next report</div>
              </div>
            </div>
          )}

          {/* Screenshot controls */}
          <div style={{ display:"flex", gap:6, alignItems:"center" }}>
            <div style={{ display:"flex", gap:5, fontSize:SZ.micro, color:T.text3, ...MONO, alignItems:"center", flex:1 }}>
              <span style={{ color:screenshot?T.green:screenshotting?T.amber:T.text3 }}>{screenshot?"◉":screenshotting?"◌":"○"}</span>
              <span>{screenshot?"Screenshot ready — or capture a region below":"Capturing full screenshot…"}</span>
            </div>
            <button
              onClick={async()=>{
                setScreenshotting(true);
                try { await triggerRegionCapture((blob)=>{ setScreenshot(blob); }); }
                catch(e){}
                finally{ setScreenshotting(false); }
              }}
              disabled={screenshotting}
              title="Click and drag to capture a specific region of the screen"
              style={{ padding:"3px 10px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, cursor:"pointer", fontSize:SZ.micro, ...MONO, flexShrink:0, transition:"all 0.1s" }}
              onMouseDown={e=>e.stopPropagation()}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border2;e.currentTarget.style.color=T.text2;}}>
              ⊡ CAPTURE REGION
            </button>
          </div>

          {/* Title */}
          <div>
            <label style={labelS}>TITLE *</label>
            <input value={title} onChange={e=>setTitle(e.target.value)} placeholder={type==="bug"?"Briefly describe what's broken…":"Describe the enhancement…"} style={inputS} autoFocus/>
          </div>

          {/* Duplicate warning */}
          {duplicates.length > 0 && (
            <div style={{ background:`${T.amber}10`, border:`1px solid ${T.amber}44`, padding:"8px 10px" }}>
              <div style={{ fontSize:SZ.micro, color:T.amber, ...MONO, fontWeight:700, marginBottom:5 }}>⚠ SIMILAR REPORTS EXIST — IS THIS A DUPLICATE?</div>
              {duplicates.map(d=>(
                <div key={d.id} style={{ display:"flex", gap:6, alignItems:"center", marginBottom:3 }}>
                  <span style={{ fontSize:SZ.micro, color:TICKET_STATUSES[d.status]?.color, ...MONO }}>{TICKET_STATUSES[d.status]?.label}</span>
                  <span style={{ fontSize:SZ.small, color:T.text2 }}>{d.title}</span>
                </div>
              ))}
            </div>
          )}

          {/* Severity */}
          <SeveritySelector value={severity} onChange={v=>{setSeverity(v);setAutoSev(false);}} autoSuggested={autoSev}/>

          {/* Module */}
          <div>
            <label style={labelS}>AFFECTED AREA</label>
            <select value={module} onChange={e=>setModule(e.target.value)} style={{...inputS}}>
              {TICKET_MODULES.map(m=><option key={m}>{m}</option>)}
            </select>
          </div>

          {/* Description */}
          <div>
            <label style={labelS}>DESCRIPTION</label>
            <textarea value={description} onChange={e=>setDesc(e.target.value)}
              placeholder={type==="bug"?"What were you doing? What happened vs. what you expected?":"Describe the feature and how it would help the team…"}
              rows={3} style={{...inputS, resize:"vertical", lineHeight:1.5}}/>
          </div>

          {/* Steps (bugs only) */}
          {type === "bug" && (
            <div>
              <label style={labelS}>STEPS TO REPRODUCE <span style={{color:T.text3,fontWeight:400}}>— optional</span></label>
              <textarea value={steps} onChange={e=>setSteps(e.target.value)}
                placeholder={"1. Go to Onboarding\n2. Click on a mission\n3. Change task status to…"}
                rows={3} style={{...inputS, resize:"vertical", lineHeight:1.5, fontFamily:"'JetBrains Mono',monospace", fontSize:SZ.small}}/>
            </div>
          )}

          {/* Auto-captured context — collapsible, labelled clearly */}
          <div style={{ background:T.bg2, border:`1px solid ${T.border1}` }}>
            <button onClick={()=>setShowContext(v=>!v)}
              style={{ width:"100%", display:"flex", alignItems:"center", justifyContent:"space-between", padding:"7px 10px", background:"none", border:"none", cursor:"pointer", textAlign:"left" }}>
              <div style={{ display:"flex", alignItems:"center", gap:7 }}>
                <span style={{ color:T.green, fontSize:SZ.micro }}>◈</span>
                <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em" }}>AUTO-CONTEXT ATTACHED</span>
                <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, opacity:0.6 }}>— browser, view, recent navigation</span>
              </div>
              <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{showContext?"▲ HIDE":"▼ SHOW"}</span>
            </button>
            {showContext && (
              <div style={{ padding:"0 10px 8px", borderTop:`1px solid ${T.border0}` }}>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"3px 12px", marginTop:7, marginBottom:breadcrumbBuffer.items.length>0?8:0 }}>
                  {[["Browser", navigator.userAgent.split(")")[0].split("(")[1]||"—"],
                    ["Viewport", `${window.innerWidth}×${window.innerHeight}`],
                    ["View", VIEW_TO_MODULE[currentView]||currentView||"—"],
                    ["Version", `v${APP_VERSION}`]
                  ].map(([k,v])=>(
                    <div key={k} style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>
                      <span style={{ color:T.text2, marginRight:5 }}>{k}:</span>{v}
                    </div>
                  ))}
                </div>
                {breadcrumbBuffer.items.length > 0 && (
                  <div>
                    <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginBottom:4, letterSpacing:"0.1em" }}>RECENT NAVIGATION</div>
                    {breadcrumbBuffer.items.slice(-5).map((b,i)=>(
                      <div key={i} style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginBottom:2 }}>
                        <span style={{ marginRight:8 }}>{b.time}</span>
                        <span style={{ color:T.text2 }}>{b.action}</span>
                        {b.detail && <span> · {b.detail}</span>}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>

          {/* File attachment */}
          <div>
            <label style={labelS}>ADDITIONAL ATTACHMENTS <span style={{color:T.text3,fontWeight:400}}>— optional</span></label>
            <input ref={fileRef} type="file" multiple accept="image/*,.pdf,.txt" style={{display:"none"}} onChange={e=>{ if(e.target.files?.length > 0) setFiles(prev=>[...prev, ...Array.from(e.target.files)]); e.target.value=""; }}/>
            <button onClick={()=>fileRef.current?.click()}
              style={{ background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, cursor:"pointer", padding:"6px 14px", fontSize:SZ.micro, ...MONO, width:"100%", textAlign:"left", transition:"all 0.1s" }}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border2;e.currentTarget.style.color=T.text2;}}>
              + ATTACH FILES
            </button>
            {files.length > 0 && (
              <div style={{ marginTop:6, display:"flex", flexDirection:"column", gap:4 }}>
                {files.map((f,i)=>(
                  <div key={i} style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"4px 8px", background:T.bg3, border:`1px solid ${T.border1}` }}>
                    <span style={{ fontSize:SZ.micro, color:T.text2, ...MONO, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", flex:1 }}>{f.name}</span>
                    <button onClick={()=>setFiles(prev=>prev.filter((_,j)=>j!==i))} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:10, marginLeft:8, flexShrink:0 }}>✕</button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div style={{ padding:"12px 18px", borderTop:`1px solid ${T.border1}`, flexShrink:0, display:"flex", gap:8 }}>
          <button onClick={onClose} style={{ flex:1, padding:"8px", background:"transparent", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", fontSize:SZ.small, ...MONO }}>CANCEL</button>
          <button onClick={handleSubmit} disabled={saving||!title.trim()}
            style={{ flex:2, padding:"8px", background:title.trim()?T.blueGlow:"transparent", border:`1px solid ${title.trim()?T.blue:T.border1}`, color:title.trim()?T.blue:T.text3, cursor:title.trim()?"pointer":"not-allowed", fontSize:SZ.small, ...MONO, fontWeight:700, letterSpacing:"0.1em" }}>
            {saving?"SUBMITTING…":"◈ SUBMIT REPORT"}
          </button>
        </div>
      </div>
    </div>
  );
};

// ── GLOBAL REPORT BUTTON ──────────────────────────────────────
const GlobalReportButton = ({ currentUser, users, currentView, onSubmitted, firmId, externalOpen, onClose: externalOnClose }) => {
  const [internalOpen, setInternalOpen] = useState(false);
  const open = externalOpen !== undefined ? externalOpen : internalOpen;
  const handleClose = () => { setInternalOpen(false); externalOnClose?.(); };
  if (!open) return null;
  return (
    <BugReportModal currentUser={currentUser} users={users} currentView={currentView} firmId={firmId}
      onClose={handleClose} onSubmitted={(t)=>{ handleClose(); if(onSubmitted) onSubmitted(t); }}/>
  );
};

// ── SUPPORT PAGE (all users — own tickets only) ───────────────
// AI: SUPPORT is where users submit bug reports and feature requests. Context (current screen, browser, last 5 actions) is auto-captured. Screenshots auto-attached. Admins manage the full queue in SUPPORT QUEUE.
const SupportView = ({ currentUser, users, firmId, initialSelectedTicketId, onClearSelectedTicket }) => {
  const [tickets, setTickets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedId, setSelectedId] = useState(null);
  const [newMessage, setNewMessage] = useState("");
  const [posting, setPosting] = useState(false);
  const [filterType, setFilterType] = useState("all");
  const [uploadingAttachment, setUploadingAttachment] = useState(false);
  const [editingTitle, setEditingTitle] = useState(false);
  const [titleDraft, setTitleDraft] = useState("");
  const replyFileRef = useRef(null);

  useEffect(() => {
    api.getTickets().then(d=>{
      const filtered = (d||[]).filter(t=>t.submitted_by===currentUser?.id);
      setTickets(filtered);
      setLoading(false);
      if(initialSelectedTicketId){ setSelectedId(initialSelectedTicketId); onClearSelectedTicket?.(); }
    }).catch(()=>setLoading(false));
  }, [currentUser]);

  const selected = tickets.find(t=>t.id===selectedId);

  const handleUpdateTitle = async () => {
    if(!titleDraft.trim() || !selectedId) return;
    await api.updateTicket(selectedId, { title: titleDraft.trim() });
    setTickets(prev=>prev.map(x=>x.id===selectedId?{...x,title:titleDraft.trim()}:x));
    setEditingTitle(false);
  };

  const handleAddAttachment = async (e) => {
    const file = e.target.files?.[0];
    if(!file || !selected) return;
    setUploadingAttachment(true);
    try {
      const storagePath = await api.uploadSupportFile(currentUser.id, file.name, file);
      const signedUrl = await sb.getSignedUrl(storagePath, 86400);
      const [att] = await api.createTicketAttachment({ ticket_id:selected.id, file_name:file.name, file_url:signedUrl, uploaded_by:currentUser.id, is_screenshot:false });
      const attObj = att || { id:`local-${Date.now()}`, ticket_id:selected.id, file_name:file.name, file_url:signedUrl, uploaded_by:currentUser.id, is_screenshot:false };
      setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,ticket_attachments:[...(t.ticket_attachments||[]),attObj]}:t));
    } catch(err){ console.error("Attachment upload failed:", err); }
    finally{ setUploadingAttachment(false); e.target.value=""; }
  };


  const handleAffectsMe = async (ticket) => {
    const already = (ticket.affects_me_user_ids||[]).includes(currentUser.id);
    if(already) return;
    await api.updateTicket(ticket.id, {
      affects_me_count:(ticket.affects_me_count||0)+1,
      affects_me_user_ids:[...(ticket.affects_me_user_ids||[]),currentUser.id]
    });
    setTickets(prev=>prev.map(t=>t.id===ticket.id?{...t,affects_me_count:(t.affects_me_count||0)+1,affects_me_user_ids:[...(t.affects_me_user_ids||[]),currentUser.id]}:t));
  };

  const handlePostMessage = async () => {
    if(!newMessage.trim()||!selected) return;
    setPosting(true);
    try {
      const [msg] = await api.createTicketMessage({ ticket_id:selected.id, author_id:currentUser.id, body:newMessage.trim(), is_internal:false });
      setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,ticket_messages:[...(t.ticket_messages||[]),msg]}:t));
      setNewMessage("");
    } catch(e){} finally{ setPosting(false); }
  };

  const filtered = tickets.filter(t=>filterType==="all"||t.ticket_type===filterType);

  return (
    <div style={{ display:"flex", height:"100%", overflow:"hidden" }}>
      {/* List */}
      <div style={{ width:selectedId?"42%":"100%", minWidth:280, display:"flex", flexDirection:"column", borderRight:selectedId?`1px solid ${T.border1}`:"none", transition:"width 0.2s" }}>
        <div style={{ padding:"20px 24px 12px", borderBottom:`1px solid ${T.border1}`, flexShrink:0 }}>
          <SectionLabel>MY SUPPORT TICKETS</SectionLabel>
          <div style={{ display:"flex", gap:4, marginTop:10, flexWrap:"wrap" }}>
            {[["all","ALL"],["bug","BUGS"],["enhancement","ENHANCEMENTS"]].map(([k,lbl])=>(
              <button key={k} onClick={()=>setFilterType(k)}
                style={{ padding:"2px 9px", background:filterType===k?T.blueGlow:"transparent", border:`1px solid ${filterType===k?T.blue:T.border1}`, color:filterType===k?T.blue:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:filterType===k?700:400 }}>
                {lbl}
              </button>
            ))}
          </div>
        </div>
        <div style={{ flex:1, overflowY:"auto", padding:"8px 12px" }}>
          {loading && <div style={{ padding:"24px", textAlign:"center", color:T.text3, ...MONO, fontSize:SZ.small }}>LOADING…</div>}
          {!loading && filtered.length===0 && (
            <div style={{ padding:"32px 16px", textAlign:"center" }}>
              <div style={{ fontSize:SZ.body, color:T.text3, ...MONO, marginBottom:8 }}>NO TICKETS YET</div>
              <div style={{ fontSize:SZ.small, color:T.text3 }}>Use the ⚑ button (bottom-right) to submit a bug or enhancement request.</div>
            </div>
          )}
          {filtered.map(t=>{
            const sm = TICKET_STATUSES[t.status]||TICKET_STATUSES.submitted;
            const sev = SEVERITY_META[t.severity]||SEVERITY_META.medium;
            const sel = selectedId===t.id;
            return (
              <div key={t.id} onClick={()=>setSelectedId(sel?null:t.id)}
                style={{ padding:"11px 14px", marginBottom:4, background:sel?T.bg3:T.bg1, border:`1px solid ${sel?T.blue:T.border1}`, borderLeft:`3px solid ${t.ticket_type==="bug"?sev.color:T.blue}`, cursor:"pointer", transition:"all 0.1s" }}
                onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bg2;}}
                onMouseLeave={e=>{if(!sel)e.currentTarget.style.background=T.bg1;}}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:8 }}>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:SZ.body, color:T.text0, fontWeight:600, marginBottom:4, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.title}</div>
                    <div style={{ display:"flex", gap:5, flexWrap:"wrap", alignItems:"center" }}>
                      <span style={{ fontSize:SZ.micro, color:t.ticket_type==="bug"?T.red:T.blue, ...MONO, fontWeight:700 }}>{t.ticket_type==="bug"?"⚠ BUG":"◈ ENHANCEMENT"}</span>
                      {t.ticket_type==="bug" && <span style={{ fontSize:SZ.micro, color:sev.color, ...MONO }}>{sev.icon} {sev.label}</span>}
                      <span style={{ fontSize:SZ.micro, color:sm.color, background:sm.bg, padding:"0px 6px", ...MONO, border:`1px solid ${sm.color}33` }}>{sm.label}</span>
                    </div>
                  </div>
                  <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, flexShrink:0 }}>{new Date(t.created_at).toLocaleDateString("en-US",{month:"short",day:"numeric"})}</div>
                </div>
                {t.fixed_in_version && <div style={{ marginTop:4, fontSize:SZ.micro, color:T.green, ...MONO }}>◈ FIXED IN v{t.fixed_in_version}</div>}
              </div>
            );
          })}
        </div>
      </div>

      {/* Detail */}
      {selected && (
        <div style={{ flex:1, display:"flex", flexDirection:"column", overflowY:"auto", minWidth:0 }}>
          <div style={{ padding:"18px 22px", borderBottom:`1px solid ${T.border1}`, flexShrink:0 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:8, marginBottom:12 }}>
              <div style={{ flex:1 }}>
                {editingTitle ? (
                  <div style={{ display:"flex", gap:6, marginBottom:6, alignItems:"center" }}>
                    <input value={titleDraft} onChange={e=>setTitleDraft(e.target.value)}
                      onKeyDown={e=>{ if(e.key==="Enter") handleUpdateTitle(); if(e.key==="Escape") setEditingTitle(false); }}
                      autoFocus
                      style={{ flex:1, background:T.bg3, border:`1px solid ${T.blue}`, color:T.text0, padding:"5px 9px", fontSize:SZ.sub, fontWeight:700, outline:"none", ...RAJDHANI }}/>
                    <button onClick={handleUpdateTitle} style={{ padding:"5px 12px", background:T.blueGlow, border:`1px solid ${T.blue}`, color:T.blue, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>SAVE</button>
                    <button onClick={()=>setEditingTitle(false)} style={{ padding:"5px 10px", background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>✕</button>
                  </div>
                ) : (
                  <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:6, cursor:"pointer" }}
                    onClick={()=>{ setTitleDraft(selected.title); setEditingTitle(true); }}
                    title="Click to edit title">
                    <div style={{ fontSize:SZ.sub, fontWeight:700, color:T.text0 }}>{selected.title}</div>
                    <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, opacity:0.5 }}>✎</span>
                  </div>
                )}
                <div style={{ display:"flex", gap:6, flexWrap:"wrap", alignItems:"center" }}>
                  <span style={{ fontSize:SZ.label, color:selected.ticket_type==="bug"?T.red:T.blue, ...MONO, fontWeight:700 }}>{selected.ticket_type==="bug"?"⚠ BUG":"◈ ENHANCEMENT"}</span>
                  {selected.ticket_type==="bug" && <span style={{ fontSize:SZ.label, color:SEVERITY_META[selected.severity]?.color, ...MONO }}>{SEVERITY_META[selected.severity]?.icon} {SEVERITY_META[selected.severity]?.label}</span>}
                  <span style={{ fontSize:SZ.label, color:TICKET_STATUSES[selected.status]?.color, background:TICKET_STATUSES[selected.status]?.bg, padding:"1px 7px", ...MONO, border:`1px solid ${TICKET_STATUSES[selected.status]?.color}33` }}>{TICKET_STATUSES[selected.status]?.label}</span>
                  {selected.affected_module && <span style={{ fontSize:SZ.label, color:T.text3, ...MONO }}>{selected.affected_module}</span>}
                </div>
              </div>
              <button onClick={()=>setSelectedId(null)} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:SZ.sub }}>✕</button>
            </div>
            <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginBottom: selected.description ? 10 : 0 }}>
              SUBMITTED {new Date(selected.created_at).toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"}).toUpperCase()} · v{selected.app_version||"—"}
            </div>
            {selected.description && <div style={{ fontSize:SZ.body, color:T.text2, lineHeight:1.6, marginTop:8 }}>{selected.description}</div>}
            {selected.steps_to_reproduce && (
              <div style={{ marginTop:10, padding:"8px 10px", background:T.bg2, border:`1px solid ${T.border1}` }}>
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, marginBottom:4 }}>STEPS TO REPRODUCE</div>
                <div style={{ fontSize:SZ.small, color:T.text2, ...MONO, whiteSpace:"pre-wrap", lineHeight:1.6 }}>{selected.steps_to_reproduce}</div>
              </div>
            )}
            {selected.resolved_note && (
              <div style={{ marginTop:10, padding:"8px 10px", background:`${T.green}10`, border:`1px solid ${T.green}44` }}>
                <div style={{ fontSize:SZ.micro, color:T.green, ...MONO, fontWeight:700, marginBottom:4 }}>RESOLUTION NOTE</div>
                <div style={{ fontSize:SZ.small, color:T.text2 }}>{selected.resolved_note}</div>
                {selected.fixed_in_version && <div style={{ fontSize:SZ.micro, color:T.green, ...MONO, marginTop:4 }}>◈ FIXED IN v{selected.fixed_in_version}</div>}
              </div>
            )}
          </div>

          {/* Thread */}
          <div style={{ flex:1, padding:"16px 22px", overflowY:"auto" }}>
            <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:10 }}>CONVERSATION</div>
            {(selected.ticket_messages||[]).filter(m=>!m.is_internal).length===0 && (
              <div style={{ fontSize:SZ.small, color:T.text3, ...MONO, marginBottom:12 }}>NO MESSAGES YET</div>
            )}
            {(selected.ticket_messages||[]).filter(m=>!m.is_internal).map(m=>{
              const author = users.find(u=>u.id===m.author_id);
              const isMe = m.author_id===currentUser?.id;
              return (
                <div key={m.id} style={{ marginBottom:10, display:"flex", gap:8, flexDirection:isMe?"row-reverse":"row" }}>
                  <Avatar userId={m.author_id} users={users} size={24}/>
                  <div style={{ maxWidth:"75%", background:isMe?T.blueGlow:T.bg3, border:`1px solid ${isMe?T.blue+"44":T.border1}`, padding:"8px 12px" }}>
                    <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginBottom:4 }}>{author?.name||"—"} · {new Date(m.created_at).toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"})}</div>
                    <div style={{ fontSize:SZ.body, color:T.text1, lineHeight:1.5 }}>{m.body}</div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Attachments on existing ticket */}
          {(selected.ticket_attachments||[]).length > 0 && (
            <div style={{ padding:"8px 22px 0", flexShrink:0 }}>
              <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:5 }}>ATTACHMENTS</div>
              <div style={{ display:"flex", flexDirection:"column", gap:3 }}>
                {(selected.ticket_attachments||[]).map(a=>(
                  <div key={a.id} style={{ display:"flex", gap:8, alignItems:"center", padding:"4px 8px", background:T.bg2, border:`1px solid ${T.border1}` }}>
                    <span style={{ color:a.is_screenshot?T.green:T.blue, fontSize:SZ.small, flexShrink:0 }}>{a.is_screenshot?"◉":"▣"}</span>
                    <a href={a.file_url} target="_blank" rel="noopener noreferrer" style={{ fontSize:SZ.micro, color:T.blue, flex:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{a.file_name}{a.is_screenshot?" (screenshot)":""}</a>
                  </div>
                ))}
              </div>
            </div>
          )}
          {/* Reply box */}
          {selected.status !== "released" && selected.status !== "no_action_required" && (
            <div style={{ padding:"12px 22px", borderTop:`1px solid ${T.border1}`, flexShrink:0 }}>
              <input ref={replyFileRef} type="file" accept="image/*,.pdf,.txt,.doc,.docx" style={{display:"none"}} onChange={handleAddAttachment}/>
              <div style={{ display:"flex", gap:8, marginBottom:6 }}>
                <input value={newMessage} onChange={e=>setNewMessage(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handlePostMessage();}}}
                  placeholder="Add a follow-up comment…"
                  style={{ flex:1, background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"7px 10px", fontSize:SZ.body, ...RAJDHANI, outline:"none" }}/>
                <button onClick={handlePostMessage} disabled={posting||!newMessage.trim()}
                  style={{ padding:"7px 16px", background:newMessage.trim()?T.blueGlow:"transparent", border:`1px solid ${newMessage.trim()?T.blue:T.border1}`, color:newMessage.trim()?T.blue:T.text3, cursor:newMessage.trim()?"pointer":"default", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>
                  POST
                </button>
              </div>
              <button onClick={()=>replyFileRef.current?.click()} disabled={uploadingAttachment}
                style={{ background:"transparent", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", padding:"4px 12px", fontSize:SZ.micro, ...MONO, transition:"all 0.1s" }}
                onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.color=T.text3;}}>
                {uploadingAttachment?"UPLOADING…":"+ ATTACH FILE"}
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

// ── ADMIN SUPPORT QUEUE (super admin only) ────────────────────
// ── TICKET ACTIVITY FEED ──────────────────────────────────────
const TICKET_ACTION_META = {
  TICKET_STATUS_CHANGED:  { label:"Status changed",   color:"#4fc3f7" },
  TICKET_SEVERITY_CHANGED:{ label:"Severity changed", color:"#ffb74d" },
  TICKET_TITLE_EDITED:    { label:"Title edited",     color:"#90caf9" },
  TICKET_ASSIGNED:        { label:"Assigned",         color:"#4dd0e1" },
  TICKET_MESSAGE_POSTED:  { label:"Message posted",   color:"#81c784" },
};

const TicketActivity = ({ ticketId, currentUser, users }) => {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if(!ticketId) return;
    setLoading(true);
    api.getAuditLog({ entityType:"ticket", entityId:String(ticketId), limit:50 })
      .then(d=>{ setEvents(d||[]); setLoading(false); })
      .catch(()=>setLoading(false));
  }, [ticketId]);

  if(loading) return null;
  if(events.length===0) return (
    <div style={{ marginBottom:14, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
      <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, marginBottom:4 }}>RECENT ACTIVITY</div>
      <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontStyle:"italic" }}>No activity recorded yet.</div>
    </div>
  );

  return (
    <div style={{ marginBottom:14, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
      <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:8 }}>RECENT ACTIVITY</div>
      <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
        {events.map(e=>{
          const meta = TICKET_ACTION_META[e.action]||{ label:e.action, color:T.text3 };
          const actor = e.user_name||"—";
          const ts = new Date(e.created_at).toLocaleDateString("en-US",{month:"short",day:"numeric",hour:"numeric",minute:"2-digit"});
          let detail = null;
          if(e.action==="TICKET_STATUS_CHANGED" && e.new_value?.status){
            const nv = TICKET_STATUSES[e.new_value.status];
            detail = <span style={{ color:nv?.color||T.text2, ...MONO, fontSize:SZ.micro }}>{nv?.label||e.new_value.status}</span>;
          } else if(e.action==="TICKET_SEVERITY_CHANGED" && e.new_value?.severity){
            const sv = SEVERITY_META[e.new_value.severity];
            detail = <span style={{ color:sv?.color||T.text2, ...MONO, fontSize:SZ.micro }}>{sv?.label||e.new_value.severity}</span>;
          } else if(e.action==="TICKET_ASSIGNED" && e.new_value?.assigned_to){
            const u = users.find(u=>u.id===e.new_value.assigned_to);
            detail = <span style={{ color:T.teal, ...MONO, fontSize:SZ.micro }}>{u?.name||"Unknown"}</span>;
          } else if(e.action==="TICKET_ASSIGNED" && !e.new_value?.assigned_to){
            detail = <span style={{ color:T.text3, ...MONO, fontSize:SZ.micro }}>Unassigned</span>;
          }
          return (
            <div key={e.id} style={{ display:"flex", alignItems:"center", gap:8, fontSize:SZ.micro, ...MONO }}>
              <span style={{ width:6, height:6, borderRadius:"50%", background:meta.color, flexShrink:0 }}/>
              <span style={{ color:T.text3, flexShrink:0 }}>{ts}</span>
              <span style={{ color:T.text2 }}>{actor}</span>
              <span style={{ color:meta.color }}>{meta.label}</span>
              {detail}
            </div>
          );
        })}
      </div>
    </div>
  );
};

const AdminSupportQueue = ({ currentUser, users, firmId, initialSelectedTicketId, onClearSelectedTicket }) => {
  const [tickets, setTickets]     = useState([]);
  const [loading, setLoading]     = useState(true);
  const [selectedId, setSelectedId] = useState(null);
  const [filterStatus, setFStatus]  = useState("all");
  const [filterType, setFType]      = useState("all");
  const [filterSev, setFSev]        = useState("all");
  const [fixedIn, setFixedIn]       = useState("");
  const [newInternalNote, setNewInternalNote] = useState("");
  const [newResolutionNote, setNewResolutionNote] = useState("");
  const [postingNote, setPostingNote] = useState(false);
  const [newMsg, setNewMsg]         = useState("");
  const [saving, setSaving]         = useState(false);
  const [posting, setPosting]       = useState(false);
  const [sortOrder, setSortOrder]   = useState("newest");
  // Track viewed tickets in localStorage — no schema change needed
  const [viewedIds, setViewedIds] = useState(() => {
    try { return new Set(JSON.parse(localStorage.getItem("ahud_viewed_tickets")||"[]")); }
    catch(e) { return new Set(); }
  });
  const markViewed = (id) => {
    setViewedIds(prev => {
      const next = new Set(prev).add(id);
      try { localStorage.setItem("ahud_viewed_tickets", JSON.stringify([...next])); } catch(e){}
      return next;
    });
  };

  useEffect(()=>{
    const load = (isFirst=false) => api.getTickets().then(d=>{
      setTickets(d||[]);
      setLoading(false);
      if(isFirst && initialSelectedTicketId){ setSelectedId(initialSelectedTicketId); onClearSelectedTicket?.(); }
    }).catch(()=>setLoading(false));
    load(true);
    const t = setInterval(load, 10000);
    return () => clearInterval(t);
  },[]);

  const selected = tickets.find(t=>t.id===selectedId);

  const handleStatusChange = async (id, status) => {
    await api.updateTicket(id, { status, ...(status==="released"&&fixedIn?{fixed_in_version:fixedIn}:{}) });
    setTickets(prev=>prev.map(t=>t.id===id?{...t,status,...(status==="released"&&fixedIn?{fixed_in_version:fixedIn}:{})}:t));
    // Notify submitter
    const ticket = tickets.find(t=>t.id===id);
    if(ticket?.submitted_by){
      const sm = TICKET_STATUSES[status];
      await api.createNotification({ user_id:ticket.submitted_by, type:"ticket_update", body:`Your ${ticket.ticket_type==="bug"?"bug report":"enhancement request"} "${ticket.title}" is now: ${sm?.label||status}`, link_type:"support", link_id:id }).catch(()=>{});
    }
  };

  const [editingTitle, setEditingTitle] = useState(false);
  const [titleDraft, setTitleDraft] = useState("");

  const handleUpdateTitle = async () => {
    if(!titleDraft.trim() || !selected) return;
    audit(currentUser).log({ action:"TICKET_TITLE_EDITED", entityType:"ticket", entityId:selected.id, entityLabel:selected.title, oldValue:{title:selected.title}, newValue:{title:titleDraft.trim()} });
    await api.updateTicket(selected.id, { title: titleDraft.trim() });
    setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,title:titleDraft.trim()}:t));
    setEditingTitle(false);
  };

  const handleAssignTicket = async (userId) => {
    if(!selected) return;
    audit(currentUser).log({ action:"TICKET_ASSIGNED", entityType:"ticket", entityId:selected.id, entityLabel:selected.title, oldValue:{assigned_to:selected.assigned_to}, newValue:{assigned_to:userId||null} });
    await api.updateTicket(selected.id, { assigned_to: userId||null });
    setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,assigned_to:userId||null}:t));
    if(userId && userId !== currentUser.id){
      await api.createNotification({ user_id:userId, type:"ticket_update", body:`You've been assigned ticket: "${selected.title}"`, link_type:"support", link_id:selected.id }).catch(()=>{});
    }
  };

  const handlePostNote = async (noteType) => {
    const body = noteType==="internal" ? newInternalNote : newResolutionNote;
    if(!body.trim() || !selected) return;
    setPostingNote(true);
    try {
      const [note] = await api.createTicketNote({ ticket_id:selected.id, author_id:currentUser.id, body:body.trim(), note_type:noteType });
      const noteObj = note || { id:`local-${Date.now()}`, ticket_id:selected.id, author_id:currentUser.id, body:body.trim(), note_type:noteType, created_at:new Date().toISOString() };
      setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,ticket_notes:[...(t.ticket_notes||[]),noteObj]}:t));
      audit(currentUser).log({ action:"TICKET_NOTE_POSTED", entityType:"ticket", entityId:selected.id, entityLabel:selected.title, metadata:{note_type:noteType, body:body.trim().slice(0,120)} });
      if(noteType==="internal" && selected.assigned_to && selected.assigned_to !== currentUser.id){
        await api.createNotification({ user_id:selected.assigned_to, type:"ticket_update", body:`Internal note added to: "${selected.title}"`, link_type:"support", link_id:selected.id }).catch(()=>{});
      }
      if(noteType==="internal") setNewInternalNote(""); else setNewResolutionNote("");
    } catch(e){} finally{ setPostingNote(false); }
  };

  const handleSaveFixedIn = async () => {
    if(!selected || !fixedIn.trim()) return;
    setSaving(true);
    try {
      await api.updateTicket(selected.id, { fixed_in_version:fixedIn.trim()||null });
      setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,fixed_in_version:fixedIn.trim()||null}:t));
    } catch(e){} finally{ setSaving(false); }
  };

  const handlePostMessage = async (isInternal=false) => {
    if(!newMsg.trim()||!selected) return;
    setPosting(true);
    try {
      const [msg] = await api.createTicketMessage({ ticket_id:selected.id, author_id:currentUser.id, body:newMsg.trim(), is_internal:isInternal });
      setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,ticket_messages:[...(t.ticket_messages||[]),msg]}:t));
      setNewMsg("");
      if(!isInternal && selected.submitted_by !== currentUser.id){
        await api.createNotification({ user_id:selected.submitted_by, type:"ticket_update", body:`Support replied to your ticket: "${selected.title}"`, link_type:"support", link_id:selected.id }).catch(()=>{});
      }
    } catch(e){} finally{ setPosting(false); }
  };

  useEffect(()=>{ if(selected){ setFixedIn(selected.fixed_in_version||""); markViewed(selected.id); }}, [selectedId]);

  const filtered = tickets.filter(t=>{
    if(filterStatus!=="all" && t.status!==filterStatus) return false;
    if(filterType!=="all" && t.ticket_type!==filterType) return false;
    if(filterSev!=="all" && t.severity!==filterSev) return false;
    return true;
  }).sort((a,b)=>{
    if(sortOrder==="oldest") return new Date(a.created_at)-new Date(b.created_at);
    if(sortOrder==="type")     return (a.ticket_type||"").localeCompare(b.ticket_type||"");
    if(sortOrder==="type_asc") return (b.ticket_type||"").localeCompare(a.ticket_type||"");
    if(sortOrder==="status")     return (a.status||"").localeCompare(b.status||"");
    if(sortOrder==="status_asc") return (b.status||"").localeCompare(a.status||"");
    if(sortOrder==="area")     return (a.affected_module||"").localeCompare(b.affected_module||"");
    if(sortOrder==="area_asc") return (b.affected_module||"").localeCompare(a.affected_module||"");
    if(sortOrder==="title")     return (a.title||"").localeCompare(b.title||"");
    if(sortOrder==="title_asc") return (b.title||"").localeCompare(a.title||"");
    if(sortOrder==="date_asc") return new Date(a.created_at)-new Date(b.created_at);
    return new Date(b.created_at)-new Date(a.created_at); // newest default
  });

  const inputS = { background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"6px 9px", fontSize:SZ.small, outline:"none", width:"100%", boxSizing:"border-box", ...RAJDHANI };

  return (
    <div style={{ display:"flex", height:"100%", overflow:"hidden" }}>
      {/* Queue list */}
      <div style={{ width:selectedId?"40%":"100%", minWidth:300, display:"flex", flexDirection:"column", borderRight:selectedId?`1px solid ${T.border1}`:"none", transition:"width 0.2s", minHeight:0 }}>
        <div style={{ padding:"20px 24px 10px", borderBottom:`1px solid ${T.border1}`, flexShrink:0, background:T.bg0 }}>
          <SectionLabel>SUPPORT QUEUE</SectionLabel>
          <div style={{ fontSize:SZ.label, color:T.text3, ...MONO, marginTop:2, marginBottom:10 }}>SUPER ADMIN · ALL TICKETS</div>
          <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
            <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
              {[["all","ALL"],["submitted","SUBMITTED"],["under_review","REVIEW"],["in_progress","IN PROGRESS"],["released","RELEASED"],["no_action_required","NO ACTION"],["duplicate","DUPLICATE"]].map(([k,lbl])=>(
                <button key={k} onClick={()=>setFStatus(k)}
                  style={{ padding:"2px 8px", background:filterStatus===k?T.blueGlow:"transparent", border:`1px solid ${filterStatus===k?T.blue:T.border1}`, color:filterStatus===k?T.blue:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:filterStatus===k?700:400 }}>
                  {lbl}{k!=="all"?` (${tickets.filter(t=>t.status===k).length})`:""}
                </button>
              ))}
            </div>
            <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
              {[["all","ALL TYPES"],["bug","BUGS"],["enhancement","ENHANCEMENTS"]].map(([k,lbl])=>(
                <button key={k} onClick={()=>setFType(k)} style={{ padding:"2px 8px", background:filterType===k?T.blueGlow:"transparent", border:`1px solid ${filterType===k?T.blue:T.border1}`, color:filterType===k?T.blue:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>{lbl}</button>
              ))}
              {[["all","ALL SEV"],["critical","CRITICAL"],["high","HIGH"],["medium","MEDIUM"],["low","LOW"]].map(([k,lbl])=>(
                <button key={k} onClick={()=>setFSev(k)} style={{ padding:"2px 8px", background:filterSev===k?(k==="all"?T.blueGlow:`${SEVERITY_META[k]?.glow}`):"transparent", border:`1px solid ${filterSev===k?(k==="all"?T.blue:SEVERITY_META[k]?.color):T.border1}`, color:filterSev===k?(k==="all"?T.blue:SEVERITY_META[k]?.color):T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>{lbl}</button>
              ))}
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:4, marginTop:2 }}>
              <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, letterSpacing:"0.1em" }}>SORT:</span>
              {[["newest","NEWEST"],["oldest","OLDEST"]].map(([k,lbl])=>(
                <button key={k} onClick={()=>setSortOrder(k)}
                  style={{ padding:"2px 8px", background:sortOrder===k?T.blueGlow:"transparent", border:`1px solid ${sortOrder===k?T.blue:T.border1}`, color:sortOrder===k?T.blue:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:sortOrder===k?700:400 }}>
                  {lbl}
                </button>
              ))}
            </div>
          </div>
        </div>
        {/* Column headers */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 72px 108px 80px 48px", gap:0, padding:"5px 12px 5px 16px", background:T.bg2, borderBottom:`1px solid ${T.border1}`, flexShrink:0 }}>
          {[["TITLE","title"],["TYPE","type"],["STATUS","status"],["AREA","area"],["DATE","date"]].map(([lbl,key])=>(
            <button key={key} onClick={()=>{ if(sortOrder===key) setSortOrder(key+"_asc"); else if(sortOrder===key+"_asc") setSortOrder("newest"); else setSortOrder(key); }}
              style={{ background:"none", border:"none", color:sortOrder===key||sortOrder===key+"_asc"?T.blue:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700, letterSpacing:"0.12em", textAlign:"left", padding:"3px 0", display:"flex", alignItems:"center", gap:3 }}>
              {lbl}
              {(sortOrder===key||sortOrder===key+"_asc") && <span style={{ fontSize:8 }}>{sortOrder===key+"_asc"?"▲":"▼"}</span>}
            </button>
          ))}
        </div>
        <div style={{ flex:1, overflowY:"auto" }}>
          {loading && <div style={{ padding:"24px", textAlign:"center", color:T.text3, ...MONO, fontSize:SZ.small }}>LOADING…</div>}
          {!loading && filtered.length===0 && <div style={{ padding:"32px 0", textAlign:"center", color:T.text3, fontSize:SZ.small, ...MONO }}>NO TICKETS MATCH FILTERS</div>}
          {filtered.map(t=>{
            const sm = TICKET_STATUSES[t.status]||TICKET_STATUSES.submitted;
            const sev = SEVERITY_META[t.severity]||SEVERITY_META.medium;
            const sel = selectedId===t.id;
            const isUnread = !viewedIds.has(t.id);
            return (
              <div key={t.id} onClick={()=>setSelectedId(sel?null:t.id)}
                style={{ display:"grid", gridTemplateColumns:"1fr 72px 108px 80px 48px", gap:0, padding:"8px 12px 8px 16px",
                  borderBottom:`1px solid ${T.border0}`, borderLeft:`3px solid ${sel?T.blue:t.ticket_type==="bug"?sev.color:T.blue+"44"}`,
                  background:sel?`${T.blue}0d`:isUnread?`${T.blue}06`:T.bg1, cursor:"pointer", alignItems:"center", transition:"all 0.1s" }}
                onMouseEnter={e=>{if(!sel)e.currentTarget.style.background=T.bg2;}}
                onMouseLeave={e=>{if(!sel)e.currentTarget.style.background=sel?`${T.blue}0d`:isUnread?`${T.blue}06`:T.bg1;}}>
                {/* Title */}
                <div style={{ minWidth:0, paddingRight:8 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:6 }}>
                    {isUnread && <span style={{ width:6, height:6, borderRadius:"50%", background:T.blue, flexShrink:0 }} title="Unread"/>}
                    <div style={{ fontSize:SZ.small, color:sel?T.blue:isUnread?T.white:T.text0, fontWeight:isUnread?700:600, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.title}</div>
                  </div>
                  <div style={{ display:"flex", gap:6, marginTop:2, alignItems:"center" }}>
                    {t.affects_me_count>0 && <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO }}>⚑ {t.affects_me_count}</span>}
                    {(t.ticket_messages||[]).length>0 && <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }} title={`${(t.ticket_messages||[]).length} message${(t.ticket_messages||[]).length!==1?"s":""}`}>◉ {(t.ticket_messages||[]).length}</span>}
                    {(t.ticket_attachments||[]).length>0 && <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }} title={`${(t.ticket_attachments||[]).length} attachment${(t.ticket_attachments||[]).length!==1?"s":""}`}>▣ {(t.ticket_attachments||[]).length}</span>}
                  </div>
                </div>
                {/* Type */}
                <div style={{ fontSize:SZ.micro, color:t.ticket_type==="bug"?T.red:T.blue, ...MONO, fontWeight:700 }}>
                  {t.ticket_type==="bug"?"BUG":"ENHANC."}
                </div>
                {/* Status */}
                <div>
                  <span style={{ fontSize:SZ.micro, color:sm.color, background:sm.bg, padding:"1px 5px", ...MONO, border:`1px solid ${sm.color}33`, whiteSpace:"nowrap" }}>
                    {{"SUBMITTED":"SUBMITTED","UNDER REVIEW":"REVIEW","IN PROGRESS":"IN PROG","NO ACTION REQUIRED":"NO ACTION","DUPLICATE":"DUPE","RELEASED":"RELEASED"}[sm.label]||sm.label}
                  </span>
                </div>
                {/* Area */}
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.affected_module||"—"}</div>
                {/* Date */}
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{new Date(t.created_at).toLocaleDateString("en-US",{month:"short",day:"numeric"})}</div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Detail / management */}
      {selected && (
        <div style={{ flex:1, display:"flex", flexDirection:"column", overflow:"hidden", minWidth:0 }}>
          <div style={{ overflowY:"auto", flex:1, padding:"18px 22px" }}>
            {/* Header */}
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:14 }}>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:SZ.sub, fontWeight:700, color:T.text0, marginBottom:6 }}>{selected.title}</div>
                <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                  <span style={{ fontSize:SZ.label, color:selected.ticket_type==="bug"?T.red:T.blue, ...MONO, fontWeight:700 }}>{selected.ticket_type==="bug"?"⚠ BUG":"◈ ENHANCEMENT"}</span>
                  {selected.ticket_type==="bug" && <span style={{ fontSize:SZ.label, color:SEVERITY_META[selected.severity]?.color, ...MONO }}>{SEVERITY_META[selected.severity]?.icon} {SEVERITY_META[selected.severity]?.label}</span>}
                  <span style={{ fontSize:SZ.label, color:T.text3, ...MONO }}>v{selected.app_version||"—"} · {selected.current_view||"—"}</span>
                </div>
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginTop:4 }}>
                  SUBMITTED BY {users.find(u=>u.id===selected.submitted_by)?.name?.toUpperCase()||"UNKNOWN"} · {new Date(selected.created_at).toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"}).toUpperCase()}
                </div>
                <div style={{ display:"flex", alignItems:"center", gap:8, marginTop:8 }}>
                  <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, whiteSpace:"nowrap" }}>ASSIGNED TO</span>
                  <select value={selected.assigned_to||""} onChange={e=>handleAssignTicket(e.target.value)}
                    style={{ background:T.bg3, border:`1px solid ${selected.assigned_to?T.teal:T.border2}`, color:selected.assigned_to?T.teal:T.text3, fontSize:SZ.micro, ...MONO, padding:"2px 6px", outline:"none", cursor:"pointer" }}>
                    <option value="">— Unassigned —</option>
                    {users.filter(u=>u.role==="ops"||u.role==="admin"||u.role==="super_admin").map(u=>(
                      <option key={u.id} value={u.id}>{u.name}</option>
                    ))}
                  </select>
                </div>
              </div>
              <button onClick={()=>setSelectedId(null)} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:SZ.sub }}>✕</button>
            </div>

            {/* Status control */}
            <div style={{ marginBottom:10 }}>
              <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:6 }}>CHANGE STATUS</div>
              <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
                {Object.entries(TICKET_STATUSES).map(([k,v])=>(
                  <button key={k} onClick={()=>handleStatusChange(selected.id,k)}
                    style={{ padding:"3px 10px", background:selected.status===k?v.bg:"transparent", border:`1px solid ${selected.status===k?v.color:T.border1}`, color:selected.status===k?v.color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:selected.status===k?700:400, transition:"all 0.1s" }}>
                    {v.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Severity control */}
            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:6 }}>SEVERITY</div>
              <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
                {Object.entries(SEVERITY_META).map(([k,v])=>(
                  <button key={k} onClick={async()=>{
                    await api.updateTicket(selected.id, { severity:k });
                    setTickets(prev=>prev.map(t=>t.id===selected.id?{...t,severity:k}:t));
                  }}
                    style={{ padding:"3px 10px", background:selected.severity===k?`${v.glow}`:"transparent", border:`1px solid ${selected.severity===k?v.color:T.border1}`, color:selected.severity===k?v.color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:selected.severity===k?700:400, transition:"all 0.1s" }}>
                    {v.icon} {v.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Description */}
            {selected.description && (
              <div style={{ marginBottom:12, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, marginBottom:4 }}>DESCRIPTION</div>
                <div style={{ fontSize:SZ.body, color:T.text2, lineHeight:1.6 }}>{selected.description}</div>
              </div>
            )}

            {/* Steps */}
            {selected.steps_to_reproduce && (
              <div style={{ marginBottom:12, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, marginBottom:4 }}>STEPS TO REPRODUCE</div>
                <div style={{ fontSize:SZ.small, color:T.text2, ...MONO, whiteSpace:"pre-wrap", lineHeight:1.6 }}>{selected.steps_to_reproduce}</div>
              </div>
            )}

            {/* Context info */}
            <div style={{ marginBottom:12, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
              <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, marginBottom:6 }}>AUTO-CAPTURED CONTEXT</div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:4 }}>
                {[["Browser",selected.browser_info],["Viewport",selected.viewport_info],["View",selected.current_view],["Version","v"+(selected.app_version||"—")]].map(([k,v])=>v?(
                  <div key={k} style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}><span style={{ color:T.text2 }}>{k}:</span> {v}</div>
                ):null)}
              </div>
              {selected.breadcrumbs?.length>0 && (
                <div style={{ marginTop:8 }}>
                  <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, marginBottom:4 }}>BREADCRUMBS</div>
                  {selected.breadcrumbs.map((b,i)=>(
                    <div key={i} style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginBottom:2 }}>
                      <span style={{ marginRight:8 }}>{b.time}</span><span style={{ color:T.text2 }}>{b.action}</span>{b.detail&&<span> · {b.detail}</span>}
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Attachments */}
            {(selected.ticket_attachments||[]).length>0 && (
              <div style={{ marginBottom:12 }}>
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:6 }}>ATTACHMENTS</div>
                {(selected.ticket_attachments||[]).map(a=>(
                  <div key={a.id} style={{ display:"flex", gap:8, alignItems:"center", padding:"6px 10px", background:T.bg2, border:`1px solid ${T.border1}`, marginBottom:3 }}>
                    <span style={{ color:a.is_screenshot?T.green:T.blue, fontSize:SZ.small }}>{a.is_screenshot?"◉":"▣"}</span>
                    <a href={a.file_url} target="_blank" rel="noopener noreferrer" style={{ fontSize:SZ.small, color:T.blue, flex:1 }}>{a.file_name}{a.is_screenshot?" (auto-screenshot)":""}</a>
                  </div>
                ))}
              </div>
            )}

            {/* Internal Notes — append-only log */}
            <div style={{ marginBottom:14, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
              <div style={{ fontSize:SZ.micro, color:T.amber, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:8 }}>⚑ INTERNAL NOTES — NOT VISIBLE TO SUBMITTER</div>
              {(selected.ticket_notes||[]).filter(n=>n.note_type==="internal").length===0 && (
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontStyle:"italic", marginBottom:8 }}>No internal notes yet.</div>
              )}
              {(selected.ticket_notes||[]).filter(n=>n.note_type==="internal").map(n=>{
                const author = users.find(u=>u.id===n.author_id);
                return (
                  <div key={n.id} style={{ marginBottom:8, paddingLeft:10, borderLeft:`2px solid ${T.amber}44` }}>
                    <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:3 }}>
                      <Avatar userId={n.author_id} users={users} size={16}/>
                      <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO, fontWeight:700 }}>{author?.name||"—"}</span>
                      <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{new Date(n.created_at).toLocaleDateString("en-US",{month:"short",day:"numeric",hour:"numeric",minute:"2-digit"})}</span>
                    </div>
                    <div style={{ fontSize:SZ.body, color:T.text1, lineHeight:1.5, whiteSpace:"pre-wrap" }}>{n.body}</div>
                  </div>
                );
              })}
              <div style={{ display:"flex", gap:6, marginTop:8, borderTop:`1px solid ${T.border0}`, paddingTop:8 }}>
                <input value={newInternalNote} onChange={e=>setNewInternalNote(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handlePostNote("internal");}}}
                  placeholder="Add internal note… (Enter to post)"
                  style={{ flex:1, background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"5px 8px", fontSize:SZ.body, ...RAJDHANI, outline:"none" }}/>
                <button onClick={()=>handlePostNote("internal")} disabled={postingNote||!newInternalNote.trim()}
                  style={{ padding:"5px 12px", background:newInternalNote.trim()?`${T.amber}20`:"transparent", border:`1px solid ${newInternalNote.trim()?T.amber:T.border1}`, color:newInternalNote.trim()?T.amber:T.text3, cursor:newInternalNote.trim()?"pointer":"default", fontSize:SZ.micro, ...MONO, fontWeight:700, whiteSpace:"nowrap" }}>
                  POST
                </button>
              </div>
            </div>

            {/* Resolution Notes — append-only log */}
            <div style={{ marginBottom:14, padding:"10px 12px", background:T.bg2, border:`1px solid ${T.border1}` }}>
              <div style={{ fontSize:SZ.micro, color:T.green, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:8 }}>◈ RESOLUTION NOTES — VISIBLE TO SUBMITTER</div>
              {(selected.ticket_notes||[]).filter(n=>n.note_type==="resolution").length===0 && (
                <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontStyle:"italic", marginBottom:8 }}>No resolution notes yet.</div>
              )}
              {(selected.ticket_notes||[]).filter(n=>n.note_type==="resolution").map(n=>{
                const author = users.find(u=>u.id===n.author_id);
                return (
                  <div key={n.id} style={{ marginBottom:8, paddingLeft:10, borderLeft:`2px solid ${T.green}44` }}>
                    <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:3 }}>
                      <Avatar userId={n.author_id} users={users} size={16}/>
                      <span style={{ fontSize:SZ.micro, color:T.green, ...MONO, fontWeight:700 }}>{author?.name||"—"}</span>
                      <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{new Date(n.created_at).toLocaleDateString("en-US",{month:"short",day:"numeric",hour:"numeric",minute:"2-digit"})}</span>
                    </div>
                    <div style={{ fontSize:SZ.body, color:T.text1, lineHeight:1.5, whiteSpace:"pre-wrap" }}>{n.body}</div>
                  </div>
                );
              })}
              <div style={{ display:"flex", gap:6, marginTop:8, borderTop:`1px solid ${T.border0}`, paddingTop:8 }}>
                <input value={newResolutionNote} onChange={e=>setNewResolutionNote(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handlePostNote("resolution");}}}
                  placeholder="Add resolution note… (Enter to post)"
                  style={{ flex:1, background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"5px 8px", fontSize:SZ.body, ...RAJDHANI, outline:"none" }}/>
                <button onClick={()=>handlePostNote("resolution")} disabled={postingNote||!newResolutionNote.trim()}
                  style={{ padding:"5px 12px", background:newResolutionNote.trim()?T.greenDim:"transparent", border:`1px solid ${newResolutionNote.trim()?T.green:T.border1}`, color:newResolutionNote.trim()?T.green:T.text3, cursor:newResolutionNote.trim()?"pointer":"default", fontSize:SZ.micro, ...MONO, fontWeight:700, whiteSpace:"nowrap" }}>
                  POST
                </button>
              </div>
            </div>

            {/* Fixed in version */}
            <div style={{ marginBottom:14 }}>
              <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:6 }}>FIXED IN VERSION</div>
              <div style={{ display:"flex", gap:8 }}>
                <input value={fixedIn} onChange={e=>setFixedIn(e.target.value)} placeholder="e.g. 1.4.1 — leave blank if not yet released" style={{...inputS, flex:1}}/>
                <button onClick={handleSaveFixedIn} disabled={saving||!fixedIn.trim()||fixedIn.trim()===(selected.fixed_in_version||"")}
                  style={{ padding:"6px 14px", background:T.blueGlow, border:`1px solid ${T.blue}`, color:T.blue, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700, whiteSpace:"nowrap" }}>
                  {saving?"SAVING…":"SAVE"}
                </button>
              </div>
            </div>

            {/* Recent Activity */}
            <TicketActivity ticketId={selected.id} currentUser={currentUser} users={users}/>

            {/* Conversation Thread — submitter ↔ assignee */}
            <div style={{ borderTop:`1px solid ${T.border1}`, paddingTop:14 }}>
              <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:10 }}>CONVERSATION THREAD</div>
              <div style={{ display:"flex", flexDirection:"column", gap:10, marginBottom:12 }}>
                {(selected.ticket_messages||[]).filter(m=>!m.is_internal).length===0 && (
                  <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, fontStyle:"italic", textAlign:"center", padding:"16px 0" }}>No messages yet</div>
                )}
                {(selected.ticket_messages||[]).filter(m=>!m.is_internal).map(m=>{
                  const author = users.find(u=>u.id===m.author_id);
                  const isMe = m.author_id===currentUser?.id;
                  return (
                    <div key={m.id} style={{ display:"flex", flexDirection:"column", alignItems:isMe?"flex-end":"flex-start", gap:3 }}>
                      <div style={{ display:"flex", alignItems:"center", gap:6, flexDirection:isMe?"row-reverse":"row" }}>
                        <Avatar userId={m.author_id} users={users} size={18}/>
                        <span style={{ fontSize:SZ.micro, color:isMe?T.blue:T.text2, ...MONO, fontWeight:600 }}>{isMe?"You":author?.name||"—"}</span>
                        <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{new Date(m.created_at).toLocaleDateString("en-US",{month:"short",day:"numeric",hour:"numeric",minute:"2-digit"})}</span>
                      </div>
                      <div style={{ maxWidth:"82%", background:isMe?T.blueDim:T.bg3, border:`1px solid ${isMe?T.blue+"33":T.border1}`, padding:"8px 12px", borderRadius:isMe?"8px 2px 8px 8px":"2px 8px 8px 8px" }}>
                        <div style={{ fontSize:SZ.body, color:T.text0, lineHeight:1.5, whiteSpace:"pre-wrap", wordBreak:"break-word" }}>{m.body}</div>
                      </div>
                    </div>
                  );
                })}
              </div>
              <div style={{ display:"flex", gap:6 }}>
                <input value={newMsg} onChange={e=>setNewMsg(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handlePostMessage(false);}}}
                  placeholder="Reply to submitter… (Enter to send)"
                  style={{ flex:1, background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"6px 9px", fontSize:SZ.body, ...RAJDHANI, outline:"none" }}/>
                <button onClick={()=>handlePostMessage(false)} disabled={posting||!newMsg.trim()}
                  style={{ padding:"6px 12px", background:newMsg.trim()?T.blueGlow:"transparent", border:`1px solid ${newMsg.trim()?T.blue:T.border1}`, color:newMsg.trim()?T.blue:T.text3, cursor:newMsg.trim()?"pointer":"default", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>REPLY</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};


// ── DEV CHAT ───────────────────────────────────────────────────
// ── DEV CHAT SHARED BODY ──────────────────────────────────────
// Renders the message list + input; used by both the drawer and the full page
// ── REGION SCREENSHOT CAPTURE ────────────────────────────────
// Global region capture state — lives outside any component so overlay mounts at root
const _regionCaptureListeners = new Set();
const _regionCaptureState = { active: false, canvas: null };

const triggerRegionCapture = async (onCapture) => {
  try {
    const html2canvas = (await import("https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.esm.min.js").catch(()=>null))?.default;
    if (!html2canvas) { alert("Screenshot library unavailable"); return; }

    // Hide all floating UI
    const floaters = document.querySelectorAll("[data-devchat-ui]");
    floaters.forEach(el => { el.style.visibility = "hidden"; });
    await new Promise(r => setTimeout(r, 100));

    const fullCanvas = await html2canvas(document.body, { scale:1, useCORS:true, logging:false, backgroundColor:"#0a0c0f" });

    // Restore floating UI
    floaters.forEach(el => { el.style.visibility = ""; });

    _regionCaptureState.canvas = fullCanvas;
    _regionCaptureState.onCapture = onCapture;
    _regionCaptureState.active = true;
    _regionCaptureListeners.forEach(fn => fn(true));
  } catch(e) {
    console.error(e);
    document.querySelectorAll("[data-devchat-ui]").forEach(el => { el.style.visibility = ""; });
  }
};

// Root-level overlay component — mounted once at app root, covers entire viewport
const RegionCaptureOverlay = () => {
  const [active, setActive] = useState(false);
  const [rect, setRect]     = useState(null);
  const downPos             = useRef(null);
  const dragging            = useRef(false);

  useEffect(() => {
    const listener = (v) => { setActive(v); setRect(null); };
    _regionCaptureListeners.add(listener);
    return () => _regionCaptureListeners.delete(listener);
  }, []);

  const toRect = (a, b) => ({
    x: Math.min(a.x, b.x), y: Math.min(a.y, b.y),
    w: Math.abs(a.x - b.x), h: Math.abs(a.y - b.y),
  });

  const onMouseDown = (e) => {
    downPos.current = { x: e.clientX, y: e.clientY };
    dragging.current = true;
    setRect(null);
  };
  const onMouseMove = (e) => {
    if (!dragging.current) return;
    setRect(toRect(downPos.current, { x: e.clientX, y: e.clientY }));
  };
  const onMouseUp = (e) => {
    if (!dragging.current) return;
    dragging.current = false;
    const r = toRect(downPos.current, { x: e.clientX, y: e.clientY });
    if (r.w < 8 || r.h < 8) { _regionCaptureState.active = false; setActive(false); return; }
    const dpr = window.devicePixelRatio || 1;
    const crop = document.createElement("canvas");
    crop.width  = r.w * dpr;
    crop.height = r.h * dpr;
    crop.getContext("2d").drawImage(
      _regionCaptureState.canvas,
      r.x * dpr, r.y * dpr, r.w * dpr, r.h * dpr,
      0, 0, r.w * dpr, r.h * dpr
    );
    crop.toBlob(blob => { if (blob) _regionCaptureState.onCapture?.(blob); }, "image/png", 0.92);
    _regionCaptureState.active = false;
    setActive(false);
  };
  const onKeyDown = (e) => { if (e.key === "Escape") { _regionCaptureState.active = false; setActive(false); }};

  if (!active) return null;

  return (
    <div onMouseDown={onMouseDown} onMouseMove={onMouseMove} onMouseUp={onMouseUp}
      onKeyDown={onKeyDown} tabIndex={0} ref={el => el?.focus()}
      style={{ position:"fixed", inset:0, zIndex:999999, cursor:"crosshair",
        background:"rgba(0,0,0,0.35)", userSelect:"none" }}>
      <div style={{ position:"absolute", top:16, left:"50%", transform:"translateX(-50%)",
        background:T.bg1, border:`1px solid ${T.border2}`, padding:"6px 14px",
        fontSize:SZ.micro, color:T.text2, ...MONO, letterSpacing:"0.12em", pointerEvents:"none" }}>
        DRAG TO SELECT REGION · ESC TO CANCEL
      </div>
      {rect && rect.w > 4 && rect.h > 4 && (
        <div style={{ position:"absolute", left:rect.x, top:rect.y, width:rect.w, height:rect.h,
          border:"2px solid #60a5fa", background:"rgba(96,165,250,0.08)", pointerEvents:"none" }}>
          <div style={{ position:"absolute", bottom:-18, right:0, fontSize:9, color:"#60a5fa",
            background:T.bg1, padding:"1px 5px", ...MONO }}>
            {rect.w}×{rect.h}
          </div>
        </div>
      )}
    </div>
  );
};

const useRegionCapture = (onCapture) => {
  const start = () => triggerRegionCapture(onCapture);
  return { start };
};

const DevChatBody = ({ messages, grouped, loading, sending, body, setBody, handleSend, bottomRef, inputRef, currentUser, users, isPage=false, newMessageId=null, onSendWithImage, onSendWithFile }) => {
  const [pendingImage, setPendingImage] = useState(null); // { blob, url }
  const [pendingFile, setPendingFile] = useState(null); // { file, name }
  const fileInputRef = useRef(null);
  const { start: startCapture } = useRegionCapture((blob) => {
    const url = URL.createObjectURL(blob);
    setPendingImage({ blob, url });
    setPendingFile(null);
  });

  // Find the last message sent by me — only that one gets a read/delivered label
  const superAdminIds = users.filter(u=>u.is_super_admin).map(u=>u.id);
  const otherSuperAdmins = superAdminIds.filter(id=>id!==currentUser?.id);
  const myMessages = messages.filter(m=>m.author_id===currentUser?.id);
  const lastMyMsg = myMessages[myMessages.length-1];

  const handleSendWithPending = () => {
    if (pendingImage) {
      onSendWithImage?.(body, pendingImage.blob);
      setPendingImage(null);
    } else if (pendingFile) {
      onSendWithFile?.(body, pendingFile.file);
      setPendingFile(null);
    } else {
      handleSend();
    }
  };

  const inputS = {
    flex:1, background:T.bg3, border:`1px solid ${T.border2}`,
    color:T.text1, padding: isPage ? "9px 12px" : "6px 9px",
    fontSize:SZ.body, ...RAJDHANI, outline:"none",
  };

  const canSend = body.trim() || pendingImage || pendingFile;

  return (
    <div style={{ flex:1, display:"flex", flexDirection:"column", minHeight:0, overflow:"hidden" }}>
      {/* Messages */}
      <div style={{ flex:1, overflowY:"auto", padding: isPage ? "20px 28px" : "10px 12px", display:"flex", flexDirection:"column", gap:2 }}>
        {loading && <div style={{ textAlign:"center", color:T.text3, fontSize:SZ.micro, ...MONO, padding:"20px 0" }}>LOADING…</div>}
        {!loading && messages.length === 0 && (
          <div style={{ textAlign:"center", color:T.text3, fontSize:SZ.small, padding:"48px 16px", lineHeight:1.8 }}>
            <div style={{ fontSize:28, marginBottom:10 }}>💬</div>
            <div>No messages yet.</div>
            <div style={{ fontSize:SZ.micro, ...MONO, marginTop:4, color:T.text3 }}>DEV CHANNEL · SUPER ADMINS ONLY</div>
          </div>
        )}
        {grouped.map((msg) => {
          const author = users.find(u => u.id === msg.author_id);
          const isMe = msg.author_id === currentUser?.id;
          return (
            <div key={msg.id} style={{ marginTop: msg.showHeader ? (isPage?14:10) : 1 }}>
              {msg.showHeader && (
                <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:3, flexDirection: isMe ? "row-reverse" : "row" }}>
                  <Avatar userId={msg.author_id} users={users} size={isPage?24:18}/>
                  <span style={{ fontSize:SZ.micro, color:T.text2, ...MONO, fontWeight:700 }}>{isMe ? "YOU" : author?.name?.split(" ")[0]?.toUpperCase() || "—"}</span>
                  <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>
                    {new Date(msg.created_at).toLocaleString("en-US",{ month:"short", day:"numeric", hour:"numeric", minute:"2-digit" })}
                  </span>
                </div>
              )}
              <div style={{ display:"flex", justifyContent: isMe ? "flex-end" : "flex-start" }}>
                <div style={{
                  maxWidth: isPage ? "60%" : "82%",
                  padding: isPage ? "9px 14px" : "6px 10px",
                  background: (!isMe && msg.id === newMessageId) ? `${T.green}22` : isMe ? T.blueGlow : T.bg3,
                  border:`1px solid ${(!isMe && msg.id === newMessageId) ? T.green+"88" : isMe ? T.blue+"44" : T.border1}`,
                  fontSize:SZ.body, color:T.text1, lineHeight:1.6,
                  wordBreak:"break-word",
                  transition:"background 0.6s ease, border-color 0.6s ease",
                  boxShadow: (!isMe && msg.id === newMessageId) ? `0 0 12px ${T.green}44` : "none",
                }}>
                  {msg.body.includes("[screenshot:") ? (() => {
                    const match = msg.body.match(/\[screenshot:(.*?)\]/);
                    const url = match?.[1];
                    const caption = msg.body.replace(/\[screenshot:.*?\]/, "").trim();
                    return (
                      <>
                        {caption && <div style={{ marginBottom:6, fontSize:SZ.body, lineHeight:1.5 }}>{caption}</div>}
                        {url && <a href={url} target="_blank" rel="noopener noreferrer">
                          <img src={url} alt="screenshot" style={{ maxWidth:"100%", maxHeight:200, display:"block", border:`1px solid ${T.border2}`, cursor:"zoom-in" }}/>
                        </a>}
                      </>
                    );
                  })() : msg.body.includes("[file:") ? (() => {
                    const match = msg.body.match(/\[file:(.*?):(.*?)\]/);
                    const fileName = match?.[1];
                    const fileUrl = match?.[2];
                    const caption = msg.body.replace(/\[file:.*?\]/, "").trim();
                    return (
                      <>
                        {caption && <div style={{ marginBottom:6, fontSize:SZ.body, lineHeight:1.5 }}>{caption}</div>}
                        {fileUrl && (
                          <a href={fileUrl} target="_blank" rel="noopener noreferrer"
                            style={{ display:"inline-flex", alignItems:"center", gap:6, padding:"6px 10px", background:T.bg2, border:`1px solid ${T.border2}`, color:T.blue, textDecoration:"none", fontSize:SZ.small, ...MONO }}>
                            ▤ {fileName || "ATTACHMENT"}
                          </a>
                        )}
                      </>
                    );
                  })() : msg.body}
                </div>
              </div>
              {/* Read/Delivered status — only on last message sent by me */}
              {isMe && lastMyMsg && msg.id === lastMyMsg.id && otherSuperAdmins.length > 0 && (() => {
                const allRead = otherSuperAdmins.every(id=>(msg.read_by||[]).includes(id));
                return (
                  <div style={{ display:"flex", justifyContent:"flex-end", marginTop:2 }}>
                    <span style={{ fontSize:"0.6rem", color:allRead?T.green:T.text3, ...MONO, letterSpacing:"0.1em", fontWeight:700 }}>
                      {allRead ? "READ" : "DELIVERED"}
                    </span>
                  </div>
                );
              })()}
            </div>
          );
        })}
        <div ref={bottomRef}/>
      </div>

      {/* Pending image preview */}
      {pendingImage && (
        <div style={{ padding: isPage ? "0 28px 8px" : "0 12px 6px", flexShrink:0 }}>
          <div style={{ position:"relative", display:"inline-block" }}>
            <img src={pendingImage.url} alt="screenshot" style={{ maxHeight:80, maxWidth:"100%", border:`1px solid ${T.blue}44`, display:"block" }}/>
            <button onClick={()=>setPendingImage(null)}
              style={{ position:"absolute", top:-6, right:-6, width:16, height:16, borderRadius:"50%",
                background:T.red, border:"none", color:"#fff", cursor:"pointer", fontSize:9,
                display:"flex", alignItems:"center", justifyContent:"center", fontWeight:700 }}>✕</button>
            <div style={{ fontSize:9, color:T.blue, ...MONO, marginTop:2 }}>SCREENSHOT ATTACHED</div>
          </div>
        </div>
      )}

      {/* Pending file preview */}
      {pendingFile && (
        <div style={{ padding: isPage ? "0 28px 8px" : "0 12px 6px", flexShrink:0 }}>
          <div style={{ display:"inline-flex", alignItems:"center", gap:8, padding:"6px 10px", background:T.bg3, border:`1px solid ${T.blue}44` }}>
            <span style={{ fontSize:SZ.micro, color:T.blue, ...MONO }}>▤ {pendingFile.file.name}</span>
            <button onClick={()=>setPendingFile(null)}
              style={{ background:"none", border:"none", color:T.red, cursor:"pointer", fontSize:10, fontWeight:700, padding:0 }}>✕</button>
          </div>
        </div>
      )}

      {/* Input */}
      <div style={{ padding: isPage ? "14px 28px" : "8px 12px", borderTop:`1px solid ${T.border1}`, flexShrink:0, display:"flex", gap:6, alignItems:"center" }}>
        {/* Hidden file input */}
        <input ref={fileInputRef} type="file" style={{display:"none"}} onChange={e=>{ if(e.target.files?.[0]){ setPendingFile({file:e.target.files[0]}); setPendingImage(null); } e.target.value=""; }}/>
        {/* Scissors / region capture */}
        <button onClick={startCapture} title="Capture screenshot region (✂)"
          style={{ background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer",
            padding: isPage ? "8px 10px" : "5px 8px", fontSize:14, flexShrink:0, transition:"all 0.1s",
            lineHeight:1 }}
          onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.color=T.text3;}}>
          ✂
        </button>
        {/* Paperclip / file attach */}
        <button onClick={()=>fileInputRef.current?.click()} title="Attach file"
          style={{ background:"none", border:`1px solid ${pendingFile?T.blue:T.border1}`, color:pendingFile?T.blue:T.text3, cursor:"pointer",
            padding: isPage ? "8px 10px" : "5px 8px", fontSize:13, flexShrink:0, transition:"all 0.1s",
            lineHeight:1 }}
          onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
          onMouseLeave={e=>{if(!pendingFile){e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.color=T.text3;}}}>
          ⊕
        </button>
        <input
          ref={inputRef}
          value={body}
          onChange={e => setBody(e.target.value)}
          onKeyDown={e => { if(e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSendWithPending(); }}}
          placeholder={pendingImage ? "Add a caption… (optional)" : pendingFile ? "Add a caption… (optional)" : "Message dev channel…"}
          style={inputS}
          autoFocus={isPage}
        />
        <button onClick={handleSendWithPending} disabled={sending || !canSend}
          style={{
            padding: isPage ? "9px 20px" : "6px 12px",
            background:canSend?T.blueGlow:"transparent",
            border:`1px solid ${canSend?T.blue:T.border1}`,
            color:canSend?T.blue:T.text3,
            cursor:canSend?"pointer":"default",
            fontSize:SZ.micro, ...MONO, fontWeight:700, transition:"all 0.1s", flexShrink:0,
          }}>
          {sending ? "…" : "SEND"}
        </button>
      </div>
    </div>
  );
};

// ── DEV CHAT HOOK — shared state + logic ──────────────────────
const playDevChatSound = () => {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    // Two-tone "blip" — friendly, not jarring
    const play = (freq, startTime, duration, gain=0.12) => {
      const osc = ctx.createOscillator();
      const amp = ctx.createGain();
      osc.connect(amp);
      amp.connect(ctx.destination);
      osc.type = "sine";
      osc.frequency.setValueAtTime(freq, startTime);
      amp.gain.setValueAtTime(0, startTime);
      amp.gain.linearRampToValueAtTime(gain, startTime + 0.01);
      amp.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
      osc.start(startTime);
      osc.stop(startTime + duration);
    };
    const t = ctx.currentTime;
    play(880, t,        0.12);  // A5
    play(1320, t + 0.1, 0.18); // E6
  } catch(e) {}
};

// ── DEV CHAT SINGLETON ────────────────────────────────────────
// Single shared state so drawer + page always show identical data
// with one WebSocket connection between them.
const _dc = {
  messages: [], listeners: new Set(), unreadListeners: new Set(),
  newMsgListeners: new Set(), presenceListeners: new Set(),
  unread: 0, presence: {}, loading: true, ws: null, initialized: false,
  isInitialLoad: true, currentUserId: null,
};

const _dcNotify      = ()  => _dc.listeners.forEach(fn => fn([..._dc.messages]));
const _dcNotifyUnread= ()  => _dc.unreadListeners.forEach(fn => fn(_dc.unread));
const _dcNotifyNew   = (id)=> _dc.newMsgListeners.forEach(fn => fn(id));
const _dcNotifyPres  = ()  => _dc.presenceListeners.forEach(fn => fn({..._dc.presence}));

const _dcInit = (currentUser) => {
  if (_dc.initialized) return;
  _dc.initialized = true;
  _dc.currentUserId = currentUser?.id;

  // Load history
  sb.get("dev_messages?select=*&order=created_at.asc&limit=300")
    .then(d => {
      _dc.messages = d || [];
      _dc.loading = false;
      _dcNotify();
      setTimeout(() => { _dc.isInitialLoad = false; }, 500);
    }).catch(() => { _dc.loading = false; _dc.isInitialLoad = false; });

  // Single WebSocket
  const token = sb.getToken();
  if (!token) return;
  const ws = new WebSocket(`${SUPABASE_URL}/realtime/v1/websocket?vsn=1.0.0&apikey=${SUPABASE_ANON_KEY}`);
  _dc.ws = ws;
  ws.onopen = () => ws.send(JSON.stringify({ topic:"realtime:public:dev_messages", event:"phx_join", payload:{ access_token:token }, ref:"1" }));
  ws.onmessage = (e) => {
    try {
      const msg = JSON.parse(e.data);
      if (msg.event === "INSERT" && msg.payload?.record) {
        const rec = msg.payload.record;
        if (_dc.messages.find(m => m.id === rec.id)) return;
        _dc.messages = [..._dc.messages, rec];
        _dcNotify();
        if (rec.author_id !== _dc.currentUserId) {
          _dc.unread++;
          _dcNotifyUnread();
          if (!_dc.isInitialLoad) {
            playDevChatSound();
            _dcNotifyNew(rec.id);
            setTimeout(() => _dcNotifyNew(null), 2000);
          }
        }
      }
    } catch(e) {}
  };
  setInterval(() => { if(ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify({ topic:"phoenix", event:"heartbeat", payload:{}, ref:"hb" })); }, 20000);
};

const useDevChat = (currentUser) => {
  const [messages, setMessages] = useState(_dc.messages);
  const [body, setBody]         = useState("");
  const [sending, setSending]   = useState(false);
  const [loading, setLoading]   = useState(_dc.loading);
  const [unread, setUnread]     = useState(_dc.unread);
  const [presence, setPresence] = useState(_dc.presence);
  const [newMessageId, setNewMessageId] = useState(null);
  const bottomRef = useRef(null);
  const inputRef  = useRef(null);

  // Boot singleton once
  useEffect(() => { if (currentUser?.id) _dcInit(currentUser); }, [currentUser?.id]);

  // Subscribe to singleton state
  useEffect(() => {
    const onMsgs = (m) => { setMessages(m); setLoading(false); };
    const onUnread = (u) => setUnread(u);
    const onNew = (id) => setNewMessageId(id);
    const onPres = (p) => setPresence(p);
    _dc.listeners.add(onMsgs);
    _dc.unreadListeners.add(onUnread);
    _dc.newMsgListeners.add(onNew);
    _dc.presenceListeners.add(onPres);
    // Sync immediately in case singleton already has data
    setMessages([..._dc.messages]);
    setLoading(_dc.loading);
    setUnread(_dc.unread);
    setPresence({..._dc.presence});
    return () => {
      _dc.listeners.delete(onMsgs);
      _dc.unreadListeners.delete(onUnread);
      _dc.newMsgListeners.delete(onNew);
      _dc.presenceListeners.delete(onPres);
    };
  }, []);

  // Scroll to bottom on new messages
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:"smooth" }); }, [messages]);

  // Presence heartbeat
  useEffect(() => {
    if (!currentUser?.id) return;
    const upsert = () => {
      sb.patch(`user_presence?user_id=eq.${currentUser.id}`, { last_seen: new Date().toISOString() })
        .then(res => { if (!res || res.length === 0) sb.post("user_presence", { user_id: currentUser.id, last_seen: new Date().toISOString() }).catch(()=>{}); })
        .catch(() => sb.post("user_presence", { user_id: currentUser.id, last_seen: new Date().toISOString() }).catch(()=>{}));
    };
    const fetchPresence = () => sb.get("user_presence?select=*").then(rows => {
      const map = {}; (rows||[]).forEach(r => { map[r.user_id] = r.last_seen; });
      _dc.presence = map; _dcNotifyPres();
    }).catch(()=>{});
    fetchPresence();
    upsert();
    const interval = setInterval(() => { upsert(); fetchPresence(); }, 60000);
    const onActivity = () => sb.patch(`user_presence?user_id=eq.${currentUser.id}`, { last_seen: new Date().toISOString() }).catch(()=>{});
    window.addEventListener("mousemove", onActivity, { passive:true });
    window.addEventListener("keydown",   onActivity, { passive:true });
    return () => { clearInterval(interval); window.removeEventListener("mousemove", onActivity); window.removeEventListener("keydown", onActivity); };
  }, [currentUser?.id]);

  const isActive = (userId) => {
    const lastSeen = presence[userId];
    return lastSeen && (Date.now() - new Date(lastSeen).getTime()) < 10 * 60 * 1000;
  };

  const handleSend = async () => {
    if (!body.trim() || sending) return;
    setSending(true);
    try {
      await sb.post("dev_messages", { author_id: currentUser.id, body: body.trim(), read_by: [currentUser.id] });
      setBody("");
    } catch(e) { console.error(e); } finally { setSending(false); }
  };

  const handleSendWithImage = async (caption, blob) => {
    setSending(true);
    try {
      const fileName = `devchat_${Date.now()}.png`;
      const path = `${currentUser.id}/${fileName}`;
      const uploadRes = await fetch(`${SUPABASE_URL}/storage/v1/object/support-attachments/${path}`, {
        method:"POST", headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${sb.getToken()}`, "Content-Type":"image/png" }, body:blob,
      });
      if (!uploadRes.ok) throw new Error("Upload failed");
      const imageUrl = await sb.getSignedUrl(`support-attachments/${path}`, 86400);
      const msgBody = (caption?.trim() ? caption.trim() + "\n" : "") + `[screenshot:${imageUrl}]`;
      await sb.post("dev_messages", { author_id: currentUser.id, body: msgBody, read_by: [currentUser.id] });
      setBody("");
    } catch(e) { console.error(e); } finally { setSending(false); }
  };

  const handleSendWithFile = async (caption, file) => {
    setSending(true);
    try {
      const safeName = file.name.replace(/[^a-zA-Z0-9._-]/g, "-");
      const path = `${currentUser.id}/devchat_${Date.now()}_${safeName}`;
      const uploadRes = await fetch(`${SUPABASE_URL}/storage/v1/object/support-attachments/${path}`, {
        method:"POST", headers:{ "apikey":SUPABASE_ANON_KEY, "Authorization":`Bearer ${sb.getToken()}`, "Content-Type":file.type||"application/octet-stream" }, body:file,
      });
      if (!uploadRes.ok) throw new Error("Upload failed");
      const fileUrl = await sb.getSignedUrl(`support-attachments/${path}`, 86400);
      const msgBody = (caption?.trim() ? caption.trim() + "\n" : "") + `[file:${file.name}:${fileUrl}]`;
      await sb.post("dev_messages", { author_id: currentUser.id, body: msgBody, read_by: [currentUser.id] });
      setBody("");
    } catch(e) { console.error(e); } finally { setSending(false); }
  };

  const markRead = () => {
    _dc.unread = 0; _dcNotifyUnread();
    const unreadMsgs = _dc.messages.filter(m => !m.read_by?.includes(currentUser?.id) && m.author_id !== currentUser?.id);
    for (const m of unreadMsgs) {
      sb.patch(`dev_messages?id=eq.${m.id}`, { read_by:[...(m.read_by||[]), currentUser.id] }).catch(()=>{});
    }
  };

  const grouped = messages.reduce((acc, msg, i) => {
    const prev = messages[i-1];
    const sameAuthor = prev?.author_id === msg.author_id;
    const within2min = prev && (new Date(msg.created_at) - new Date(prev.created_at)) < 120000;
    acc.push({ ...msg, showHeader: !sameAuthor || !within2min });
    return acc;
  }, []);

  return { messages, grouped, body, setBody, sending, loading, unread, setUnread, presence, isActive, handleSend, handleSendWithImage, handleSendWithFile, markRead, bottomRef, inputRef, newMessageId };
};

// ── DEV CHAT FLOATING DRAWER ──────────────────────────────────
const DevChat = ({ currentUser, users, onNavigateToPage, externalOpen, onClose: onExternalClose }) => {
  const [_internalOpen, _setInternalOpen] = useState(false);
  const open = externalOpen !== undefined ? externalOpen : _internalOpen;
  const setOpen = (v) => { const val = typeof v === "function" ? v(open) : v; _setInternalOpen(val); if (!val) onExternalClose?.(); };
  const [size, setSize]   = useState({ w:420, h:560 });
  const [pos, setPos]     = useState(null); // null = default bottom-left anchor; {x,y} = dragged position
  const isResizing        = useRef(false);
  const isDragging        = useRef(false);
  const resizeStart       = useRef({});
  const dragStart         = useRef({});
  const drawerRef         = useRef(null);

  const onDragMouseDown = (e) => {
    // Don't interfere with buttons/inputs inside the header
    if (e.target.closest("button") || e.target.closest("input")) return;
    e.preventDefault();
    isDragging.current = true;
    const rect = drawerRef.current?.getBoundingClientRect();
    dragStart.current = { mx: e.clientX, my: e.clientY, dx: rect?.left ?? 24, dy: rect?.top ?? (window.innerHeight - 80 - size.h) };
    const onMove = (me) => {
      if (!isDragging.current) return;
      const nx = dragStart.current.dx + (me.clientX - dragStart.current.mx);
      const ny = dragStart.current.dy + (me.clientY - dragStart.current.my);
      // Clamp so window stays on screen
      setPos({
        x: Math.max(0, Math.min(window.innerWidth  - size.w, nx)),
        y: Math.max(0, Math.min(window.innerHeight - size.h, ny)),
      });
    };
    const onUp = () => { isDragging.current = false; window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseup", onUp); };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
  };

  const { messages, grouped, body, setBody, sending, loading, unread, setUnread, presence, isActive, handleSend, handleSendWithImage, handleSendWithFile, markRead, bottomRef, inputRef, newMessageId } = useDevChat(currentUser);

  const superAdmins = users.filter(u => u.is_super_admin);

  // Mark read when opened
  useEffect(() => { if (open) { markRead(); inputRef.current?.focus(); } }, [open]);

  // Increment unread only when closed
  // (already handled in useDevChat — but we need to suppress when open)
  useEffect(() => { if (open) setUnread(0); }, [messages, open]);

  // ── Resize drag ───────────────────────────────────────────
  const onResizeMouseDown = (e) => {
    e.preventDefault();
    isResizing.current = true;
    resizeStart.current = { x: e.clientX, y: e.clientY, w: size.w, h: size.h };
    const onMove = (me) => {
      if (!isResizing.current) return;
      const dw = me.clientX - resizeStart.current.x; // dragging right = wider
      const dh = resizeStart.current.y - me.clientY; // dragging up = taller
      setSize({
        w: Math.max(280, Math.min(640, resizeStart.current.w + dw)),
        h: Math.max(320, Math.min(window.innerHeight - 120, resizeStart.current.h + dh)),
      });
    };
    const onUp = () => { isResizing.current = false; window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseup", onUp); };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
  };

  const PresenceRow = () => (
    <div style={{ display:"flex", gap:8, marginTop:6, alignItems:"center" }}>
      {superAdmins.map(u => {
        const active = isActive(u.id);
        const isMe = u.id === currentUser?.id;
        return (
          <div key={u.id} style={{ display:"flex", alignItems:"center", gap:5 }}
            title={active ? `${u.name.split(" ")[0]} · Active` : `${u.name.split(" ")[0]} · Last seen ${presence[u.id] ? new Date(presence[u.id]).toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"}) : "unknown"}`}>
            <div style={{ position:"relative", flexShrink:0 }}>
              <Avatar userId={u.id} users={users} size={20}/>
              <span style={{ position:"absolute", bottom:-1, right:-1, width:8, height:8, borderRadius:"50%", background:active?T.green:T.text3, border:`2px solid ${T.bg1}`, boxShadow:active?`0 0 6px ${T.green}`:"none", transition:"all 0.3s" }}/>
            </div>
            <span style={{ fontSize:SZ.micro, color:active?T.text1:T.text3, ...MONO, fontWeight:active?700:400 }}>
              {isMe ? "YOU" : u.name.split(" ")[0].toUpperCase()}
            </span>
            {active && !isMe && <span style={{ fontSize:9, color:T.green, ...MONO }}>ACTIVE</span>}
          </div>
        );
      })}
    </div>
  );

  return (
    <>
      {/* Drawer */}
      {open && (
        <div ref={drawerRef} data-devchat-ui style={{
          position:"fixed",
          ...(pos ? { left:pos.x, top:pos.y } : { bottom:0, left:"15rem" }),
          zIndex:9001,
          width:size.w, height:size.h, background:T.bg1,
          border:`1px solid ${T.border2}`, display:"flex", flexDirection:"column",
          clipPath:"polygon(0 0, calc(100% - 10px) 0, 100% 10px, 100% 100%, 0 100%)",
          boxShadow:"0 8px 32px rgba(0,0,0,0.5)",
          animation:"slideUpIn 0.15s ease-out",
          userSelect: (isResizing.current || isDragging.current) ? "none" : "auto",
        }}>

          {/* Resize handle — top-right corner, drag right/up to expand */}
          <div onMouseDown={onResizeMouseDown}
            style={{ position:"absolute", top:0, right:0, width:20, height:20, cursor:"ne-resize", zIndex:10,
              display:"flex", alignItems:"center", justifyContent:"center", opacity:0.35 }}
            title="Drag to resize"
            onMouseEnter={e=>e.currentTarget.style.opacity="1"}
            onMouseLeave={e=>e.currentTarget.style.opacity="0.35"}>
            <svg width="10" height="10" viewBox="0 0 10 10">
              <line x1="2" y1="8" x2="8" y2="2" stroke={T.text3} strokeWidth="1.5"/>
              <line x1="2" y1="2" x2="8" y2="2" stroke={T.text3} strokeWidth="1.5"/>
              <line x1="8" y1="2" x2="8" y2="8" stroke={T.text3} strokeWidth="1.5"/>
            </svg>
          </div>

          {/* Header — drag handle */}
          <div onMouseDown={onDragMouseDown}
            style={{ padding:"10px 14px 8px", borderBottom:`1px solid ${T.border1}`, flexShrink:0, cursor:"grab", userSelect:"none" }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between" }}>
              <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                <span style={{ fontSize:14 }}>💬</span>
                <span style={{ fontSize:SZ.small, fontWeight:700, color:T.text0, ...MONO, letterSpacing:"0.08em" }}>DEV CHANNEL</span>
                <span style={{ fontSize:SZ.micro, color:T.green, ...MONO }}>● LIVE</span>
              </div>
              <div style={{ display:"flex", gap:6, alignItems:"center" }}>
                {/* Pop out to new window */}
                <button onClick={() => {
                    const w = window.open("", "devchat", `width=420,height=600,left=${window.screen.width - 460},top=60,resizable=yes,scrollbars=no,toolbar=no,menubar=no,location=no,status=no`);
                    if (!w) return;
                    // Write a minimal shell that loads the same app in chat-only mode
                    w.document.write(`<!DOCTYPE html>
<html>
<head>
  <title>AdvisorHUD · Dev Channel</title>
  <style>
    * { margin:0; padding:0; box-sizing:border-box; }
    body { background:#0a0c0f; color:#e2e8f0; font-family:'Inter',system-ui,sans-serif; height:100vh; display:flex; flex-direction:column; }
    #msg { flex:1; overflow-y:auto; padding:16px; display:flex; flex-direction:column; gap:4px; }
    .bubble { max-width:80%; padding:8px 12px; font-size:13px; line-height:1.5; word-break:break-word; }
    .me { align-self:flex-end; background:#1e3a5f; border:1px solid #2d5f9e44; }
    .them { align-self:flex-start; background:#1a1d24; border:1px solid #2a2d35; }
    .hdr { font-size:10px; font-family:'JetBrains Mono',monospace; color:#64748b; margin-bottom:3px; }
    #footer { padding:12px; border-top:1px solid #1e2130; display:flex; gap:8px; flex-shrink:0; background:#0d1017; }
    #input { flex:1; background:#1a1d24; border:1px solid #2a2d35; color:#e2e8f0; padding:8px 10px; font-size:13px; outline:none; font-family:'Inter',system-ui,sans-serif; }
    #send { padding:8px 16px; background:#1e3a5f; border:1px solid #2d5f9e; color:#60a5fa; cursor:pointer; font-size:11px; font-family:'JetBrains Mono',monospace; font-weight:700; letter-spacing:0.1em; }
    #send:disabled { opacity:0.4; cursor:default; }
    #topbar { padding:10px 14px; border-bottom:1px solid #1e2130; display:flex; align-items:center; gap:8px; background:#0d1017; flex-shrink:0; }
    #topbar span { font-size:11px; font-family:'JetBrains Mono',monospace; font-weight:700; letter-spacing:0.1em; color:#94a3b8; }
    .dot { width:7px; height:7px; border-radius:50%; background:#3dba7a; box-shadow:0 0 6px #3dba7a; display:inline-block; }
  </style>
</head>
<body>
  <div id="topbar"><span class="dot"></span><span>DEV CHANNEL · LIVE</span></div>
  <div id="msg"></div>
  <div id="footer">
    <input id="input" placeholder="Message dev channel…" />
    <button id="send">SEND</button>
  </div>
  <script>
    const SUPABASE_URL = "${SUPABASE_URL}";
    const SUPABASE_ANON_KEY = "${SUPABASE_ANON_KEY}";
    const TOKEN = "${sb.getToken()}";
    const ME_ID = "${currentUser?.id}";
    const ME_NAME = "${currentUser?.name}";

    const msgEl = document.getElementById("msg");
    const input = document.getElementById("input");
    const sendBtn = document.getElementById("send");

    const headers = { "Content-Type":"application/json", "apikey":SUPABASE_ANON_KEY, "Authorization":"Bearer "+TOKEN };

    // Load history
    fetch(SUPABASE_URL+"/rest/v1/dev_messages?select=*&order=created_at.asc&limit=300", { headers })
      .then(r=>r.json()).then(msgs => { msgs.forEach(addBubble); scrollBottom(); });

    function addBubble(msg) {
      const isMe = msg.author_id === ME_ID;
      const wrap = document.createElement("div");
      wrap.style.display = "flex";
      wrap.style.flexDirection = "column";
      wrap.style.alignItems = isMe ? "flex-end" : "flex-start";
      wrap.style.marginTop = "8px";
      const hdr = document.createElement("div");
      hdr.className = "hdr";
      hdr.textContent = (isMe ? "YOU" : "") + " · " + new Date(msg.created_at).toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"});
      const b = document.createElement("div");
      b.className = "bubble " + (isMe ? "me" : "them");
      // Render screenshot images instead of raw [screenshot:url] text
      const screenshotMatch = msg.body && msg.body.match(/\[screenshot:(.*?)\]/);
      if (screenshotMatch) {
        const url = screenshotMatch[1];
        const caption = msg.body.replace(/\[screenshot:.*?\]/, "").trim();
        if (caption) { const t = document.createElement("div"); t.textContent = caption; t.style.marginBottom = "6px"; b.appendChild(t); }
        const a = document.createElement("a"); a.href = url; a.target = "_blank";
        const img = document.createElement("img"); img.src = url; img.alt = "screenshot";
        img.style.cssText = "max-width:100%;max-height:200px;display:block;border:1px solid #2a2d35;cursor:zoom-in;";
        a.appendChild(img); b.appendChild(a);
      } else {
        b.textContent = msg.body;
      }
      wrap.appendChild(hdr);
      wrap.appendChild(b);
      msgEl.appendChild(wrap);
    }

    function scrollBottom() { msgEl.scrollTop = msgEl.scrollHeight; }

    // Realtime
    const ws = new WebSocket(SUPABASE_URL.replace("https","wss")+"/realtime/v1/websocket?vsn=1.0.0&apikey="+SUPABASE_ANON_KEY);
    ws.onopen = () => ws.send(JSON.stringify({topic:"realtime:public:dev_messages",event:"phx_join",payload:{access_token:TOKEN},ref:"1"}));
    ws.onmessage = (e) => {
      try {
        const m = JSON.parse(e.data);
        if (m.event === "INSERT" && m.payload?.record) {
          addBubble(m.payload.record);
          scrollBottom();
          // Play blip
          try {
            const ctx = new AudioContext();
            [880,1320].forEach((f,i) => {
              const o=ctx.createOscillator(), g=ctx.createGain();
              o.connect(g); g.connect(ctx.destination);
              o.frequency.value=f; g.gain.setValueAtTime(0,ctx.currentTime+i*0.1);
              g.gain.linearRampToValueAtTime(0.1,ctx.currentTime+i*0.1+0.01);
              g.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+i*0.1+0.2);
              o.start(ctx.currentTime+i*0.1); o.stop(ctx.currentTime+i*0.1+0.2);
            });
          } catch(e){}
        }
      } catch(e){}
    };
    setInterval(()=>{ if(ws.readyState===1) ws.send(JSON.stringify({topic:"phoenix",event:"heartbeat",payload:{},ref:"hb"})); },20000);

    // Send
    async function sendMsg() {
      const body = input.value.trim();
      if (!body) return;
      sendBtn.disabled = true;
      input.value = "";
      await fetch(SUPABASE_URL+"/rest/v1/dev_messages", {
        method:"POST", headers:{...headers,"Prefer":"return=representation"},
        body: JSON.stringify({ author_id:ME_ID, body, read_by:[ME_ID] })
      });
      sendBtn.disabled = false;
      input.focus();
    }
    sendBtn.onclick = sendMsg;
    input.onkeydown = (e) => { if(e.key==="Enter"&&!e.shiftKey){ e.preventDefault(); sendMsg(); }};
    input.focus();
  </script>
</body>
</html>`);
                    w.document.close();
                  }}
                  title="Pop out to new window"
                  style={{ background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer",
                    fontSize:SZ.micro, ...MONO, padding:"2px 7px", transition:"all 0.1s" }}
                  onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
                  onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.color=T.text3;}}>
                  ⧉ POP OUT
                </button>
                {/* Open full page */}
                <button onClick={() => { setOpen(false); onNavigateToPage(); }}
                  title="Open full page"
                  style={{ background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer",
                    fontSize:SZ.micro, ...MONO, padding:"2px 7px", transition:"all 0.1s" }}
                  onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
                  onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.color=T.text3;}}>
                  ⤢ EXPAND
                </button>
                <button onClick={() => { setOpen(false); }}
                  title="Close"
                  style={{ background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer",
                    fontSize:SZ.small, ...MONO, padding:"2px 8px", transition:"all 0.1s", userSelect:"none" }}
                  onMouseEnter={e=>{e.currentTarget.style.borderColor=T.red;e.currentTarget.style.color=T.red;}}
                  onMouseLeave={e=>{e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.color=T.text3;}}>✕</button>
              </div>
            </div>
            <PresenceRow/>
          </div>

          <DevChatBody messages={messages} grouped={grouped} loading={loading} sending={sending}
            body={body} setBody={setBody} handleSend={handleSend}
            bottomRef={bottomRef} inputRef={inputRef} currentUser={currentUser} users={users} newMessageId={newMessageId}
            onSendWithImage={handleSendWithImage} onSendWithFile={handleSendWithFile}/>
        </div>
      )}
    </>
  );
};

// ── DEV CHANNEL FULL PAGE ─────────────────────────────────────
const DevChannelPage = ({ currentUser, users }) => {
  const { messages, grouped, body, setBody, sending, loading, presence, isActive, handleSend, handleSendWithImage, handleSendWithFile, markRead, bottomRef, inputRef, newMessageId } = useDevChat(currentUser);
  const superAdmins = users.filter(u => u.is_super_admin);

  useEffect(() => { markRead(); }, []);
  // Scroll to bottom on mount and when messages load
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:"instant" }); }, [loading]);

  return (
    <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column", overflow:"hidden", background:T.bg0 }}>
      {/* Header */}
        <div style={{ padding:"20px 28px 14px", borderBottom:`1px solid ${T.border1}`, flexShrink:0 }}>
          <SectionLabel>DEV CHANNEL</SectionLabel>
          <div style={{ fontSize:SZ.label, color:T.text3, ...MONO, marginTop:2, marginBottom:12 }}>SUPER ADMIN · INTERNAL · REAL-TIME</div>
          {/* Presence row */}
          <div style={{ display:"flex", gap:16, alignItems:"center" }}>
            {superAdmins.map(u => {
              const active = isActive(u.id);
              const isMe = u.id === currentUser?.id;
              return (
                <div key={u.id} style={{ display:"flex", alignItems:"center", gap:8 }}
                  title={active ? "Active now" : `Last seen ${presence[u.id] ? new Date(presence[u.id]).toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"}) : "unknown"}`}>
                  <div style={{ position:"relative" }}>
                    <Avatar userId={u.id} users={users} size={32}/>
                    <span style={{ position:"absolute", bottom:0, right:0, width:10, height:10, borderRadius:"50%",
                      background:active?T.green:T.text3, border:`2px solid ${T.bg0}`,
                      boxShadow:active?`0 0 8px ${T.green}`:"none", transition:"all 0.3s" }}/>
                  </div>
                  <div>
                    <div style={{ fontSize:SZ.body, color:active?T.text0:T.text2, fontWeight:600 }}>{isMe?"You":u.name}</div>
                    <div style={{ fontSize:SZ.micro, color:active?T.green:T.text3, ...MONO }}>
                      {active ? "● ACTIVE NOW" : presence[u.id] ? `LAST SEEN ${new Date(presence[u.id]).toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"})}` : "OFFLINE"}
                    </div>
                  </div>
                </div>
              );
            })}
            <div style={{ marginLeft:"auto", fontSize:SZ.micro, color:T.text3, ...MONO }}>
              {messages.length} MESSAGE{messages.length!==1?"S":""}
            </div>
          </div>
        </div>

        {/* New message flash banner */}
        {newMessageId && (
          <div style={{
            padding:"7px 28px", background:`${T.green}18`, borderBottom:`1px solid ${T.green}44`,
            display:"flex", alignItems:"center", gap:8, flexShrink:0,
            animation:"fadeIn 0.2s ease-out",
          }}>
            <span style={{ fontSize:10, color:T.green }}>●</span>
            <span style={{ fontSize:SZ.micro, color:T.green, ...MONO, fontWeight:700, letterSpacing:"0.12em" }}>NEW MESSAGE</span>
          </div>
        )}
        <DevChatBody messages={messages} grouped={grouped} loading={loading} sending={sending}
          body={body} setBody={setBody} handleSend={handleSend}
          bottomRef={bottomRef} inputRef={inputRef} currentUser={currentUser} users={users} isPage={true} newMessageId={newMessageId}
          onSendWithImage={handleSendWithImage} onSendWithFile={handleSendWithFile}/>
    </div>
  );
};

// ── MENTION TEXTAREA ────────────────────────────────────────────
const MentionTextarea = ({ value, onChange, onSubmit, placeholder, users, rows=3, style={} }) => {
  const [mentionQuery, setMentionQuery] = useState("");
  const [mentionOpen, setMentionOpen] = useState(false);
  const [mentionPos, setMentionPos] = useState(0); // caret position when @ was typed
  const [dropdownPos, setDropdownPos] = useState({ top:0, left:0 });
  const textareaRef = useRef(null);

  const filteredUsers = mentionOpen
    ? users.filter(u => u.name.toLowerCase().includes(mentionQuery.toLowerCase()) && u.active && !u.is_super_admin).slice(0,6)
    : [];

  const handleChange = (e) => {
    const val = e.target.value;
    const caret = e.target.selectionStart;
    onChange(val);

    // detect @ trigger
    const textBeforeCaret = val.slice(0, caret);
    const match = textBeforeCaret.match(/@(\w*)$/);
    if (match) {
      setMentionQuery(match[1]);
      setMentionPos(caret - match[0].length);
      setMentionOpen(true);
      // position dropdown near caret — approximate
      const ta = textareaRef.current;
      if (ta) {
        const rect = ta.getBoundingClientRect();
        setDropdownPos({ top: rect.bottom + window.scrollY - 4, left: rect.left + 12 });
      }
    } else {
      setMentionOpen(false);
      setMentionQuery("");
    }
  };

  const insertMention = (user) => {
    const before = value.slice(0, mentionPos);
    const after = value.slice(mentionPos + mentionQuery.length + 1); // +1 for @
    const newVal = before + `@${user.name} ` + after;
    onChange(newVal);
    setMentionOpen(false);
    setMentionQuery("");
    setTimeout(()=>textareaRef.current?.focus(), 0);
  };

  const handleKeyDown = (e) => {
    if (mentionOpen && (e.key === "Escape")) { setMentionOpen(false); return; }
    if (e.key === "Enter" && (e.metaKey || e.ctrlKey) && value.trim()) { onSubmit(); return; }
  };

  // Parse comment body — highlight @mentions
  const renderBody = (text) => {
    if (!text) return null;
    const parts = text.split(/(@[\w\s]+?)(?=\s|$|@)/g);
    return parts.map((p, i) => {
      if (p.startsWith("@")) {
        const name = p.slice(1).trim();
        const matched = users.find(u => u.name.toLowerCase() === name.toLowerCase());
        if (matched) return <span key={i} style={{ color:T.blue, fontWeight:600, background:`${T.blue}18`, padding:"0 3px", borderRadius:2 }}>{p}</span>;
      }
      return <span key={i}>{p}</span>;
    });
  };

  return (
    <div style={{ position:"relative" }}>
      <textarea
        ref={textareaRef}
        value={value}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        rows={rows}
        placeholder={placeholder}
        style={{ ...style, resize:"vertical", lineHeight:"1.5" }}
      />
      {mentionOpen && filteredUsers.length > 0 && (
        <div style={{ position:"fixed", top:dropdownPos.top, left:dropdownPos.left, background:T.bg2, border:`1px solid ${T.blue}44`, zIndex:9999, minWidth:200, boxShadow:`0 8px 24px ${T.bg0}99` }}>
          <div style={{ padding:"5px 10px", fontSize:SZ.micro, color:T.text2, ...MONO, letterSpacing:"0.12em", borderBottom:`1px solid ${T.border0}` }}>MENTION USER</div>
          {filteredUsers.map(u => (
            <div key={u.id} onClick={()=>insertMention(u)}
              style={{ display:"flex", alignItems:"center", gap:9, padding:"8px 12px", cursor:"pointer", transition:"background 0.1s" }}
              onMouseEnter={e=>e.currentTarget.style.background=T.bg3}
              onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
              <div style={{ width:24, height:24, background:T.blue, display:"flex", alignItems:"center", justifyContent:"center", fontSize:SZ.micro, fontWeight:700, color:T.bg0, ...MONO, flexShrink:0 }}>{u.initials}</div>
              <div>
                <div style={{ fontSize:SZ.small, fontWeight:600, color:T.text0, ...INTER }}>{u.name}</div>
                <div style={{ fontSize:SZ.micro, color:T.text2, ...MONO }}>{u.role?.toUpperCase()}</div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};
MentionTextarea.renderBody = (text, users) => {
  if (!text) return null;
  const parts = text.split(/(@[\w][\w ]*)/g);
  return parts.map((p, i) => {
    if (p.startsWith("@")) {
      const name = p.slice(1).trim();
      const matched = users?.find(u => u.name.toLowerCase() === name.toLowerCase());
      if (matched) return <span key={i} style={{ color:T.blue, fontWeight:600, background:`${T.blue}18`, padding:"0 3px" }}>{p}</span>;
    }
    return <span key={i}>{p}</span>;
  });
};


// ── TOAST NOTIFICATION ─────────────────────────────────────────
const ToastNotification = ({ toasts, onDismiss }) => {
  if (!toasts.length) return null;
  return (
    <div style={{ position:"fixed", bottom:24, left:24, zIndex:9999, display:"flex", flexDirection:"column-reverse", gap:10, maxWidth:340 }}>
      {toasts.map(t => {
        const meta = {
          assigned:        { glyph:"◑", color:T.blue   },
          mention:         { glyph:"@",  color:T.purple },
          resolved:        { glyph:"✓",  color:T.green  },
          task_complete:   { glyph:"✓",  color:T.green  },
          phase_complete:  { glyph:"◈",  color:T.blue   },
          mission_complete:{ glyph:"◈",  color:T.green  },
          urgent:          { glyph:"⚑",  color:T.red    },
          comment:         { glyph:"◉",  color:T.text2  },
          playbook_step:   { glyph:"▣",  color:T.amber  },
          new_request:     { glyph:"◉",  color:T.blue   },
          status_update:   { glyph:"◈",  color:T.amber  },
          mission_launched:{ glyph:"▣",  color:T.teal   },
          overdue:         { glyph:"⚑",  color:T.red    },
          ticket_update:   { glyph:"◉",  color:T.text2  },
        }[t.type] || { glyph:"◈", color:T.blue };
        return (
          <div key={t.id} style={{
            background:T.bg2, border:`1px solid ${meta.color}44`,
            borderLeft:`3px solid ${meta.color}`,
            padding:"12px 14px", display:"flex", alignItems:"flex-start", gap:10,
            boxShadow:`0 4px 24px rgba(0,0,0,0.5)`,
            animation:"toast-in 0.2s ease",
          }}>
            <span style={{ color:meta.color, fontSize:14, marginTop:1, flexShrink:0, ...MONO }}>{meta.glyph}</span>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:SZ.small, color:T.text1, lineHeight:"1.5", ...INTER }}>{t.body}</div>
              <div style={{ fontSize:"0.6rem", color:T.text3, marginTop:4, letterSpacing:"0.1em", ...MONO }}>JUST NOW</div>
            </div>
            <button onClick={()=>onDismiss(t.id)} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:12, padding:0, flexShrink:0, lineHeight:1 }}>✕</button>
          </div>
        );
      })}
    </div>
  );
};

// ── NOTIFICATION BELL ───────────────────────────────────────────
const NotificationBell = ({ currentUser, users, setView, setSelectedRequestId, setSelectedMissionId, setSelectedTicketId }) => {
  const [notifs, setNotifs] = useState([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [btnRect, setBtnRect] = useState(null);
  const [toasts, setToasts] = useState([]);
  const btnRef = useRef(null);
  const unread = notifs.filter(n=>!n.read).length;

  const dismissToast = (id) => setToasts(prev=>prev.filter(t=>t.id!==id));

  const showToast = (notif) => {
    const id = notif.id || `toast-${Date.now()}`;
    setToasts(prev=>[...prev, { ...notif, id }]);
    setTimeout(()=>dismissToast(id), 6000);
  };

  const load = async () => {
    if (!currentUser?.id) return;
    setLoading(true);
    try { const data = await api.getNotifications(currentUser.id); setNotifs(data||[]); }
    catch(e){ console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(()=>{
    load();
    if (!currentUser?.id) return;
    const t = setInterval(load, 5000);
    return () => clearInterval(t);
  },[currentUser?.id]);

  const handleOpen = () => {
    if (btnRef.current) setBtnRect(btnRef.current.getBoundingClientRect());
    setOpen(o=>!o);
    if(!open) load();
  };

  const NOTIF_META = {
    assigned:                { glyph:"◑", color:T.blue   },
    mention:                 { glyph:"@",  color:T.purple },
    resolved:                { glyph:"✓",  color:T.green  },
    task_complete:           { glyph:"✓",  color:T.green  },
    phase_complete:          { glyph:"◈",  color:T.blue   },
    mission_complete:        { glyph:"◈",  color:T.green  },
    urgent:                  { glyph:"⚑",  color:T.red    },
    comment:                 { glyph:"◉",  color:T.text2  },
    playbook_step:           { glyph:"▣",  color:T.amber  },
    new_request:             { glyph:"◉",  color:T.blue   },
    status_update:           { glyph:"◈",  color:T.amber  },
    mission_launched:        { glyph:"▣",  color:T.teal   },
    overdue:                 { glyph:"⚑",  color:T.red    },
    ticket_update:           { glyph:"◉",  color:T.text2  },
    // Notification engine types
    request_assigned:        { glyph:"◑",  color:T.blue   },
    compliance_flag:         { glyph:"⚑",  color:T.red    },
    onboarding_phase_complete:{ glyph:"◈", color:T.blue   },
    onboarding_complete:     { glyph:"◈",  color:T.green  },
    project_assigned:        { glyph:"▣",  color:T.blue   },
    project_complete:        { glyph:"✓",  color:T.green  },
    project_overdue:         { glyph:"⚑",  color:T.red    },
    project_due_soon:        { glyph:"⚑",  color:T.amber  },
    milestone_complete:      { glyph:"✓",  color:T.green  },
    milestone_overdue:       { glyph:"⚑",  color:T.amber  },
  };

  const handleClick = async (n) => {
    if (!n.read) await api.markNotificationRead(n.id).catch(()=>{});
    setNotifs(prev=>prev.map(x=>x.id===n.id?{...x,read:true}:x));
    if (n.link_type==="request" && n.link_id) {
      setSelectedRequestId(n.link_id);
      setView("requests");
    } else if (n.link_type==="mission" && n.link_id) {
      setSelectedMissionId?.(n.link_id);
    } else if (n.link_type==="support" && n.link_id) {
      setSelectedTicketId?.(n.link_id);
      setView("support");
    } else if (n.link_type==="project" && n.link_id) {
      setView("projects");
    }
    setOpen(false);
  };

  const markAllRead = async () => {
    await api.markAllNotificationsRead(currentUser.id).catch(()=>{});
    setNotifs(prev=>prev.map(n=>({...n,read:true})));
  };

  const clearAll = async () => {
    await api.clearNotifications(currentUser.id).catch(()=>{});
    setNotifs([]);
  };

  const fmtAge = (d) => {
    const mins = Math.floor((Date.now()-new Date(d))/60000);
    if (mins < 1) return "just now";
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins/60);
    if (hrs < 24) return `${hrs}h ago`;
    return `${Math.floor(hrs/24)}d ago`;
  };

  return (
    <div style={{ position:"relative" }}>
      <button ref={btnRef} onClick={handleOpen} title="Notifications" style={{ background:"none", border:`1px solid ${unread>0?T.blue:T.border1}`, color:unread>0?T.blue:T.text3, cursor:"pointer", padding:"3px 8px", ...MONO, fontSize:SZ.small, position:"relative", transition:"all 0.15s" }}
        onMouseEnter={e=>{e.currentTarget.style.borderColor=T.blue;e.currentTarget.style.color=T.blue;}}
        onMouseLeave={e=>{e.currentTarget.style.borderColor=unread>0?T.blue:T.border1;e.currentTarget.style.color=unread>0?T.blue:T.text3;}}>
        ◉
        {unread > 0 && (
          <span className="notif-badge-pulse" style={{ position:"absolute", top:-5, right:-5, background:T.red, color:T.white, borderRadius:"50%", width:16, height:16, fontSize:9, display:"flex", alignItems:"center", justifyContent:"center", fontWeight:700, ...MONO }}>{unread>9?"9+":unread}</span>
        )}
      </button>
      {open && (
        <div style={{ position:"fixed", top:0, left:0, right:0, bottom:0, zIndex:9990 }} onClick={()=>setOpen(false)}/>
      )}
      {open && (
        <div style={{ position:"fixed", ...(window.innerWidth < 768 ? { bottom:60, left:8, right:8, width:"auto" } : { bottom: btnRect ? (window.innerHeight - btnRect.top + 8) : 60, left: btnRect ? Math.max(8, btnRect.left - 280) : 8, width:320 }), background:T.bg2, border:`1px solid ${T.border2}`, zIndex:9999, boxShadow:`0 8px 32px ${T.bg0}cc` }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 14px", borderBottom:`1px solid ${T.border1}` }}>
            <div style={{ fontSize:SZ.small, fontWeight:700, color:T.text0, ...MONO, letterSpacing:"0.14em" }}>NOTIFICATIONS{unread>0&&<span style={{color:T.red,marginLeft:6}}>{unread} NEW</span>}</div>
            <div style={{ display:"flex", gap:8 }}>
              {unread>0&&<button onClick={markAllRead} style={{ fontSize:SZ.micro, color:T.text3, ...MONO, background:"none", border:"none", cursor:"pointer", letterSpacing:"0.1em" }} onMouseEnter={e=>e.currentTarget.style.color=T.blue} onMouseLeave={e=>e.currentTarget.style.color=T.text3}>READ ALL</button>}
              {notifs.length>0&&<button onClick={clearAll} style={{ fontSize:SZ.micro, color:T.text3, ...MONO, background:"none", border:"none", cursor:"pointer", letterSpacing:"0.1em" }} onMouseEnter={e=>e.currentTarget.style.color=T.red} onMouseLeave={e=>e.currentTarget.style.color=T.text3}>CLEAR</button>}
            </div>
          </div>
          <div style={{ maxHeight:400, overflowY:"auto", display:"flex", flexDirection:"column-reverse" }}>
            {loading && <div style={{ padding:"20px 14px", color:T.text2, ...MONO, fontSize:SZ.small, textAlign:"center" }}>LOADING...</div>}
            {!loading && notifs.length===0 && (
              <div style={{ padding:"24px 14px", textAlign:"center" }}>
                <div style={{ fontSize:SZ.head, marginBottom:6, opacity:0.3 }}>◉</div>
                <div style={{ fontSize:SZ.small, color:T.text2, ...MONO }}>NO NOTIFICATIONS</div>
              </div>
            )}
            {notifs.map(n=>{
              const meta = NOTIF_META[n.type] || { glyph:"◉", color:T.text2 };
              return (
              <div key={n.id} onClick={()=>handleClick(n)} style={{ padding:"10px 14px", borderBottom:`1px solid ${T.border0}`, cursor:"pointer", background:n.read?"transparent":T.blueGlow, borderLeft:`3px solid ${n.read?"transparent":meta.color}`, transition:"background 0.1s" }}
                onMouseEnter={e=>e.currentTarget.style.background=T.bg3}
                onMouseLeave={e=>e.currentTarget.style.background=n.read?"transparent":T.blueGlow}>
                <div style={{ display:"flex", gap:8, alignItems:"flex-start" }}>
                  <span style={{ fontSize:SZ.small, color:meta.color, flexShrink:0, marginTop:1 }}>{meta.glyph}</span>
                  <div>
                    <div style={{ fontSize:SZ.small, color:n.read?T.text2:T.text0, ...INTER, lineHeight:1.4, marginBottom:4 }}>{n.body}</div>
                    <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{fmtAge(n.created_at)}{n.link_type&&<span style={{marginLeft:6,color:meta.color,opacity:0.7}}>→ {n.link_type.toUpperCase()}</span>}</div>
                  </div>
                </div>
              </div>
            );})}
          </div>
        </div>
      )}
      <ToastNotification toasts={toasts} onDismiss={dismissToast}/>
    </div>
  );
};

// ── AWACS VIEW ─────────────────────────────────────────────────
// AI: AWACS is the ops radar — firm-wide operational overview. Stat cards show active missions, open requests, alerts (overdue + blocked), and open tickets. Each card is clickable and routes to the relevant view. First stop every morning for ops and admin.
// ── SIGNALS ENGINE ─────────────────────────────────────────────
// Computes ranked proactive observations from all firm data.
// Returns array of signal objects sorted by severity.
// Conservative: only fires on clearly broken situations.
// Each signal: { id, type, severity, title, body, action, actionLabel, entityId }

const SIGNAL_TYPES = {
  ONBOARDING_PACE:   { icon:"▣", color:"#e09d3a", group:"onboarding" },
  ONBOARDING_STALL:  { icon:"⚑", color:"#d44f42", group:"onboarding" },
  HOUSEHOLD_STALE:   { icon:"☎", color:"#e09d3a", group:"clients", label:"Client Relationship" },
  PIPELINE_COLD:     { icon:"◈", color:"#9b7dc8", group:"pipeline"   },
  REQUEST_STALE:     { icon:"◉", color:"#e09d3a", group:"requests"   },
  REQUEST_URGENT:    { icon:"⚑", color:"#d44f42", group:"requests"   },
};

function computeSignals({ instances=[], households=[], pipelineCards=[], pipelineStages=[], requests=[], firmSettings={} }) {
  const sigs = [];
  const now = Date.now();

  // ── Onboarding pace risk ──────────────────────────────────────
  instances.filter(i=>i.status==="active"&&i.target_date).forEach(inst => {
    const tasks = inst.phases.flatMap(p=>p.tasks);
    const total = tasks.length;
    if (!total) return;
    const done = tasks.filter(t=>t.status==="completed").length;
    const pct = Math.round((done/total)*100);
    const daysLeft = Math.round((new Date(inst.target_date+"T12:00:00") - now) / 86400000);
    const daysElapsed = inst.start_date ? Math.round((now - new Date(inst.start_date)) / 86400000) : null;

    // Overdue — past go-live date
    if (daysLeft < 0 && pct < 100) {
      sigs.push({
        id: `overdue-${inst.id}`,
        type: "ONBOARDING_STALL",
        severity: 1,
        title: `${inst.advisor_name} is past go-live date`,
        body: `${Math.abs(daysLeft)} days overdue · ${pct}% complete. Immediate attention required.`,
        actionLabel: "View Onboarding",
        entityId: inst.id,
        entityType: "mission",
      });
      return;
    }

    // Pace risk — behind schedule based on elapsed vs completion ratio
    if (daysLeft > 0 && daysElapsed > 14 && total > 0) {
      const expectedPct = Math.min(95, Math.round(((daysElapsed) / (daysElapsed + daysLeft)) * 100));
      if (pct < expectedPct - 20) { // 20pt behind expected — meaningful gap
        const blockedTasks = tasks.filter(t=>t.status==="blocked");
        const overdueTasks = tasks.filter(t=>t.status!=="completed"&&t.due_date&&new Date(t.due_date)<now);
        const bottleneck = inst.phases.find(p=>p.tasks.some(t=>t.status==="blocked"||isOverdue(t)));
        sigs.push({
          id: `pace-${inst.id}`,
          type: "ONBOARDING_PACE",
          severity: 2,
          title: `${inst.advisor_name}'s onboarding is behind pace`,
          body: `${pct}% complete with ${daysLeft} days to go-live. Expected ~${expectedPct}%.${bottleneck?` Bottleneck: ${bottleneck.name}.`:""}${blockedTasks.length?` ${blockedTasks.length} blocked.`:""}${overdueTasks.length?` ${overdueTasks.length} overdue.`:""}`,
          actionLabel: "View Onboarding",
          entityId: inst.id,
          entityType: "mission",
        });
      }
    }

    // Stall — no task completed in last 7 days and not close to done
    if (pct < 90 && daysLeft > 3) {
      const recentlyCompleted = tasks.filter(t => {
        if (t.status !== "completed" || !t.completed_date) return false;
        return Math.round((now - new Date(t.completed_date)) / 86400000) <= 7;
      });
      if (recentlyCompleted.length === 0 && daysElapsed > 7) {
        sigs.push({
          id: `stall-${inst.id}`,
          type: "ONBOARDING_STALL",
          severity: 2,
          title: `${inst.advisor_name}'s onboarding has stalled`,
          body: `No tasks completed in the last 7 days. ${pct}% complete · ${daysLeft} days to go-live.`,
          actionLabel: "View Onboarding",
          entityId: inst.id,
          entityType: "mission",
        });
      }
    }
  });

  // ── Stale households ─────────────────────────────────────────
  households.filter(h=>h.status==="active").forEach(hh => {
    // Sort activities descending so acts[0] is always the most recent — never rely on insertion order
    const acts = [...(hh.activities||[])].sort((a,b)=>new Date(b.occurred_at)-new Date(a.occurred_at));
    const lastAct = acts[0];
    const daysSince = lastAct ? Math.round((now - new Date(lastAct.occurred_at)) / 86400000) : null;
    const threshold = 45;
    if (daysSince === null || daysSince > threshold) {
      sigs.push({
        id: `stale-hh-${hh.id}`,
        type: "HOUSEHOLD_STALE",
        severity: daysSince === null ? 3 : (daysSince > 90 ? 2 : 3),
        title: `${hh.name} — schedule a touchpoint`,
        body: daysSince === null
          ? "No relationship activity logged for this household. Consider reaching out."
          : `${daysSince} days since last logged contact. A check-in call or note keeps the relationship healthy.`,
        actionLabel: "View Household",
        entityId: hh.id,
        entityType: "household",
      });
    }
  });

  // ── Pipeline cold cards ──────────────────────────────────────
  pipelineCards.forEach(card => {
    const stage = pipelineStages.find(s=>s.id===card.stage_id);
    if (!stage || stage.is_won || stage.is_lost) return;
    const daysInStage = card.stage_entered_at
      ? Math.round((now - new Date(card.stage_entered_at)) / 86400000)
      : null;
    const slaThreshold = stage.sla_days || 14;
    if (daysInStage !== null && daysInStage > slaThreshold) {
      sigs.push({
        id: `cold-${card.id}`,
        type: "PIPELINE_COLD",
        severity: 3,
        title: `${card.title} has gone cold`,
        body: `${daysInStage} days in "${stage.name}" — past the ${slaThreshold}-day threshold. Follow up or advance the card.`,
        actionLabel: "View Pipeline",
        entityId: card.pipeline_id,
        entityType: "pipeline",
      });
    }
  });

  // ── Stale open requests ──────────────────────────────────────
  requests.filter(r=>r.status!=="resolved"&&r.status!=="cancelled").forEach(req => {
    const age = Math.round((now - new Date(req.created_at)) / 86400000);
    if (req.priority==="urgent" && age > 1) {
      sigs.push({
        id: `urgent-req-${req.id}`,
        type: "REQUEST_URGENT",
        severity: 1,
        title: `Urgent request aging: "${req.title}"`,
        body: `${age} days old${req.assigned_to ? "" : " · Unassigned"}. Urgent requests should resolve within 24 hours.`,
        actionLabel: "Open Request",
        entityId: req.id,
        entityType: "request",
      });
    } else if (!req.assigned_to && age > 2) {
      sigs.push({
        id: `unassigned-req-${req.id}`,
        type: "REQUEST_STALE",
        severity: 2,
        title: `Unassigned request: "${req.title}"`,
        body: `${age} days old with no owner. Assign it to keep it moving.`,
        actionLabel: "Open Request",
        entityId: req.id,
        entityType: "request",
      });
    } else if (age > 7 && req.status==="open") {
      sigs.push({
        id: `stale-req-${req.id}`,
        type: "REQUEST_STALE",
        severity: 3,
        title: `Request stalled: "${req.title}"`,
        body: `${age} days open with no resolution. Check status and update or resolve.`,
        actionLabel: "Open Request",
        entityId: req.id,
        entityType: "request",
      });
    }
  });

  // ── Knowledge base nudge — fires once if no docs uploaded ────
  if (!firmSettings?.knowledge_docs?.length && instances.length > 0) {
    sigs.push({
      id: "knowledge-base-empty",
      type: "REQUEST_STALE",
      severity: 4, // lowest priority — informational
      title: "Train HUD Intelligence on your firm",
      body: "Upload your routing framework, custodian guidelines, or any firm documents so HUD Intelligence can answer firm-specific questions accurately.",
      actionLabel: "Go to Firm Admin",
      entityId: null,
      entityType: "settings",
    });
  }

  // Sort by severity (1=critical first), cap at 8 signals total
  return sigs.sort((a,b)=>a.severity-b.severity).slice(0,8);
}

// ── Signal Card component ───────────────────────────────────────
const SignalCard = ({ signal, onAction, compact=false }) => {
  const meta = SIGNAL_TYPES[signal.type] || SIGNAL_TYPES.REQUEST_STALE;
  return (
    <div style={{
      background: T.bg2,
      border: `1px solid ${meta.color}33`,
      borderLeft: `3px solid ${meta.color}`,
      padding: compact ? "8px 12px" : "10px 14px",
      display: "flex", alignItems: "flex-start", gap: 10,
      transition: "background 0.1s",
    }}
      onMouseEnter={e=>e.currentTarget.style.background=T.bg3}
      onMouseLeave={e=>e.currentTarget.style.background=T.bg2}>
      <span style={{ fontSize: 14, color: meta.color, flexShrink: 0, marginTop: 1 }}>{meta.icon}</span>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ fontSize: SZ.small, fontWeight: 700, color: T.text0, ...INTER, marginBottom: 2 }}>{signal.title}</div>
        <div style={{ fontSize: SZ.label, color: T.text2, ...INTER, lineHeight: 1.5 }}>{signal.body}</div>
      </div>
      {onAction && (
        <button onClick={()=>onAction(signal)}
          style={{ flexShrink: 0, padding: "3px 10px", background: "none", border: `1px solid ${meta.color}55`, color: meta.color, cursor: "pointer", fontSize: SZ.micro, ...MONO, fontWeight: 700, letterSpacing: "0.08em", whiteSpace: "nowrap", transition: "all 0.1s" }}
          onMouseEnter={e=>{e.currentTarget.style.background=`${meta.color}18`;}}
          onMouseLeave={e=>{e.currentTarget.style.background="none";}}>
          {signal.actionLabel} →
        </button>
      )}
    </div>
  );
};

// ── OPS MORNING BRIEFING ──────────────────────────────────────
// AI-generated 2-3 sentence briefing for ops/admin users.
// Cached daily per user. Quality-gated — won't show generic output.
const AWACSBriefingBlock = ({ currentUser, instances, requests, users, signals, households, firmName, mode="ops" }) => {
  const [briefing, setBriefing] = useState(null);
  const [loading, setLoading] = useState(false);
  const [generatedAt, setGeneratedAt] = useState(null);

  const todayKey = new Date().toISOString().split("T")[0];
  const cacheKey = `ahud_${mode}_briefing_${currentUser?.id}_${todayKey}`;

  const buildOpsContext = () => {
    const active = instances.filter(i=>i.status==="active");
    const allTasks = active.flatMap(i=>i.phases.flatMap(p=>p.tasks));
    const overdueTasks = allTasks.filter(t=>t.due_date&&t.status!=="completed"&&new Date(t.due_date)<new Date());
    const openReqs = requests.filter(r=>r.status!=="resolved"&&r.status!=="cancelled");
    const unassignedReqs = openReqs.filter(r=>!r.assigned_to);
    const urgentReqs = openReqs.filter(r=>r.priority==="urgent");
    const staleReqs = openReqs.filter(r=>Math.floor((Date.now()-new Date(r.created_at))/86400000)>=3);

    // Stalled missions — no tasks completed in 7 days
    const stalledMissions = active.filter(inst=>{
      const tasks = inst.phases.flatMap(p=>p.tasks);
      const recentlyCompleted = tasks.filter(t=>t.completed_date&&new Date(t.completed_date)>new Date(Date.now()-7*86400000));
      return recentlyCompleted.length===0 && tasks.some(t=>t.status!=="completed");
    });

    // Stale households
    const staleHH = (households||[]).filter(h=>{
      const acts=[...(h.activities||[])].sort((a,b)=>new Date(b.occurred_at)-new Date(a.occurred_at));
      const ds=acts[0]?Math.round((Date.now()-new Date(acts[0].occurred_at))/86400000):999;
      return ds>45&&h.status==="active";
    });

    return `FIRM: ${firmName||"this firm"}
DATE: ${new Date().toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric"})}
OPS LEAD: ${currentUser?.name||"Ops"}

UNASSIGNED REQUESTS (${unassignedReqs.length}):
${unassignedReqs.slice(0,3).map(r=>{
  const age=Math.floor((Date.now()-new Date(r.created_at))/86400000);
  return `- "${r.title}" | ${r.priority?.toUpperCase()||"NORMAL"} | ${age}d old`;
}).join("\n")||"- None"}

URGENT REQUESTS (${urgentReqs.length}):
${urgentReqs.slice(0,3).map(r=>`- "${r.title}" | submitted by ${users.find(u=>u.id===r.submitted_by)?.name||"unknown"}`).join("\n")||"- None"}

STALE REQUESTS 3+ DAYS OLD (${staleReqs.length}):
${staleReqs.slice(0,3).map(r=>{
  const age=Math.floor((Date.now()-new Date(r.created_at))/86400000);
  const assignee=users.find(u=>u.id===r.assigned_to);
  return `- "${r.title}" | ${age}d old | ${assignee?`Assigned: ${assignee.name.split(" ")[0]}`:"UNASSIGNED"}`;
}).join("\n")||"- None"}

ACTIVE ONBOARDINGS (${active.length}):
${active.slice(0,5).map(i=>{
  const tasks=i.phases.flatMap(p=>p.tasks);
  const pct=Math.round(tasks.filter(t=>t.status==="completed").length/Math.max(tasks.length,1)*100);
  const overdue=tasks.filter(t=>t.due_date&&t.status!=="completed"&&new Date(t.due_date)<new Date()).length;
  const daysLeft=i.target_date?Math.round((new Date(i.target_date+"T12:00:00")-new Date())/86400000):null;
  return `- ${i.advisor_name} | ${pct}% complete${daysLeft!==null?` | ${daysLeft}d to go-live`:""}${overdue>0?` | ⚑ ${overdue} OVERDUE`:""}`;
}).join("\n")||"- None"}

STALLED ONBOARDINGS (no progress in 7 days): ${stalledMissions.map(i=>i.advisor_name).join(", ")||"None"}
STALE HOUSEHOLDS (45+ days no contact): ${staleHH.length}`;
  };

  const buildAdvisorContext = () => {
    const myCards = instances; // pipelineCards passed as instances for advisor mode
    const myHH = households||[];
    const openReqs = requests.filter(r=>r.submitted_by===currentUser?.id&&r.status!=="resolved");
    const staleHH = myHH.filter(h=>{
      const acts=[...(h.activities||[])].sort((a,b)=>new Date(b.occurred_at)-new Date(a.occurred_at));
      const ds=acts[0]?Math.round((Date.now()-new Date(acts[0].occurred_at))/86400000):999;
      return ds>45;
    });
    const pipelineValue = myCards.reduce((s,c)=>s+(parseFloat(c.estimated_value)||0),0);
    const stalledCards = myCards.filter(c=>{
      const daysIn=c.stage_entered_at?Math.round((Date.now()-new Date(c.stage_entered_at))/86400000):0;
      return daysIn>14;
    });

    return `ADVISOR: ${currentUser?.name||"Advisor"}
DATE: ${new Date().toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric"})}

MY CLIENTS (${myHH.length} households):
${staleHH.slice(0,3).map(h=>{
  const acts=[...(h.activities||[])].sort((a,b)=>new Date(b.occurred_at)-new Date(a.occurred_at));
  const ds=acts[0]?Math.round((Date.now()-new Date(acts[0].occurred_at))/86400000):null;
  return `- ${h.name} | ${ds?ds+"d no contact":"never contacted"}${h.aum_approximate?` | $${h.aum_approximate}M`:""}`;
}).join("\n")||"- All clients recently contacted"}

MY PIPELINE (${myCards.length} prospects | $${pipelineValue.toFixed(1)}M):
${stalledCards.slice(0,3).map(c=>{
  const daysIn=c.stage_entered_at?Math.round((Date.now()-new Date(c.stage_entered_at))/86400000):0;
  return `- ${c.title} | ${c.stage_name||"unknown stage"} | ${daysIn}d in stage${c.estimated_value?` | $${parseFloat(c.estimated_value).toFixed(1)}M`:""}`;
}).join("\n")||"- No stalled prospects"}

OPEN REQUESTS TO OPS (${openReqs.length}):
${openReqs.slice(0,3).map(r=>{
  const age=Math.floor((Date.now()-new Date(r.created_at))/86400000);
  return `- "${r.title}" | ${r.status?.toUpperCase()} | ${age}d old`;
}).join("\n")||"- None"}`;
  };

  const isSpecific = (text, ctx) => {
    // Quality gate: briefing must reference at least one specific name or number from context
    if (!text) return false;
    if (text.length < 60) return false;
    // Check for generic phrases that indicate a bad output
    const genericPhrases = ["have a great day","hope this helps","let me know","as always","looking forward"];
    if (genericPhrases.some(p=>text.toLowerCase().includes(p))) return false;
    return true;
  };

  const fetchBriefing = async (force=false) => {
    if (!force) {
      try {
        const cached = localStorage.getItem(cacheKey);
        if (cached) {
          const { text, ts } = JSON.parse(cached);
          const ageHours = (Date.now()-ts)/3600000;
          if (ageHours < 4 && text) {
            setBriefing(text);
            setGeneratedAt(new Date(ts));
            return;
          }
        }
      } catch(e) {}
    }
    setLoading(true);
    try {
      const ctx = mode==="advisor" ? buildAdvisorContext() : buildOpsContext();
      const systemPrompt = mode==="advisor"
        ? `You are AdvisorHUD's intelligence system for ${firmName||"this firm"}. Write a 2-3 sentence morning briefing for this advisor about their client relationships and prospect pipeline. Be specific — use real names and numbers from the data. Lead with the most important relationship or pipeline item needing attention. Do not start with "Good morning" or any greeting. No bullet points. Flowing prose only. If everything is healthy, say so briefly.`
        : `You are AdvisorHUD's operations intelligence for ${firmName||"this firm"}. Write a 2-3 sentence morning briefing for this ops lead. Be specific — use real names, request titles, and ages from the data. Lead with the single most urgent item (unassigned requests, overdue tasks, stalled onboardings). Never write generic statements — always name the specific situation. Do not start with "Good morning." No bullet points. Flowing prose only. If nothing is urgent, say so in one sentence.`;

      const res = await fetch("/api/briefing", {
        method:"POST",
        headers:{"Content-Type":"application/json","Authorization":`Bearer ${sb.getToken()}`},
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:300,
          system: systemPrompt,
          messages:[{role:"user",content:ctx}],
        }),
      });
      const data = await res.json();
      const text = data.content?.[0]?.text||null;
      if (text && isSpecific(text, ctx)) {
        setBriefing(text);
        const now = Date.now();
        setGeneratedAt(new Date(now));
        try { localStorage.setItem(cacheKey, JSON.stringify({text,ts:now})); } catch(e){}
      }
      // If quality gate fails, silently don't render — signals panel still shows below
    } catch(e) { console.error("Briefing error:",e); }
    finally { setLoading(false); }
  };

  useEffect(()=>{ if(currentUser?.id) fetchBriefing(); },[currentUser?.id]);

  if (!briefing && !loading) return null; // Don't render empty state — signals below handle it

  return (
    <div style={{ background:`linear-gradient(135deg, ${T.bg1} 0%, ${T.bg2} 100%)`, border:`1px solid ${T.blue}22`, borderLeft:`3px solid ${T.blue}`, padding:"16px 20px", marginBottom:20, position:"relative", overflow:"hidden" }}>
      <div style={{ position:"absolute", top:-30, right:-30, width:160, height:160, background:`radial-gradient(circle, ${T.blue}06 0%, transparent 70%)`, pointerEvents:"none" }}/>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{ width:5, height:5, background:T.blue, transform:"rotate(45deg)", flexShrink:0 }}/>
          <span style={{ fontSize:SZ.micro, color:T.blue, ...MONO, fontWeight:700, letterSpacing:"0.16em" }}>
            {mode==="advisor" ? "HUD INTELLIGENCE · ADVISOR BRIEFING" : "HUD INTELLIGENCE · MORNING BRIEFING"}
          </span>
          {generatedAt && <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>
            {generatedAt.toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"})}
          </span>}
        </div>
        <button onClick={()=>fetchBriefing(true)} disabled={loading}
          style={{ padding:"2px 9px", background:"transparent", border:`1px solid ${T.border1}`, color:T.text3, cursor:loading?"wait":"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.08em", transition:"all 0.1s" }}
          onMouseEnter={e=>{if(!loading){e.currentTarget.style.color=T.blue;e.currentTarget.style.borderColor=T.blue;}}}
          onMouseLeave={e=>{e.currentTarget.style.color=T.text3;e.currentTarget.style.borderColor=T.border1;}}>
          {loading?"…":"↺"}
        </button>
      </div>
      {loading && (
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          {[0,1,2].map(i=><div key={i} style={{ width:4, height:4, background:T.blue, borderRadius:"50%", animation:`pulse 1.2s ease-in-out ${i*0.2}s infinite` }}/>)}
          <span style={{ fontSize:SZ.label, color:T.text3, ...MONO, letterSpacing:"0.1em" }}>GENERATING BRIEFING…</span>
        </div>
      )}
      {!loading && briefing && (
        <div style={{ fontSize:SZ.body, color:T.text1, lineHeight:1.75, ...INTER }}>{briefing}</div>
      )}
    </div>
  );
};

const AWACS = ({ instances, requests, users, households, signals, setView, setSelectedMissionId, onDeploy, setQueueFilterUser, currentUser, navigateToRequest, firmName="" }) => {
  const isMobile = useMobile();
  const [supportTickets, setSupportTickets] = useState([]);
  useEffect(()=>{ api.getTickets().then(d=>setSupportTickets(d||[])).catch(()=>{}); },[]);
  // setSelectedMissionId is now a combined navigate fn (sets id + switches view)
  const goToMission = (id) => setSelectedMissionId(id);
  const tasks = instances.flatMap(i=>i.phases.flatMap(p=>p.tasks.map(t=>({...t,_instanceId:i.id}))));
  const overdue = tasks.filter(t=>(t.status==="overdue"||isOverdue(t))&&["ready","in_progress","waiting"].includes(t.status)||t.status==="overdue");
  const blocked = tasks.filter(t=>t.status==="blocked");
  const completed = tasks.filter(t=>t.status==="completed");
  const openRequests = requests.filter(r=>r.status==="open"||r.status==="in_progress");
  const activeMissions = instances.filter(i=>i.status==="active");
  const opsUsers = users.filter(u=>(u.role==="ops"||u.role==="admin")&&!u.is_super_admin);
  const workload = opsUsers.map(u=>{
    const myTasks = tasks.filter(t=>t.assigned_to===u.id);
    const doneTasks = myTasks.filter(t=>t.status==="completed");
    const pct = myTasks.length ? Math.round((doneTasks.length/myTasks.length)*100) : 0;
    return { user:u, total:myTasks.length, done:doneTasks.length, pct };
  }).filter(w=>w.total>0).sort((a,b)=>a.pct-b.pct); // only show people with actual work

  // Personal tasks for the logged-in ops user
  const myPersonalTasks = currentUser ? tasks.filter(t=>t.assigned_to===currentUser.id&&t.status!=="completed") : [];

  // Signal navigation handler
  const handleSignalAction = (sig) => {
    if (sig.entityType==="mission") goToMission(sig.entityId);
    else if (sig.entityType==="request" && navigateToRequest) navigateToRequest(sig.entityId);
    else if (sig.entityType==="pipeline") setView("pipelines");
    else if (sig.entityType==="household") setView("crm");
    else if (sig.entityType==="settings") setView("users"); // → Firm Admin → Knowledge Base tab
  };

  const statCards = [
    { label:"ACTIVE ONBOARDINGS", value:activeMissions.length, color:T.blue,   sub:"IN PROGRESS",    icon:"◈", action:()=>{ if(activeMissions[0]) goToMission(activeMissions[0].id); else setView("missions"); } },
    { label:"OPEN REQUESTS",   value:openRequests.length,   color:T.purple,  sub:"AWAITING ACTION", icon:"◉", action:()=>setView("requests") },
    { label:"ALERTS",    value:overdue.length+blocked.length, color:T.red, sub:`${overdue.length} OVERDUE · ${blocked.length} BLOCKED`, icon:"⚑", action:()=>{ const first=[...overdue,...blocked][0]; if(first) goToMission(first._instanceId||first.workflow_instance_id); else setView("missions"); } },
    { label:"TASKS COMPLETE",  value:completed.length,      color:T.green,   sub:`OF ${tasks.length} TOTAL`, icon:"✓", action:()=>setView("missions") },
    { label:"OPEN TICKETS",   value:supportTickets.filter(t=>t.status!=="released"&&t.status!=="no_action_required").length, color:T.amber, sub:`${supportTickets.filter(t=>t.severity==="critical"&&t.status!=="released").length} CRITICAL · ${supportTickets.filter(t=>t.ticket_type==="bug"&&t.status!=="released").length} BUGS`, icon:"⚑", action:()=>setView("admin_support") },
  ];

  return (
    <div style={{ padding: isMobile ? "16px 14px" : "32px 36px", maxWidth:1400 }}>
      {/* Header — personalized greeting */}
      <div style={{ marginBottom:20 }}>
        <div style={{ fontSize:SZ.small, color:T.text3, letterSpacing:"0.12em", ...MONO }}>
          {new Date().toLocaleDateString("en-US",{weekday:"long",year:"numeric",month:"short",day:"numeric"}).toUpperCase()} · FIRM-WIDE OPERATIONAL OVERVIEW
        </div>
      </div>

      {/* [1] AI OPS BRIEFING — leads the page */}
      <AWACSBriefingBlock
        currentUser={currentUser}
        instances={instances}
        requests={requests}
        users={users}
        signals={signals}
        households={households}
        firmName={firmName}
        mode="ops"
      />

      {/* [2] Signals panel — proactive observations */}
      {signals && signals.length > 0 && (
        <div style={{ marginBottom:28 }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
            <SectionLabel>HUD INTELLIGENCE · {signals.length} SIGNAL{signals.length!==1?"S":""} REQUIRING ATTENTION</SectionLabel>
          </div>
          <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
            {signals.map(sig=>(
              <SignalCard key={sig.id} signal={sig} onAction={handleSignalAction}/>
            ))}
          </div>
        </div>
      )}
      {signals && signals.length === 0 && instances.length > 0 && (
        <div style={{ marginBottom:28, background:T.bg1, border:`1px solid ${T.border1}`, borderLeft:`3px solid ${T.green}`, padding:"12px 16px", display:"flex", alignItems:"center", gap:10 }}>
          <span style={{ color:T.green }}>◈</span>
          <span style={{ fontSize:SZ.small, color:T.green, ...MONO, fontWeight:700, letterSpacing:"0.1em" }}>ALL CLEAR — No signals requiring attention</span>
        </div>
      )}

      {/* [3] Personal task queue — what's specifically yours */}
      {myPersonalTasks.length > 0 && (
        <div style={{ marginBottom:28 }}>
          <SectionLabel>YOUR TASKS · {myPersonalTasks.length} OPEN</SectionLabel>
          <div style={{ background:T.bg1, border:`1px solid ${T.border1}`, overflow:"hidden" }}>
            {myPersonalTasks.slice(0,5).map((t,i)=>{
              const inst = instances.find(i=>i.phases.some(p=>p.tasks.some(tk=>tk.id===t.id)));
              const over = isOverdue(t);
              return (
                <div key={t.id} onClick={()=>inst&&goToMission(inst.id)}
                  style={{ padding:"9px 16px", borderBottom:i<Math.min(myPersonalTasks.length-1,4)?`1px solid ${T.border0}`:"none", display:"flex", alignItems:"center", gap:10, cursor:inst?"pointer":"default", transition:"background 0.1s" }}
                  onMouseEnter={e=>e.currentTarget.style.background=T.bg2}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <div style={{ width:8, height:8, borderRadius:"50%", background:over?T.red:T.blue, boxShadow:`0 0 5px ${over?T.red:T.blue}`, flexShrink:0 }}/>
                  <div style={{ flex:1, minWidth:0 }}>
                    <span style={{ fontSize:SZ.small, color:over?T.amber:T.text1, ...INTER }}>{t.name}</span>
                    {inst && <span style={{ fontSize:SZ.label, color:T.text3, ...MONO, marginLeft:8 }}>{inst.advisor_name}</span>}
                  </div>
                  {over && <span style={{ fontSize:SZ.micro, color:T.red, ...MONO, fontWeight:700 }}>OVERDUE</span>}
                  {t.due_date && !over && <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{fmtDate(t.due_date)}</span>}
                </div>
              );
            })}
            {myPersonalTasks.length > 5 && (
              <div onClick={()=>setView("mytasks")} style={{ padding:"8px 16px", fontSize:SZ.label, color:T.blue, ...MONO, cursor:"pointer", borderTop:`1px solid ${T.border0}`, textAlign:"center" }}>
                +{myPersonalTasks.length-5} more → VIEW MY TASKS
              </div>
            )}
          </div>
        </div>
      )}

      {/* [4] Stat cards — orientation context, not the lead */}
      <div style={{ display:"grid", gridTemplateColumns: isMobile ? "repeat(2,1fr)" : "repeat(5,1fr)", gap:10, marginBottom:28 }}>
        {statCards.map(s=>(
          <div key={s.label} onClick={s.action||undefined}
            style={{ background:T.bg2, border:`1px solid ${T.border1}`, borderTop:`2px solid ${s.color}`,
              padding:"12px 14px 10px", position:"relative", overflow:"hidden",
              cursor:s.action?"pointer":"default", transition:"all 0.15s" }}
            onMouseEnter={e=>{if(s.action){e.currentTarget.style.borderColor=s.color;e.currentTarget.style.background=T.bg3;}}}
            onMouseLeave={e=>{if(s.action){e.currentTarget.style.borderColor=T.border1;e.currentTarget.style.background=T.bg2;}}}>
            <div style={{ position:"absolute", top:8, right:10, fontSize:24, color:s.color, opacity:0.08, lineHeight:1 }}>{s.icon}</div>
            <div style={{ fontSize:SZ.head, fontWeight:700, color:s.color, ...MONO, lineHeight:1, marginBottom:5 }}>{s.value}</div>
            <div style={{ fontSize:SZ.label, fontWeight:700, color:T.text1, letterSpacing:"0.1em", ...RAJDHANI, marginBottom:3 }}>{s.label}</div>
            <div style={{ fontSize:SZ.micro, color:T.text2, letterSpacing:"0.06em", ...MONO }}>{s.sub}{s.action&&<span style={{marginLeft:4,opacity:0.4}}>→</span>}</div>
          </div>
        ))}
      </div>

      {/* Main grid */}
      <div style={{ display:"grid", gridTemplateColumns: isMobile ? "1fr" : "1fr 380px", gap:28, alignItems:"start" }}>

        {/* LEFT: Missions + Request Queue */}
        <div style={{ display:"flex", flexDirection:"column", gap:32 }}>

          {/* Active Missions */}
          <div>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
              <SectionLabel>ACTIVE ONBOARDINGS</SectionLabel>
              {onDeploy && (
                <button onClick={onDeploy}
                  style={{ padding:"5px 16px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, cursor:"pointer", fontSize:SZ.small, letterSpacing:"0.12em", ...MONO, clipPath:"polygon(0 0, calc(100% - 4px) 0, 100% 4px, 100% 100%, 0 100%)" }}
                  onMouseEnter={e=>{e.currentTarget.style.color=T.blue;e.currentTarget.style.borderColor=T.blue;}}
                  onMouseLeave={e=>{e.currentTarget.style.color=T.text2;e.currentTarget.style.borderColor=T.border2;}}>
                  + NEW
                </button>
              )}
            </div>

            {instances.length===0 && (
              <div style={{ background:T.bg1, border:`1px solid ${T.border1}`, padding:"56px 32px", textAlign:"center" }}>
                <div style={{ fontSize:48, marginBottom:14, opacity:0.1 }}>◈</div>
                <div style={{ fontSize:SZ.body, color:T.text2, letterSpacing:"0.12em", ...MONO, marginBottom:6 }}>NO ACTIVE ONBOARDINGS</div>
                <div style={{ fontSize:SZ.small, color:T.text3, ...MONO }}>Click + NEW above to deploy your first onboarding mission</div>
              </div>
            )}

            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {instances.map(inst=>{
                const instTasks=inst.phases.flatMap(p=>p.tasks);
                const pct=calcPct(instTasks);
                const nOvr=instTasks.filter(t=>t.status==="overdue"||isOverdue(t)).length;
                const nBlk=instTasks.filter(t=>t.status==="blocked").length;
                const nDone=instTasks.filter(t=>t.status==="completed").length;
                const activePhase=inst.phases.find(p=>p.status==="in_progress")||inst.phases[0];
                const hasAlert=nOvr>0||nBlk>0;
                const mt=getMissionType(inst.mission_type);
                const accentColor=nBlk>0?T.red:nOvr>0?T.amber:mt.color;
                return (
                  <div key={inst.id} onClick={()=>{goToMission(inst.id);}}
                    style={{ background:T.bg2, border:`1px solid ${hasAlert?T.border2:T.border1}`,
                      borderLeft:`3px solid ${accentColor}`, padding:"18px 22px",
                      cursor:"pointer", transition:"all 0.12s", position:"relative" }}
                    onMouseEnter={e=>{e.currentTarget.style.background=T.bg3;e.currentTarget.style.borderColor=T.blue;}}
                    onMouseLeave={e=>{e.currentTarget.style.background=T.bg2;e.currentTarget.style.borderColor=hasAlert?T.border2:T.border1;}}>

                    {/* Top row: name + badges + VIEW */}
                    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                      <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                        <div style={{ fontSize:SZ.sub, fontWeight:700, color:T.text0, ...INTER }}>{inst.advisor_name}</div>
                        <MissionTypeBadge typeId={inst.mission_type} small/>
                        {nOvr>0&&<Badge status="overdue" small/>}
                        {nBlk>0&&<Badge status="blocked" small/>}
                      </div>
                      <span style={{ fontSize:SZ.micro, color:T.text2, ...MONO, opacity:0.8 }}>VIEW →</span>
                    </div>

                    {/* Phase + target */}
                    <div style={{ fontSize:SZ.label, color:T.text1, letterSpacing:"0.1em", ...MONO, marginBottom:12 }}>
                      {activePhase?.name?.toUpperCase()} · TARGET {fmtDate(inst.target_date).toUpperCase()}
                    </div>

                    {/* Progress bar */}
                    <ProgressBar pct={pct} showLabel segments animate/>

                    {/* Stats — inline, no divider */}
                    <div style={{ display:"flex", gap:6, marginTop:12, alignItems:"center" }}>
                      <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{instTasks.length} tasks</span>
                      <span style={{ fontSize:SZ.micro, color:T.border2, ...MONO }}>·</span>
                      <span style={{ fontSize:SZ.micro, color:nDone>0?T.green:T.text3, ...MONO, fontWeight:nDone>0?700:400 }}>{nDone} done</span>
                      {nOvr>0&&<><span style={{ fontSize:SZ.micro, color:T.border2, ...MONO }}>·</span><span style={{ fontSize:SZ.micro, color:T.amber, ...MONO, fontWeight:700 }}>⚑ {nOvr} overdue</span></>}
                      {nBlk>0&&<><span style={{ fontSize:SZ.micro, color:T.border2, ...MONO }}>·</span><span style={{ fontSize:SZ.micro, color:T.red, ...MONO, fontWeight:700 }}>◼ {nBlk} blocked</span></>}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>


        </div>

        {/* RIGHT: Threat Board + Ops Workload */}
        <div style={{ display:"flex", flexDirection:"column", gap:20 }}>

          {/* Threat boards */}
          {[
            { key:"overdue", label:"OVERDUE", items:overdue.slice(0,6), color:T.amber, renderMeta:t=>fmtDate(t.due_date) },
            { key:"blocked", label:"BLOCKED", items:blocked.slice(0,6), color:T.red,   renderMeta:t=><Avatar userId={t.assigned_to} users={users} size={18}/> },
          ].map(({key,label,items,color,renderMeta})=>(
            <div key={key} style={{ background:T.bg2, border:`1px solid ${T.border2}`, borderTop:`2px solid ${color}`, overflow:"hidden" }}>
              <div style={{ padding:"12px 16px", borderBottom:`1px solid ${T.border0}`, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <span style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", ...MONO }}>ALERTS</span>
                  <span style={{ fontSize:SZ.micro, color:color, letterSpacing:"0.14em", ...MONO, marginLeft:6, fontWeight:700 }}>— {label}</span>
                </div>
                <span style={{ fontSize:SZ.micro, color:items.length>0?color:T.text3, background:items.length>0?`${color}18`:T.bg3, padding:"2px 8px", ...MONO, fontWeight:700 }}>{items.length}</span>
              </div>
              {items.length===0 && (
                <div style={{ padding:"18px", textAlign:"center" }}>
                  <div style={{ fontSize:SZ.small, color:T.text3, letterSpacing:"0.1em", ...MONO }}>◈ ALL CLEAR</div>
                </div>
              )}
              {items.map(t=>(
                <div key={t.id} onClick={()=>{goToMission(t._instanceId||t.workflow_instance_id);}}
                  style={{ padding:"12px 16px", borderBottom:`1px solid ${T.border0}22`, display:"flex", justifyContent:"space-between", alignItems:"center", cursor:"pointer", gap:10 }}
                  onMouseEnter={e=>e.currentTarget.style.background=T.bg2}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <div style={{ minWidth:0, flex:1 }}>
                    <div style={{ fontSize:SZ.small, color:T.text0, fontWeight:500, ...INTER, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.name}</div>
                    <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginTop:2 }}>{instances.find(i=>i.id===(t._instanceId||t.workflow_instance_id))?.advisor_name}</div>
                  </div>
                  <div style={{ fontSize:SZ.micro, color, ...MONO, flexShrink:0 }}>{renderMeta(t)}</div>
                </div>
              ))}
            </div>
          ))}

          {/* Team Queue / OPS Workload */}
          <div style={{ background:T.bg2, border:`1px solid ${T.border2}`, overflow:"hidden" }}>
            <div style={{ padding:"12px 16px", borderBottom:`1px solid ${T.border0}`, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <span style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", ...MONO, fontWeight:700 }}>TEAM QUEUE</span>
              <button onClick={()=>setView("queue")} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.08em", padding:0, transition:"color 0.1s" }}
                onMouseEnter={e=>e.currentTarget.style.color=T.blue}
                onMouseLeave={e=>e.currentTarget.style.color=T.text3}>VIEW ALL →</button>
            </div>
            {workload.length===0 && (
              <div style={{ padding:"18px", textAlign:"center" }}>
                <div style={{ fontSize:SZ.small, color:T.text3, ...MONO }}>NO OPS TEAM CONFIGURED</div>
              </div>
            )}
            {workload.map(({user:u,total,done,pct})=>(
              <div key={u.id}
                onClick={()=>{if(setQueueFilterUser)setQueueFilterUser(u.id);setView("queue");}}
                style={{ padding:"10px 16px", borderBottom:`1px solid ${T.border0}22`, cursor:"pointer", transition:"background 0.1s" }}
                onMouseEnter={e=>e.currentTarget.style.background=T.bg2}
                onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:7 }}>
                    <Avatar userId={u.id} users={users} size={20}/>
                    <span style={{ fontSize:SZ.small, color:T.text1, ...INTER }}>{u.name.split(" ")[0]}</span>
                    <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{u.name.split(" ")[1]||""}</span>
                  </div>
                  <span style={{ fontSize:SZ.micro, color:pct===100?T.green:total===0?T.text3:T.text2, ...MONO, fontWeight:total>0?700:400 }}>
                    {total===0?"no tasks":`(${done}/${total}) · ${pct}%`}
                  </span>
                </div>
                <div style={{ height:3, background:T.bg4, overflow:"hidden" }}>
                  <div style={{ width:`${pct}%`, height:"100%", background:pct===100?T.green:pct>60?T.blue:pct>30?T.amber:T.red, transition:"width 0.5s ease" }}/>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};



// ── TASK ROW ───────────────────────────────────────────────────
const STATUSES = ["not_started","ready","in_progress","waiting","blocked","completed","overdue"];

const TaskRow = ({ task, users, onStatusChange, onAssignTask, onUpdateDueDate, play, currentUser, inst, onFormSent }) => {
  const [open,setOpen]=useState(false);
  const [sendFormOpen, setSendFormOpen] = useState(false);
  const [linkedFormName, setLinkedFormName] = useState(null);
  const [formSendStatus, setFormSendStatus] = useState(null); // null | "sent" | "opened" | "draft_saved" | "submitted"
  const { flashing, flash } = useFlash();
  const s=getSt(task.status);
  const over=isOverdue(task);

  // Poll form send status when a form has been sent from this task
  useEffect(() => {
    if (!task.form_send_id) return;
    api.getFormSend(task.form_send_id).then(send => {
      if (send?.status) setFormSendStatus(send.status);
    }).catch(() => {});
  }, [task.form_send_id]);

  const handleStatusChange = async (newStatus) => {
    if (newStatus==="completed") { flash(); if(play) play("task"); }
    onStatusChange(task.id, newStatus);
  };

  return (
    <>
      <div onClick={()=>setOpen(!open)} style={{ display:"grid", gridTemplateColumns:"6px 1fr 100px 80px 120px 20px", alignItems:"center", gap:10, padding:"10px 16px", borderBottom:`1px solid ${T.border0}`, cursor:"pointer",
        background:flashing?`${T.green}18`:open?T.bg3:"transparent",
        transition:"background 0.3s", borderLeft:flashing?`2px solid ${T.green}`:undefined }}
        onMouseEnter={e=>{if(!open&&!flashing)e.currentTarget.style.background=T.bg2;}}
        onMouseLeave={e=>{if(!open&&!flashing)e.currentTarget.style.background="transparent";}}>
        <div style={{ width:3, height:"100%", minHeight:20, background:flashing?T.green:s.color, borderRadius:1, transition:"background 0.3s" }}/>
        <div style={{ display:"flex", alignItems:"center", gap:7, minWidth:0 }}>
          {task.requires_upload&&<Tooltip text="REQUIRES FILE UPLOAD"><span style={{ fontSize:SZ.body, color:T.text3, flexShrink:0 }}>↑</span></Tooltip>}
          {task.advisor_visible&&<Tooltip text="ADVISOR-VISIBLE TASK"><span style={{ fontSize:SZ.body, color:T.blueMid, flexShrink:0 }}>◉</span></Tooltip>}
          <span style={{ fontSize:SZ.body, color:flashing?T.green:over?T.amber:T.text0, fontWeight:task.status==="in_progress"?600:400, ...INTER, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", transition:"color 0.3s" }}>{task.name}</span>
        </div>
        <Badge status={task.status} small/>
        <div style={{ fontSize:SZ.small, color:over?T.amber:T.text1, ...MONO, fontWeight:over?700:400 }}>{fmtDate(task.due_date)}</div>
        <div style={{ display:"flex", alignItems:"center", gap:5, minWidth:0 }}>
          {task.assigned_to
            ? <><Avatar userId={task.assigned_to} users={users} size={18}/><span style={{ fontSize:SZ.micro, color:T.text1, ...MONO, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{users.find(u=>u.id===task.assigned_to)?.name?.split(" ")[0]||"—"}</span></>
            : <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO, whiteSpace:"nowrap" }}>Unassigned</span>
          }
        </div>
        <Tooltip text={open?"COLLAPSE":"EXPAND DETAILS"}><div style={{ fontSize:SZ.small, color:T.text3, textAlign:"right", cursor:"pointer" }}>{open?"▲":"▼"}</div></Tooltip>
      </div>
      {open && (
        <div style={{ background:T.bg3, borderBottom:`1px solid ${T.border1}`, padding:"12px 16px 12px 36px" }}>
          <div style={{ display:"grid", gridTemplateColumns:"160px 200px 160px 1fr", gap:12, alignItems:"start" }}>
            <div>
              <div style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", marginBottom:4, ...MONO, fontWeight:700 }}>STATUS</div>
              <select value={task.status} onChange={e=>{e.stopPropagation();handleStatusChange(e.target.value);}} onClick={e=>e.stopPropagation()}
                style={{ width:"100%", background:T.bg4, border:`1px solid ${T.border2}`, color:T.text1, padding:"5px 7px", fontSize:SZ.small, ...MONO, cursor:"pointer", outline:"none" }}>
                {STATUSES.map(s=><option key={s} value={s}>{s.replace(/_/g," ").toUpperCase()}</option>)}
              </select>
            </div>
            {onAssignTask && (
              <div>
                <div style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", marginBottom:4, ...MONO, fontWeight:700 }}>ASSIGNED TO</div>
                <select value={task.assigned_to||""} onChange={e=>{e.stopPropagation();onAssignTask(task.id,e.target.value||null);}} onClick={e=>e.stopPropagation()}
                  style={{ width:"100%", background:T.bg4, border:`1px solid ${T.border2}`, color:T.text1, padding:"5px 7px", fontSize:SZ.small, ...MONO, cursor:"pointer", outline:"none" }}>
                  <option value="">— Unassigned —</option>
                  {users.filter(u=>(u.role==="ops"||u.role==="admin")&&!u.is_super_admin).map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
                </select>
              </div>
            )}
            {onUpdateDueDate && (
              <div>
                <div style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", marginBottom:4, ...MONO, fontWeight:700 }}>DUE DATE</div>
                <input type="date" defaultValue={task.due_date||""} onBlur={e=>{e.stopPropagation();onUpdateDueDate(task.id, e.target.value||null);}} onClick={e=>e.stopPropagation()}
                  style={{ width:"100%", background:T.bg4, border:`1px solid ${T.border2}`, color:task.due_date?T.text1:T.text3, padding:"5px 7px", fontSize:SZ.small, ...MONO, cursor:"pointer", outline:"none", boxSizing:"border-box" }}/>
              </div>
            )}
            {task.template_description && (
              <div style={{ gridColumn:"1/-1", marginTop:4, padding:"8px 10px", background:T.bg2, borderLeft:`2px solid ${T.border2}` }}>
                <div style={{ fontSize:SZ.micro, color:T.text3, letterSpacing:"0.14em", marginBottom:4, ...MONO, fontWeight:700 }}>TASK GUIDANCE</div>
                <div style={{ fontSize:SZ.body, color:T.text2, lineHeight:1.5 }}>{task.template_description}</div>
              </div>
            )}
            {task.notes && (
              <div>
                <div style={{ fontSize:SZ.label, color:T.text2, letterSpacing:"0.16em", marginBottom:5, ...MONO }}>NOTES</div>
                <div style={{ fontSize:SZ.body, color:T.text1, background:T.bg4, padding:"8px 10px", border:`1px solid ${T.border1}`, ...INTER, lineHeight:"1.5" }}>{task.notes}</div>
              </div>
            )}
          </div>
          {task.files?.length>0 && (
            <div style={{ marginTop:10 }}>
              <div style={{ fontSize:SZ.label, color:T.text2, letterSpacing:"0.16em", marginBottom:5, ...MONO }}>FILES</div>
              {task.files.map(f=>(
                <div key={f.id} style={{ display:"flex", alignItems:"center", gap:8, padding:"4px 8px", background:T.bg4, border:`1px solid ${T.border1}`, marginBottom:3 }}>
                  <span style={{ fontSize:SZ.body, color:T.text3 }}>▣</span>
                  <span style={{ fontSize:SZ.body, color:T.blue }}>{f.file_name}</span>
                  <span style={{ fontSize:SZ.small, color:T.text3, marginLeft:"auto", ...MONO }}>{fmtDate(f.created_at)}</span>
                </div>
              ))}
            </div>
          )}
          {/* Template forms — pre-attached documents */}
          {(task.template_forms||[]).length>0&&(
            <div style={{ marginTop:10 }}>
              <div style={{ fontSize:SZ.label, color:T.blue, letterSpacing:"0.16em", marginBottom:6, ...MONO, fontWeight:700 }}>◈ REFERENCE DOCUMENTS</div>
              {(task.template_forms||[]).map((form,fi)=>(
                <div key={fi} style={{ display:"flex", alignItems:"flex-start", gap:10, padding:"8px 10px", background:T.bg4, border:`1px solid ${T.border1}`, borderLeft:`2px solid ${T.blue}44`, marginBottom:4 }}>
                  <span style={{ fontSize:SZ.body, color:T.blue, flexShrink:0 }}>⊞</span>
                  <div style={{ flex:1, minWidth:0 }}>
                    <a href={form.url} target="_blank" rel="noopener noreferrer"
                      style={{ fontSize:SZ.body, color:T.blue, fontWeight:700, ...RAJDHANI, letterSpacing:"0.04em", textDecoration:"none", display:"block", marginBottom:form.description?3:0 }}>
                      {form.label} ↗
                    </a>
                    {form.description&&<div style={{ fontSize:SZ.small, color:T.text2 }}>{form.description}</div>}
                  </div>
                </div>
              ))}
            </div>
          )}
          {task.depends_on_task_id&&<div style={{ marginTop:8, fontSize:SZ.label, color:T.text3, ...MONO }}>↳ PREDECESSOR DEPENDENCY</div>}

          {/* Linked AdvisorHUD Form — send from task context */}
          {task.required_form_id && currentUser && (currentUser.role==="admin"||currentUser.role==="ops") && (() => {
            const alreadySent = !!task.form_send_id;
            const isSubmitted = formSendStatus === "submitted";
            const isInProgress = formSendStatus === "draft_saved";
            const isOpened = formSendStatus === "opened";

            const statusColor = isSubmitted ? T.green : isInProgress ? T.amber : alreadySent ? T.blue : T.blue;
            const statusBg = isSubmitted ? T.greenDim : isInProgress ? T.amberDim : alreadySent ? T.blueGlow : T.blueGlow;
            const statusLabel = isSubmitted ? "◉ SUBMITTED" : isInProgress ? "◈ IN PROGRESS" : isOpened ? "◈ OPENED" : alreadySent ? "◈ FORM SENT" : "◈ LINKED FORM";
            const statusSub = isSubmitted ? "Form completed by recipient" : isInProgress ? "Recipient has started filling out the form" : isOpened ? "Recipient opened the form link" : alreadySent ? "Awaiting recipient submission" : "Send this form to the advisor or client from this task";

            return (
              <div style={{ marginTop:10, padding:"10px 12px", background:statusBg, border:`1px solid ${statusColor}44`, borderLeft:`2px solid ${statusColor}` }}>
                <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", gap:10 }}>
                  <div>
                    <div style={{ fontSize:SZ.label, color:statusColor, ...MONO, letterSpacing:"0.12em", fontWeight:700 }}>
                      {statusLabel}
                    </div>
                    <div style={{ fontSize:SZ.micro, color:T.text3, marginTop:2 }}>{statusSub}</div>
                  </div>
                  <button
                    onClick={e=>{ e.stopPropagation();
                      if (!linkedFormName) {
                        api.getFormDetail(task.required_form_id).then(f=>setLinkedFormName(f?.name||task.name)).catch(()=>setLinkedFormName(task.name));
                      }
                      setSendFormOpen(true); }}
                    style={{ padding:"5px 14px", background:isSubmitted?"transparent":alreadySent?"transparent":T.blue, border:`1px solid ${statusColor}66`, color:isSubmitted||alreadySent?statusColor:"#0a0e1a", cursor:"pointer", fontSize:SZ.micro, fontWeight:700, ...MONO, letterSpacing:"0.1em", flexShrink:0, transition:"all 0.15s" }}>
                    {isSubmitted ? "↗ VIEW" : alreadySent ? "↺ RESEND" : "◈ SEND FORM"}
                  </button>
                </div>
              </div>
            );
          })()}

          {/* SendFormModal triggered from task */}
          {sendFormOpen && task.required_form_id && currentUser && (() => {
            const formObj = { id: task.required_form_id, name: linkedFormName || task.name };
            // Pre-populate recipient from mission advisor if available
            const advisorEmail = inst?.advisor_email || "";
            const advisorName  = inst?.advisor_name  || "";
            return (
              <SendFormModal
                form={formObj}
                currentUser={currentUser}
                users={users||[]}
                prefillEmail={advisorEmail}
                prefillName={advisorName}
                onClose={()=>setSendFormOpen(false)}
                onSent={async(sendResult)=>{
                  setSendFormOpen(false);
                  // Stamp form_send_id onto the workflow_task so we know it was sent
                  if(sendResult?.id){
                    await sb.patch(`workflow_tasks?id=eq.${task.id}`, { form_send_id: sendResult.id }).catch(()=>{});
                    onFormSent?.(task.id, sendResult.id);
                  }
                }}
              />
            );
          })()}
        </div>
      )}
    </>
  );
};

// ── MISSIONS VIEW ──────────────────────────────────────────────

// ── OPS PHASE CONTROL PANEL ────────────────────────────────────
const PhaseControlPanel = ({ inst, onPhaseUpdated }) => {
  const [saving, setSaving] = useState(null);
  const [editNote, setEditNote] = useState({});
  const today = new Date().toISOString().split("T")[0];

  const isVisible = (p) => p.start_date && new Date(p.start_date+"T12:00:00") <= new Date();
  const isUpcoming = (p) => p.start_date && new Date(p.start_date+"T12:00:00") > new Date();

  const handleUnlock = async (phase) => {
    setSaving(phase.id);
    try {
      const note = editNote[phase.id] || null;
      await api.updatePhaseField(phase.id, { start_date: today, ops_note: note, status: "in_progress" });
      onPhaseUpdated(phase.id, { start_date: today, ops_note: note, status: "in_progress" });
      // Flip tasks with no incomplete predecessors to READY + stamp due dates
      const eligibleTasks = (phase.tasks||[]).filter(t=>
        t.status==="not_started" && !t.depends_on_task_id
      );
      for(const task of eligibleTasks){
        const dueDate = addDays(today, task.sla_days??2);
        await sb.patch(`workflow_tasks?id=eq.${task.id}`, { status:"ready", due_date:dueDate }).catch(()=>{});
        onPhaseUpdated(phase.id, {
          tasks:(phase.tasks||[]).map(t=>t.id===task.id?{...t,status:"ready",due_date:dueDate}:t)
        });
        // Notify assigned user or owner-type members
        if(task.assigned_to){
          await api.createNotification({ user_id:task.assigned_to, type:"status_update", body:`Task ready: "${task.name}"`, link_type:"mission", link_id:inst?.id }).catch(()=>{});
        }
      }
    } catch(e) { console.error(e); }
    finally { setSaving(null); }
  };

  const handleSchedule = async (phase, date) => {
    setSaving(phase.id);
    try {
      await api.updatePhaseField(phase.id, { start_date: date });
      onPhaseUpdated(phase.id, { start_date: date });
    } catch(e) { console.error(e); }
    finally { setSaving(null); }
  };

  const handleLock = async (phase) => {
    setSaving(phase.id);
    try {
      await api.updatePhaseField(phase.id, { start_date: null, ops_note: null });
      onPhaseUpdated(phase.id, { start_date: null, ops_note: null });
    } catch(e) { console.error(e); }
    finally { setSaving(null); }
  };

  const handleSaveNote = async (phase) => {
    setSaving(phase.id+"_note");
    try {
      const note = editNote[phase.id] ?? phase.ops_note ?? "";
      await api.updatePhaseField(phase.id, { ops_note: note||null });
      onPhaseUpdated(phase.id, { ops_note: note||null });
    } catch(e) { console.error(e); }
    finally { setSaving(null); }
  };

  return (
    <div style={{ marginBottom:20 }}>
      <div style={{ fontSize:SZ.label, color:T.text2, ...MONO, fontWeight:700, letterSpacing:"0.12em", marginBottom:10, paddingBottom:6, borderBottom:`1px solid ${T.border1}` }}>
        ◈ PHASE VISIBILITY CONTROL
        <span style={{ fontWeight:400, color:T.text3, marginLeft:8 }}>— ADVISOR SEES PHASES WITH A START DATE ≤ TODAY</span>
      </div>
      {inst.phases.map((phase, i) => {
        const visible = isVisible(phase);
        const upcoming = isUpcoming(phase);
        const locked = !phase.start_date;
        const isSaving = saving===phase.id;
        const noteVal = editNote[phase.id] !== undefined ? editNote[phase.id] : (phase.ops_note||"");
        return (
          <div key={phase.id} style={{ display:"grid", gridTemplateColumns:"28px 1fr auto", gap:10, alignItems:"start", padding:"8px 0", borderBottom:`1px solid ${T.border0}` }}>
            {/* Status indicator */}
            <div style={{ paddingTop:2 }}>
              <div style={{ width:10, height:10, borderRadius:"50%", background:visible?T.green:upcoming?T.amber:T.text3, margin:"0 auto" }}/>
            </div>
            {/* Phase info */}
            <div>
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>P{String(phase.sequence_order).padStart(2,"0")}</span>
                <span style={{ fontSize:SZ.small, fontWeight:700, color:visible?T.text0:T.text3, ...RAJDHANI, letterSpacing:"0.08em" }}>{phase.name.toUpperCase()}</span>
                {visible && <span style={{ fontSize:SZ.micro, color:T.green, ...MONO, fontWeight:700 }}>● LIVE</span>}
                {upcoming && <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO, fontWeight:700 }}>◌ SCHEDULED {fmtDate(phase.start_date)}</span>}
                {locked && i===0 && <span style={{ fontSize:SZ.micro, color:T.red, ...MONO }}>⚠ AUTO-START MISSING</span>}
              </div>
              {/* Ops note */}
              <div style={{ display:"flex", gap:6, alignItems:"center" }}>
                <input
                  value={noteVal}
                  onChange={e=>setEditNote(prev=>({...prev,[phase.id]:e.target.value}))}
                  placeholder="Advisor-visible note when phase unlocks (optional)..."
                  style={{ flex:1, background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"3px 8px", fontSize:SZ.micro, ...MONO, outline:"none" }}
                />
                {(editNote[phase.id]!==undefined && editNote[phase.id]!==(phase.ops_note||"")) && (
                  <button onClick={()=>handleSaveNote(phase)} disabled={saving===phase.id+"_note"}
                    style={{ padding:"3px 8px", background:T.blueGlow, border:`1px solid ${T.blue}`, color:T.blue, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>
                    {saving===phase.id+"_note"?"…":"SAVE"}
                  </button>
                )}
              </div>
            </div>
            {/* Actions */}
            <div style={{ display:"flex", gap:6, alignItems:"center", flexShrink:0 }}>
              {locked ? (
                <>
                  <input type="date" defaultValue={today}
                    onChange={e=>setEditNote(prev=>({...prev,[phase.id+"_date"]:e.target.value}))}
                    style={{ background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"3px 6px", fontSize:SZ.micro, ...MONO, outline:"none" }}
                  />
                  <button onClick={()=>handleUnlock(phase)} disabled={isSaving}
                    style={{ padding:"4px 10px", background:T.greenDim, border:`1px solid ${T.green}`, color:T.green, cursor:"pointer", fontSize:SZ.micro, fontWeight:700, letterSpacing:"0.08em", ...MONO, whiteSpace:"nowrap" }}>
                    {isSaving?"…":"▶ UNLOCK"}
                  </button>
                </>
              ) : (
                <>
                  <input type="date" value={phase.start_date||""}
                    onChange={e=>handleSchedule(phase, e.target.value)}
                    style={{ background:T.bg3, border:`1px solid ${T.border2}`, color:T.text1, padding:"3px 6px", fontSize:SZ.micro, ...MONO, outline:"none" }}
                  />
                  {!phase.auto_start && (
                    <button onClick={()=>handleLock(phase)} disabled={isSaving}
                      style={{ padding:"4px 10px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>
                      {isSaving?"…":"✕ LOCK"}
                    </button>
                  )}
                </>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
};

// AI: ONBOARDING (Missions) is mission control for all advisor onboardings. Left panel = mission list with progress bars and status. Right panel = phase and task detail with inline status controls, due dates, and file uploads. Ops uses this to execute tasks; advisors use BRIEFING instead.
const MissionsView = ({ instances, setInstances, users, selectedId, setSelectedId, onUpdateTask, play, onMissionComplete, onArchiveMission, currentUser, firmSpecialists, firmPrefs=[] }) => {
  const isMobile = useMobile();
  const [expandedPhases,setExpandedPhases]=useState(new Set());
  const togglePhase = (id) => setExpandedPhases(prev=>{
    const next = new Set(prev);
    next.has(id) ? next.delete(id) : next.add(id);
    return next;
  });
  const [confirmCancel,setConfirmCancel]=useState(false);
  const [showPhaseControl,setShowPhaseControl]=useState(false);
  const [myTeamInstId,setMyTeamInstId]=useState(null);

  const handlePhaseUpdated = (phaseId, fields) => {
    if(!setInstances) return;
    setInstances(prev=>prev.map(inst=>({
      ...inst,
      phases:inst.phases.map(p=>p.id===phaseId?{...p,...fields}:p)
    })));
  };
  const [missionTab, setMissionTab]=useState("all"); // "all" | "advisor_onboarding" | "client_onboarding"

  const tabInstances = missionTab==="all" ? instances
    : instances.filter(i => (i.mission_type||"advisor_onboarding")===missionTab);

  const inst=tabInstances.find(i=>i.id===selectedId)||tabInstances[0];

  const advisorCount = instances.filter(i=>(i.mission_type||"advisor_onboarding")==="advisor_onboarding").length;
  const clientCount  = instances.filter(i=>i.mission_type==="client_onboarding").length;

  if(!inst) return (
    <div style={{ padding:"28px 32px", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", minHeight:400 }}>
      <div style={{ fontSize:SZ.stat, marginBottom:16, opacity:0.15 }}>◈</div>
      <div style={{ fontSize:SZ.body, color:T.text2, letterSpacing:"0.14em", ...MONO }}>NO ACTIVE ONBOARDINGS</div>
      <div style={{ fontSize:SZ.small, color:T.text3, marginTop:6, ...MONO }}>Deploy an onboarding from the sidebar to begin</div>
    </div>
  );
  const allTasks=inst.phases.flatMap(p=>p.tasks);
  const pct=calcPct(allTasks);


  // Check if mission just completed
  const handleTaskUpdate = async (taskId, newStatus) => {
    await onUpdateTask(taskId, newStatus);
    if (newStatus==="completed" && play) play("task");
  };

  const handleAssignTask = async (taskId, userId) => {
    try {
      await sb.patch(`workflow_tasks?id=eq.${taskId}`, { assigned_to: userId });
      // Notify the newly assigned user (skip if unassigning or self-assigning)
      if (userId && userId !== currentUser?.id) {
        const task = instances.flatMap(i=>i.phases.flatMap(p=>p.tasks)).find(t=>t.id===taskId);
        const inst = instances.find(i=>i.phases.some(p=>p.tasks.some(t=>t.id===taskId)));
        if (task && inst) {
          await api.createNotification({
            user_id: userId,
            type: "assigned",
            body: `${currentUser?.name} assigned you to "${task.name}" on the ${inst.advisor_name} mission`,
            link_type: "task",
            link_id: taskId,
          }).catch(()=>{});
        }
      }
    } catch(e){ console.error(e); }
  };

  const handleUpdateDueDate = async (taskId, dueDate) => {
    try {
      await sb.patch(`workflow_tasks?id=eq.${taskId}`, { due_date: dueDate || null });
    } catch(e){ console.error(e); }
  };

  return (
    <div style={{ padding: isMobile ? "16px 14px" : "28px 32px" }}>
      {/* Onboarding type tabs */}
      <div style={{ display:"flex", gap:0, marginBottom:0, borderBottom:`1px solid ${T.border1}` }}>
        {[
          { id:"all",               label:"ALL",              count:instances.length,  color:T.blue   },
          { id:"advisor_onboarding",label:"ADVISOR",          count:advisorCount,      color:T.blue   },
          { id:"client_onboarding", label:"CLIENT ONBOARDING",count:clientCount,       color:T.teal   },
        ].map(tab=>{
          const active=missionTab===tab.id;
          return (
            <button key={tab.id} onClick={()=>{ setMissionTab(tab.id); setExpandedPhases(new Set()); }}
              style={{ padding:"8px 16px", border:"none", borderBottom:`2px solid ${active?tab.color:"transparent"}`, background:"transparent", color:active?tab.color:T.text2, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.1em", fontWeight:active?700:500, marginBottom:-1, display:"flex", alignItems:"center", gap:6, transition:"all 0.1s" }}>
              {tab.label}
              <span style={{ background:active?`${tab.color}22`:T.bg3, color:active?tab.color:T.text3, padding:"1px 5px", fontSize:SZ.micro, ...MONO, fontWeight:600 }}>{tab.count}</span>
            </button>
          );
        })}
      </div>

      {/* Mission switcher */}
      <div style={{ display:"flex", gap:4, marginTop:16, marginBottom:20, borderBottom:`1px solid ${T.border0}`, paddingBottom:0, flexWrap:"wrap" }}>
        {tabInstances.map(i=>{
          const active=selectedId===i.id;
          const iTasks=i.phases.flatMap(p=>p.tasks);
          const hasAlert=iTasks.some(t=>t.status==="blocked"||isOverdue(t));
          const mt=getMissionType(i.mission_type);
          return (
            <button key={i.id} onClick={()=>{setSelectedId(i.id);setExpandedPhases(new Set());}}
              style={{ padding:"10px 18px", border:"none", borderBottom:`2px solid ${active?mt.color:"transparent"}`, background:"transparent", color:active?mt.color:T.text2, cursor:"pointer", fontSize:SZ.small, ...INTER, letterSpacing:"0em", fontWeight:active?600:400, marginBottom:-1, transition:"all 0.1s", display:"flex", alignItems:"center", gap:6 }}>
              <span style={{ fontSize:SZ.small, color:active?mt.color:mt.color, opacity:active?1:0.5 }}>{mt.icon}</span>
              {i.advisor_name}
              {hasAlert&&<span style={{ width:5, height:5, background:T.amber, transform:"rotate(45deg)", display:"inline-block" }}/>}
            </button>
          );
        })}
      </div>

      {/* MY TEAM modal */}
      {myTeamInstId===inst.id && (
        <MyTeamModal inst={inst} users={users} firmSpecialists={firmSpecialists||[]} onClose={()=>setMyTeamInstId(null)}/>
      )}

      {/* Mission header */}
      <div style={{ background:T.bg1, border:`1px solid ${T.border1}`, padding:"20px 24px", marginBottom:20 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:16, gap:12, flexWrap:"wrap" }}>
          <div>
            <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:4 }}>
              <div style={{ fontSize:SZ.title, fontWeight:700, color:T.white, ...INTER, letterSpacing:"-0.01em" }}>{inst.advisor_name}</div>
              <MissionTypeBadge typeId={inst.mission_type}/>
            </div>
            <div style={{ fontSize:SZ.small, color:T.text2, letterSpacing:"0.02em", marginTop:4, ...INTER }}>
              Engaged {fmtDate(inst.start_date)}{inst.mission_type!=="client_onboarding" && inst.target_date ? ` · ${GO_LIVE_TERM} ${fmtDate(inst.target_date)}` : ""}
            </div>
            {inst.notes&&<div style={{ fontSize:SZ.body, color:T.text2, marginTop:8 }}>{inst.notes}</div>}
          </div>
          <div style={{ display:"flex", gap:8, alignItems:"center", flexWrap:"wrap", justifyContent:"flex-end", flexShrink:0 }}>
            {inst.assignedUsers.map(uid=><Avatar key={uid} userId={uid} users={users} size={32}/>)}
            <Badge status={inst.status}/>
            <button onClick={()=>setMyTeamInstId(s=>s===inst.id?null:inst.id)}
              style={{ padding:"4px 12px", background:"none", border:`1px solid ${T.border1}`, color:T.text2, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700, letterSpacing:"0.1em", transition:"all 0.1s" }}
              onMouseEnter={e=>{e.currentTarget.style.color=T.teal;e.currentTarget.style.borderColor=T.teal;}}
              onMouseLeave={e=>{e.currentTarget.style.color=T.text2;e.currentTarget.style.borderColor=T.border1;}}>
              ◈ MY TEAM
            </button>
            <button onClick={()=>setShowPhaseControl(s=>!s)}
              style={{ padding:"4px 10px", background:showPhaseControl?T.blueGlow:"none", border:`1px solid ${showPhaseControl?T.blue:T.border2}`, color:showPhaseControl?T.blue:T.text2, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.1em", transition:"all 0.1s" }}>
              ◈ PHASE CONTROL
            </button>
            {currentUser?.role==="admin" && inst.status!=="cancelled" && (
              <button onClick={()=>setConfirmCancel(true)}
                style={{ padding:"4px 10px", background:"none", border:`1px solid ${T.border2}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.1em", transition:"all 0.1s" }}
                onMouseEnter={e=>{e.currentTarget.style.color=T.red;e.currentTarget.style.borderColor=T.red;}}
                onMouseLeave={e=>{e.currentTarget.style.color=T.text3;e.currentTarget.style.borderColor=T.border2;}}>
                ⊗ CANCEL ONBOARDING
              </button>
            )}
          </div>
        </div>

        {/* Progress with Go Live context */}
        <div style={{ marginBottom:14 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
            <span style={{ fontSize:SZ.label, color:T.text2, letterSpacing:"0.16em", ...MONO }}>ONBOARDING PROGRESS{inst.mission_type!=="client_onboarding" && inst.target_date ? ` · ${GO_LIVE_TERM} ${Math.max(0,Math.round((new Date(inst.target_date+"T12:00:00")-new Date())/(1000*60*60*24)))} DAYS` : ""}</span>
            <span style={{ fontSize:SZ.body, color:pct===100?T.green:T.blue, ...MONO, fontWeight:700 }}>{pct}%</span>
          </div>
          <ProgressBar pct={pct} height={6} segments animate/>
        </div>

        {/* Cancel mission confirm */}
        {confirmCancel&&(
          <div style={{ marginBottom:14, padding:"12px 16px", background:T.redDim, border:`1px solid ${T.red}44`, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <span style={{ fontSize:SZ.small, color:T.red, ...MONO }}>⚠ CANCEL "{inst.advisor_name}" mission? It will be archived and removed from the active view.</span>
            <div style={{ display:"flex", gap:8 }}>
              <button onClick={()=>setConfirmCancel(false)} style={{ padding:"4px 12px", background:"none", border:`1px solid ${T.border2}`, color:T.text2, cursor:"pointer", fontSize:SZ.label, ...MONO }}>KEEP</button>
              <button onClick={()=>{onArchiveMission(inst.id);setConfirmCancel(false);}} style={{ padding:"4px 12px", background:T.redDim, border:`1px solid ${T.red}`, color:T.red, cursor:"pointer", fontSize:SZ.label, ...MONO, fontWeight:700 }}>CONFIRM CANCEL</button>
            </div>
          </div>
        )}

        {/* Phase control panel */}
        {showPhaseControl && inst && (
          <div style={{ margin:"16px 0", padding:"14px 16px", background:T.bg2, border:`1px solid ${T.border2}` }}>
            <PhaseControlPanel inst={inst} onPhaseUpdated={handlePhaseUpdated}/>
          </div>
        )}

      </div>

      {/* Phase + task tables — collapsible */}
      {inst.phases.map(phase=>{
        const phasePct=calcPct(phase.tasks);
        const phaseComplete=phasePct===100;
        const isExpanded=expandedPhases.has(phase.id);
        // Phase visual state: complete=green, has_progress=blue, standby=dimmed
        const hasProgress = phasePct > 0 && !phaseComplete;
        const isActive = phase.status==="in_progress" || hasProgress;
        const isStandby = !phaseComplete && !isActive;
        const accentColor = phaseComplete?T.green:isActive?T.blue:T.border1;
        const rowBg = phaseComplete?T.greenDim:isActive?`${T.blue}08`:T.bg2;
        const textColor = phaseComplete?T.green:isActive?T.text0:T.text3;
        const rowOpacity = isStandby ? 0.6 : 1;
        return (
          <div key={phase.id} style={{ marginBottom:6, border:`1px solid ${phaseComplete?T.green+"44":isActive?T.blue+"33":T.border0}`, background:T.bg1, overflow:"hidden", transition:"all 0.3s", opacity:rowOpacity }}>
            {/* Phase header — click to expand/collapse */}
            <div onClick={()=>togglePhase(phase.id)}
              style={{ padding:"11px 16px", background:rowBg, display:"flex", justifyContent:"space-between", alignItems:"center", borderLeft:`3px solid ${accentColor}`, cursor:"pointer", transition:"background 0.15s", userSelect:"none" }}
              onMouseEnter={e=>{if(!phaseComplete)e.currentTarget.style.background=T.bg3;}}
              onMouseLeave={e=>{e.currentTarget.style.background=rowBg;}}>
              <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                <span style={{ fontSize:SZ.label, color:isStandby?T.text3:T.text2, ...MONO }}>P{phase.sequence_order.toString().padStart(2,"0")}</span>
                {isActive && !phaseComplete && <div style={{ width:5, height:5, borderRadius:"50%", background:T.blue, boxShadow:`0 0 6px ${T.blue}`, flexShrink:0 }}/>}
                <span style={{ fontSize:SZ.body, fontWeight:isStandby?400:700, color:textColor, ...RAJDHANI, letterSpacing:"0.1em", transition:"color 0.3s" }}>{phase.name.toUpperCase()}</span>
                <Badge status={phaseComplete?"completed":isActive?"in_progress":phase.status} small/>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                <span style={{ fontSize:SZ.small, color:phaseComplete?T.green:isActive?T.blue:T.text3, ...MONO, fontWeight:phaseComplete||isActive?700:400 }}>{phase.tasks.filter(t=>t.status==="completed").length}/{phase.tasks.length}</span>
                {phasePct>0&&<div style={{ width:80 }}><ProgressBar pct={phasePct} animate/></div>}
                <span style={{ fontSize:SZ.small, color:T.text3, ...MONO, transition:"transform 0.2s", display:"inline-block", transform:isExpanded?"rotate(180deg)":"rotate(0deg)" }}>▼</span>
              </div>
            </div>
            {/* Task list — only shown when expanded */}
            {isExpanded && (
              <>
                <div style={{ display:"grid", gridTemplateColumns:"6px 1fr 100px 80px 120px 20px", gap:10, padding:"6px 16px", borderBottom:`1px solid ${T.border0}`, background:T.bg2, borderTop:`1px solid ${T.border0}` }}>
                  {["","TASK","STATUS","DUE DATE","OWNER",""].map((h,i)=>(
                    <div key={i} style={{ fontSize:SZ.micro, color:T.text2, letterSpacing:"0.16em", fontWeight:700, ...MONO, whiteSpace:"nowrap" }}>{h}</div>
                  ))}
                </div>
                {phase.tasks.map(task=><TaskRow key={task.id} task={task} users={users} onStatusChange={onUpdateTask} onAssignTask={handleAssignTask} onUpdateDueDate={handleUpdateDueDate} play={play} currentUser={currentUser} inst={inst} onFormSent={(taskId, sendId)=>{ if(setInstances) setInstances(prev=>prev.map(mi=>({...mi, phases:mi.phases.map(p=>({...p, tasks:p.tasks.map(t=>t.id===taskId?{...t,form_send_id:sendId}:t)}))})));}}/>)}
              </>
            )}
          </div>
        );
      })}
    </div>
  );
};

// ── REQUESTS VIEW ──────────────────────────────────────────────
const REQUEST_TYPES = [
  "Account Maintenance","New Account","Money Movement","B/D Change",
  "Platform Access","ACAT Transfer","SBLOC","Alternatives",
  "Compliance","Branded Materials","General Request","Other",
];




// ── PLAYBOOK PANEL ────────────────────────────────────────────────
const WAITING_ON_COLORS = {
  ops:      { color: "#5b9fd4", label: "OPS" },
  advisor:  { color: "#3dba7a", label: "ADVISOR" },
  client:   { color: "#e09d3a", label: "CLIENT" },
  external: { color: "#9b7dc8", label: "EXTERNAL" },
};

const PlaybookPanel = ({ request, currentUser, users, playbookTemplates, onPlaybookChange }) => {
  const [playbook, setPlaybook] = useState(null);
  const [loading, setLoading] = useState(true);
  const [attaching, setAttaching] = useState(false);
  const [showAttach, setShowAttach] = useState(false);
  const [completingStep, setCompletingStep] = useState(null); // stepId
  const [stepNotes, setStepNotes] = useState("");
  const [expandedStep, setExpandedStep] = useState(null);
  const [firmForms, setFirmForms] = useState([]);
  const [sendFormStepId, setSendFormStepId] = useState(null); // stepId whose modal is open
  const [stepFormStatuses, setStepFormStatuses] = useState({}); // { [stepId]: "sent"|"opened"|"draft_saved"|"submitted" }
  const isOps = currentUser?.role === "admin" || currentUser?.role === "ops";

  useEffect(() => {
    sb.get("form_definitions?is_archived=eq.false&order=name&select=id,name,category")
      .then(d => setFirmForms(d||[])).catch(()=>{});
  }, []);

  // Poll form send status for any step that has a form_send_id
  useEffect(() => {
    if (!playbook?.request_playbook_steps) return;
    const stepsWithSend = playbook.request_playbook_steps.filter(s => s.form_send_id);
    if (!stepsWithSend.length) return;
    Promise.all(stepsWithSend.map(s =>
      api.getFormSend(s.form_send_id).then(send => ({ stepId: s.id, status: send?.status || "sent" })).catch(() => null)
    )).then(results => {
      const map = {};
      results.filter(Boolean).forEach(r => { map[r.stepId] = r.status; });
      setStepFormStatuses(map);
    });
  }, [playbook?.request_playbook_steps?.map(s=>s.form_send_id).join(",")]);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    api.getRequestPlaybook(request.id).then(pb => {
      if (!cancelled) { setPlaybook(pb); setLoading(false); }
    }).catch(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [request.id]);

  const handleAttach = async (templateId) => {
    const tmpl = playbookTemplates.find(t => t.id === templateId);
    if (!tmpl) return;
    setAttaching(true);
    try {
      const steps = [...(tmpl.playbook_template_steps || [])].sort((a,b) => a.step_order - b.step_order);
      const pb = await api.attachPlaybook(request.id, templateId, currentUser?.id, steps);
      setPlaybook({ ...pb, playbook_templates: tmpl, request_playbook_steps: pb.request_playbook_steps });
      audit(currentUser).log({ action:"PLAYBOOK_ATTACHED", entityType:"request", entityId:request.id, entityLabel:request.title, newValue:{playbook:tmpl.name} });
      setShowAttach(false);
      onPlaybookChange?.();
    } catch(e) { console.error(e); }
    finally { setAttaching(false); }
  };

  const handleComplete = async (step) => {
    if (completingStep === step.id) {
      // Confirm
      const steps = [...(playbook.request_playbook_steps||[])].sort((a,b) => a.step_order - b.step_order);
      const nextStep = steps.find(s => s.step_order > step.step_order && s.status === "pending");
      try {
        await api.completePlaybookStep(step.id, currentUser?.id, stepNotes, nextStep || null);
        audit(currentUser).log({ action:"PLAYBOOK_STEP_COMPLETED", entityType:"request", entityId:request.id, entityLabel:request.title, metadata:{step:step.name, notes:stepNotes?.slice(0,120)||null} });
        // Notify request submitter that a step progressed
        if(request.submitted_by && request.submitted_by!==currentUser?.id) {
          const msg = nextStep
            ? `Step "${step.name}" completed on "${request.title}" — now waiting on: ${nextStep.waiting_on||"next step"}`
            : `All steps complete on "${request.title}"`;
          await api.createNotification({ user_id:request.submitted_by, type:"playbook_step", body:msg, link_type:"request", link_id:request.id }).catch(()=>{});
        }
        setPlaybook(prev => {
          const updatedSteps = prev.request_playbook_steps.map(s => {
            if (s.id === step.id) return { ...s, status:"complete", completed_at: new Date().toISOString(), notes: stepNotes||null };
            if (nextStep && s.id === nextStep.id) return { ...s, status:"active", started_at: new Date().toISOString(), due_at: new Date(Date.now()+s.expected_days*24*60*60*1000).toISOString() };
            return s;
          });
          return { ...prev, request_playbook_steps: updatedSteps };
        });
        setCompletingStep(null);
        setStepNotes("");
      } catch(e) { console.error(e); }
    } else {
      setCompletingStep(step.id);
      setStepNotes(step.notes || "");
      setExpandedStep(step.id);
    }
  };

  const handleSkip = async (step) => {
    const steps = [...(playbook.request_playbook_steps||[])].sort((a,b) => a.step_order - b.step_order);
    const nextStep = steps.find(s => s.step_order > step.step_order && s.status === "pending");
    await api.skipPlaybookStep(step.id, currentUser?.id, "Skipped");
    audit(currentUser).log({ action:"PLAYBOOK_STEP_SKIPPED", entityType:"request", entityId:request.id, entityLabel:request.title, metadata:{step:step.name} });
    if (nextStep) await api.completePlaybookStep(null, null, null, nextStep);
    setPlaybook(prev => ({
      ...prev,
      request_playbook_steps: prev.request_playbook_steps.map(s => {
        if (s.id === step.id) return { ...s, status:"skipped" };
        if (nextStep && s.id === nextStep.id) return { ...s, status:"active", started_at:new Date().toISOString(), due_at:new Date(Date.now()+s.expected_days*24*60*60*1000).toISOString() };
        return s;
      })
    }));
  };

  const getDaysOverdue = (step) => {
    if (!step.due_at || step.status !== "active") return null;
    const diff = Math.floor((Date.now() - new Date(step.due_at)) / (1000*60*60*24));
    return diff > 0 ? diff : null;
  };

  const getDaysRemaining = (step) => {
    if (!step.due_at || step.status !== "active") return null;
    const diff = Math.ceil((new Date(step.due_at) - Date.now()) / (1000*60*60*24));
    return diff >= 0 ? diff : null;
  };

  if (loading) return null;

  // No playbook attached
  if (!playbook) {
    if (!isOps) return null;
    const matchingTemplate = playbookTemplates?.find(t => t.request_type === (request.request_type || request.type));
    return (
      <div style={{ margin:"8px 0 6px", display:"flex", alignItems:"center", justifyContent:"space-between", gap:8 }}>
        <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, letterSpacing:"0.06em" }}>
          {matchingTemplate
            ? <><span style={{ color:T.blue }}>◈</span> {matchingTemplate.name} playbook available</>
            : "NO PLAYBOOK FOR THIS TYPE"
          }
        </div>
        {matchingTemplate && (
          showAttach ? (
            <div style={{ display:"flex", gap:6, alignItems:"center" }}>
              <span style={{ fontSize:SZ.small, color:T.text2, ...INTER }}>Attach {matchingTemplate.name}?</span>
              <button onClick={()=>handleAttach(matchingTemplate.id)} disabled={attaching}
                style={{ padding:"4px 10px", background:T.blueGlow, border:`1px solid ${T.blue}`, color:T.blue, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>
                {attaching?"ATTACHING...":"ATTACH"}
              </button>
              <button onClick={()=>setShowAttach(false)} style={{ padding:"4px 8px", background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>✕</button>
            </div>
          ) : (
            <button onClick={()=>setShowAttach(true)}
              style={{ padding:"4px 12px", background:"none", border:`1px solid ${T.border2}`, color:T.text2, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.08em" }}>
              + ATTACH PLAYBOOK
            </button>
          )
        )}
      </div>
    );
  }

  // Playbook attached — render steps
  const steps = [...(playbook.request_playbook_steps||[])].sort((a,b) => a.step_order - b.step_order);
  const completed = steps.filter(s => s.status === "complete" || s.status === "skipped").length;
  const activeStep = steps.find(s => s.status === "active");
  const allDone = steps.every(s => s.status === "complete" || s.status === "skipped");
  const overdueCount = steps.filter(s => getDaysOverdue(s) !== null).length;

  return (
    <div style={{ margin:"14px 0", border:`1px solid ${overdueCount>0?T.amber+"66":T.border2}`, background:T.bg1 }}>
      {/* Playbook header */}
      <div style={{ padding:"10px 14px", borderBottom:`1px solid ${T.border1}`, display:"flex", alignItems:"center", justifyContent:"space-between", background:T.bg2 }}>
        <div style={{ display:"flex", alignItems:"center", gap:10 }}>
          <span style={{ color:T.blue, fontSize:SZ.small }}>◈</span>
          <span style={{ fontSize:SZ.small, fontWeight:700, color:T.text0, ...MONO, letterSpacing:"0.1em" }}>
            {(playbook.playbook_templates?.name || "PLAYBOOK").toUpperCase()}
          </span>
          <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{completed}/{steps.length} STEPS</span>
          {overdueCount > 0 && (
            <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO, background:`${T.amber}18`, padding:"2px 7px", fontWeight:700 }}>
              ⚠ {overdueCount} OVERDUE
            </span>
          )}
          {allDone && (
            <span style={{ fontSize:SZ.micro, color:T.green, ...MONO, background:`${T.green}18`, padding:"2px 7px", fontWeight:700 }}>✓ COMPLETE</span>
          )}
        </div>
        {/* Progress bar */}
        <div style={{ width:100, height:4, background:T.bg4, borderRadius:2, overflow:"hidden" }}>
          <div style={{ width:`${(completed/steps.length)*100}%`, height:"100%", background:allDone?T.green:T.blue, transition:"width 0.3s" }}/>
        </div>
      </div>

      {/* Steps */}
      <div>
        {steps.map((step, idx) => {
          const isActive = step.status === "active";
          const isDone = step.status === "complete" || step.status === "skipped";
          const isPending = step.status === "pending";
          const isConfirming = completingStep === step.id;
          const daysOver = getDaysOverdue(step);
          const daysLeft = getDaysRemaining(step);
          const wo = WAITING_ON_COLORS[step.waiting_on] || WAITING_ON_COLORS.ops;
          const completedByUser = users?.find(u => u.id === step.completed_by);

          return (
            <div key={step.id}
              style={{ borderBottom: idx < steps.length-1 ? `1px solid ${T.border0}` : "none",
                background: isActive ? `${T.blue}07` : "transparent" }}>
              <div style={{ padding:"9px 14px", display:"flex", alignItems:"flex-start", gap:10, cursor: (isActive||isDone) ? "pointer":"default" }}
                onClick={() => (isActive||isDone) && setExpandedStep(expandedStep===step.id?null:step.id)}>
                {/* Step indicator */}
                <div style={{ width:20, height:20, flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center", marginTop:1 }}>
                  {isDone
                    ? <span style={{ color:step.status==="skipped"?T.text3:T.green, fontSize:14 }}>{step.status==="skipped"?"–":"✓"}</span>
                    : isActive
                      ? <div style={{ width:10, height:10, borderRadius:"50%", background:daysOver?T.amber:T.blue, boxShadow:`0 0 6px ${daysOver?T.amber:T.blue}` }}/>
                      : <div style={{ width:8, height:8, borderRadius:"50%", border:`1px solid ${T.border2}` }}/>
                  }
                </div>

                {/* Step content */}
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:8, flexWrap:"wrap" }}>
                    <span style={{ fontSize:SZ.small, color:isDone?T.text3:isActive?T.text0:T.text2, ...INTER, fontWeight:isActive?600:400,
                      textDecoration:step.status==="skipped"?"line-through":"none" }}>
                      {step.name}
                    </span>
                    <span style={{ fontSize:SZ.micro, color:wo.color, ...MONO, background:`${wo.color}18`, padding:"1px 5px", flexShrink:0 }}>
                      {wo.label}
                    </span>
                    {isActive && daysOver !== null && (
                      <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO, fontWeight:700 }}>⚠ {daysOver}d OVERDUE</span>
                    )}
                    {isActive && daysLeft !== null && daysLeft <= 1 && (
                      <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO }}>DUE TODAY</span>
                    )}
                    {isActive && daysLeft !== null && daysLeft > 1 && (
                      <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>due in {daysLeft}d</span>
                    )}
                    {isDone && completedByUser && (
                      <span style={{ fontSize:SZ.micro, color:T.text3, ...MONO }}>{completedByUser.initials} · {fmtDate(step.completed_at)}</span>
                    )}
                  </div>
                  {step.notes && !isConfirming && (
                    <div style={{ fontSize:SZ.small, color:T.text2, ...INTER, marginTop:3, fontStyle:"italic" }}>{step.notes}</div>
                  )}
                </div>

                {/* Action buttons — active step only, ops/admin only */}
                {isActive && isOps && !isConfirming && (() => {
                  const sendStatus = stepFormStatuses[step.id];
                  const isSubmitted = sendStatus === "submitted";
                  const isInProgress = sendStatus === "draft_saved";
                  const isOpened = sendStatus === "opened";
                  const btnColor = isSubmitted ? T.green : isInProgress ? T.amber : isOpened ? T.blue : T.blue;
                  const btnLabel = isSubmitted ? "◉ SUBMITTED" : isInProgress ? "◈ IN PROGRESS" : isOpened ? "◈ OPENED" : step.form_send_id ? "↺ RESEND" : "◈ SEND FORM";
                  return (
                    <div style={{ display:"flex", gap:4, flexShrink:0 }} onClick={e=>e.stopPropagation()}>
                      {step.required_form_id && (
                        <button onClick={()=>setSendFormStepId(step.id)}
                          style={{ padding:"3px 9px", background:`${btnColor}18`, border:`1px solid ${btnColor}44`, color:btnColor, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>
                          {btnLabel}
                        </button>
                      )}
                      <button onClick={()=>handleComplete(step)}
                        style={{ padding:"3px 9px", background:`${T.green}18`, border:`1px solid ${T.green}44`, color:T.green, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>
                        ✓ DONE
                      </button>
                      {!step.is_blocking && (
                        <button onClick={()=>handleSkip(step)}
                          style={{ padding:"3px 7px", background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>
                          SKIP
                        </button>
                      )}
                    </div>
                  );
                })()}
                {/* Show form status badge on done steps */}
                {isDone && step.form_send_id && (() => {
                  const sendStatus = stepFormStatuses[step.id];
                  const isSubmitted = sendStatus === "submitted";
                  const color = isSubmitted ? T.green : T.blue;
                  const label = isSubmitted ? "◉ SUBMITTED" : "◉ FORM SENT";
                  return (
                    <div style={{ flexShrink:0 }}>
                      <span style={{ fontSize:SZ.micro, color, ...MONO, background:`${color}18`, padding:"2px 7px" }}>{label}</span>
                    </div>
                  );
                })()}
                {isDone && step.required_form_id && !step.form_send_id && (
                  <div style={{ flexShrink:0 }}>
                    <span style={{ fontSize:SZ.micro, color:T.amber, ...MONO, background:`${T.amber}18`, padding:"2px 7px" }}>⚠ FORM NOT SENT</span>
                  </div>
                )}
              </div>

              {/* Completion confirm / notes inline */}
              {isConfirming && isActive && (
                <div style={{ padding:"0 14px 10px 44px" }} onClick={e=>e.stopPropagation()}>
                  <div style={{ fontSize:SZ.micro, color:T.text3, ...MONO, marginBottom:4, letterSpacing:"0.08em" }}>STEP NOTES (optional)</div>
                  <input value={stepNotes} onChange={e=>setStepNotes(e.target.value)}
                    placeholder="e.g. carrier confirmed receipt, partial transfer — resubmitting residual..."
                    style={{ width:"100%", background:T.bg4, border:`1px solid ${T.border2}`, color:T.text0, padding:"5px 8px", fontSize:SZ.small, ...INTER, outline:"none", boxSizing:"border-box", marginBottom:6 }}
                    onKeyDown={e=>{if(e.key==="Escape"){setCompletingStep(null);setStepNotes("");}}}
                    autoFocus/>
                  <div style={{ display:"flex", gap:6 }}>
                    <button onClick={()=>handleComplete(step)}
                      style={{ padding:"4px 12px", background:`${T.green}22`, border:`1px solid ${T.green}66`, color:T.green, cursor:"pointer", fontSize:SZ.micro, ...MONO, fontWeight:700 }}>
                      CONFIRM COMPLETE
                    </button>
                    <button onClick={()=>{setCompletingStep(null);setStepNotes("");}}
                      style={{ padding:"4px 8px", background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO }}>
                      CANCEL
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* SendFormModal triggered from playbook step */}
      {sendFormStepId && (() => {
        const step = steps.find(s => s.id === sendFormStepId);
        if (!step?.required_form_id) return null;
        const formObj = firmForms.find(f => f.id === step.required_form_id) || { id: step.required_form_id, name: step.name };
        const requesterEmail = request.requester_email || "";
        const requesterName  = request.requester_name  || request.advisor_name || "";
        return (
          <SendFormModal
            form={formObj}
            currentUser={currentUser}
            users={users||[]}
            prefillEmail={requesterEmail}
            prefillName={requesterName}
            onClose={()=>setSendFormStepId(null)}
            onSent={async(sendResult)=>{
              setSendFormStepId(null);
              if (sendResult?.id) {
                await sb.patch(`request_playbook_steps?id=eq.${step.id}`, { form_send_id: sendResult.id }).catch(()=>{});
                setPlaybook(prev=>({
                  ...prev,
                  request_playbook_steps: prev.request_playbook_steps.map(s =>
                    s.id === step.id ? { ...s, form_send_id: sendResult.id } : s
                  )
                }));
              }
            }}
          />
        );
      })()}
    </div>
  );
};
