      <button onClick={()=>setEditing(false)} style={{ padding:"5px 8px", background:"none", border:`1px solid ${T.border1}`, color:T.text3, cursor:"pointer", fontSize:SZ.micro, ...MONO, flexShrink:0 }}>✕</button>
