const getScreenHintKey  = (userId, view) => `ahud_hint_${userId}_${view}`;
const getScreenHintCount = (userId, view) => parseInt(localStorage.getItem(getScreenHintKey(userId, view)) || "0");
const bumpScreenHint    = (userId, view) => {
  const n = getScreenHintCount(userId, view) + 1;
  localStorage.setItem(getScreenHintKey(userId, view), String(n));
};
const shouldShowHint    = (userId, view) => getScreenHintCount(userId, view) < 3;

// ── WELCOME MODAL ──────────────────────────────────────────────
const WelcomeModal = ({ currentUser, mode, onDismiss, onNavigate }) => {
  const role   = currentUser?.is_super_admin ? "super_admin" : (currentUser?.role || "advisor");
  const name   = currentUser?.name?.split(" ")[0] || "";
  const content = mode === "orientation"
    ? (WELCOME_ORIENTATION[role] || WELCOME_ORIENTATION.advisor)
    : WELCOME_WHATS_NEW;

  const accentColor = mode === "orientation"
    ? ({ ops: T.blue, admin: T.amber, advisor: T.green, super_admin: T.blue }[role] || T.blue)
    : T.blue;

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 2000,
      background: "rgba(7,8,10,0.85)",
      display: "flex", alignItems: "center", justifyContent: "center",
      backdropFilter: "blur(4px)",
    }}>
      <div style={{
        width: "100%", maxWidth: 520,
        background: T.bg1,
        border: `1px solid ${accentColor}44`,
        borderTop: `3px solid ${accentColor}`,
        clipPath: "polygon(0 0, calc(100% - 16px) 0, 100% 16px, 100% 100%, 0 100%)",
        boxShadow: `0 24px 80px rgba(0,0,0,0.7), 0 0 0 1px ${accentColor}22`,
        overflow: "hidden",
      }}>

        {/* Header */}
        <div style={{ padding: "28px 32px 20px", borderBottom: `1px solid ${T.border1}` }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
            <F22Mark size={28} color={accentColor} />
            <div style={{ fontSize: SZ.micro, color: accentColor, ...MONO, letterSpacing: "0.16em", fontWeight: 700 }}>
              ADVISORHUD · v{APP_VERSION}
            </div>
          </div>
          <div style={{ fontSize: SZ.title, fontWeight: 700, color: T.white, ...INTER, letterSpacing: "-0.01em", marginBottom: 4 }}>
            {content.headline}{name ? ` ${name}.` : ""}
          </div>
          <div style={{ fontSize: SZ.body, color: T.text2, ...INTER }}>
            {content.subtitle}
          </div>
        </div>

        {/* Items */}
        <div style={{ padding: "20px 32px", display: "flex", flexDirection: "column", gap: 14 }}>
          {content.items.map((item, i) => (
            <div key={i} style={{ display: "flex", gap: 14, alignItems: "flex-start" }}>
              <div style={{
                width: 32, height: 32, flexShrink: 0,
                background: item.color + "18",
                border: `1px solid ${item.color}44`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: 13, color: item.color,
                clipPath: "polygon(0 0, calc(100% - 5px) 0, 100% 5px, 100% 100%, 0 100%)",
              }}>
                {item.glyph}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: SZ.small, fontWeight: 700, color: T.text0, ...MONO, letterSpacing: "0.08em", marginBottom: 3 }}>
                  {item.title}
                </div>
                <div style={{ fontSize: SZ.small, color: T.text2, ...INTER, lineHeight: "1.55" }}>
                  {item.body}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Actions */}
        <div style={{ padding: "16px 32px 28px", display: "flex", gap: 10, alignItems: "center" }}>
          {content.cta_primary?.view && (
            <button
              onClick={() => { markWelcomeSeen(currentUser?.id); onNavigate(content.cta_primary.view); onDismiss(); }}
              style={{
                flex: 1, padding: "10px 0",
                background: accentColor + "18",
                border: `1px solid ${accentColor}`,
                color: accentColor,
                fontSize: SZ.small, fontWeight: 700, ...MONO, letterSpacing: "0.1em",
                cursor: "pointer", transition: "all 0.12s",
                clipPath: "polygon(0 0, calc(100% - 6px) 0, 100% 6px, 100% 100%, 0 100%)",
              }}
              onMouseEnter={e => { e.currentTarget.style.background = accentColor + "30"; }}
              onMouseLeave={e => { e.currentTarget.style.background = accentColor + "18"; }}>
              {content.cta_primary.label}
            </button>
          )}
          <button
            onClick={() => {
              markWelcomeSeen(currentUser?.id);
              if (content.cta_secondary?.view) onNavigate(content.cta_secondary.view);
              onDismiss();
            }}
            style={{
              flex: content.cta_primary?.view ? "0 0 auto" : 1,
              padding: "10px 18px",
              background: "none",
              border: `1px solid ${T.border2}`,
              color: T.text2,
              fontSize: SZ.small, fontWeight: 500, ...MONO, letterSpacing: "0.08em",
              cursor: "pointer", transition: "all 0.12s",
            }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = T.text2; e.currentTarget.style.color = T.text0; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = T.border2; e.currentTarget.style.color = T.text2; }}>
            {content.cta_secondary?.label || "Got it"}
          </button>
        </div>

      </div>
    </div>
  );
};

// ── SCREEN HINT BANNER ─────────────────────────────────────────
const ScreenHintBanner = ({ userId, view, onDismiss }) => {
  const hint = SCREEN_HINTS[view];
  // Hooks MUST come before any conditional returns (Rules of Hooks)
  const [visible, setVisible] = useState(true);
  useEffect(() => {
    if (hint && shouldShowHint(userId, view)) {
      bumpScreenHint(userId, view);
    }
  }, [view]);

  if (!hint || !shouldShowHint(userId, view)) return null;
  if (!visible) return null;

  const dismiss = () => { setVisible(false); if (onDismiss) onDismiss(); };

  return (
    <div style={{
      display: "flex", alignItems: "center", justifyContent: "space-between",
      gap: 12, padding: "8px 20px",
      background: T.blueDim,
      borderBottom: `1px solid ${T.blue}33`,
      flexShrink: 0,
      animation: "toast-in 0.2s ease",
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <span style={{ color: T.blue, fontSize: 11, flexShrink: 0 }}>◈</span>
        <span style={{ fontSize: SZ.small, color: T.text1, ...INTER, lineHeight: "1.4" }}>
          {hint}
        </span>
      </div>
      <button onClick={dismiss}
        style={{ background: "none", border: "none", color: T.text3, cursor: "pointer", fontSize: 13, padding: "0 4px", flexShrink: 0, lineHeight: 1 }}
        onMouseEnter={e => { e.currentTarget.style.color = T.text1; }}
        onMouseLeave={e => { e.currentTarget.style.color = T.text3; }}>
        ✕
      </button>
    </div>
  );
};
