// ── Manual Form Builder ────────────────────────────────────────
// Mirrors FormReviewScreen but starts blank — no AI intake required
const ManualFormScreen = ({ currentUser, onSave, onBack }) => {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [category, setCategory] = useState("custom");
  const [saving, setSaving] = useState(false);
  const [saveError, setSaveError] = useState("");
  const [showFormPreview, setShowFormPreview] = useState(false);
  const [showEmailPreview, setShowEmailPreview] = useState(false);
  const [showUnsavedGuard, setShowUnsavedGuard] = useState(false);
  const [firmName, setFirmName] = useState("");
  const [firmLogoUrl, setFirmLogoUrl] = useState(null);
  const editor = useFormEditor([]);
  const { fields, addField, addSection, validateFields } = editor;

  const hasChanges = name.trim().length > 0 || fields.length > 0;
  const handleBack = () => { if (hasChanges) { setShowUnsavedGuard(true); } else { onBack(); } };

  useEffect(() => {
    api.getFirmSettings(currentUser?.firm_id).then(d => {
      if (d?.name) setFirmName(d.name);
      if (d?.settings?.logo_path) setFirmLogoUrl(getFirmAssetUrl(d.settings.logo_path));
    }).catch(() => {});
  }, [currentUser?.firm_id]);

  const totalFields = fields.filter(f => f.field_type !== "section_header").length;
  const piiFields   = fields.filter(f => f.is_pii).length;
  const reqFields   = fields.filter(f => f.is_required).length;

  const handleSave = async () => {
    const err = validateFields();
    if (err) { setSaveError(err); return; }
    if (!name.trim()) { setSaveError("Form name is required."); return; }
    if (fields.length === 0) { setSaveError("Add at least one field before saving."); return; }
    setSaving(true); setSaveError("");
    try {
      const schema = { name: name.trim(), description: description.trim(), category, fields };
      const saved = await api.saveFormFromIntake(currentUser.firm_id, currentUser.id, null, schema, "Manually created");
      onSave(saved);
    } catch (err) {
      setSaveError(err.message || "Failed to save form. Try again.");
      setSaving(false);
    }
  };

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100%", overflow:"hidden" }}>
      {showFormPreview && <FormPreviewModal fields={fields} formName={name} firmName={firmName} firmLogoUrl={firmLogoUrl} onClose={() => setShowFormPreview(false)}/>}
      {showEmailPreview && <EmailPreviewModal formName={name} firmName={firmName} firmLogoUrl={firmLogoUrl} onClose={() => setShowEmailPreview(false)}/>}
      {showUnsavedGuard && <UnsavedChangesModal onLeave={onBack} onStay={()=>setShowUnsavedGuard(false)}/>}

      {/* Top bar */}
      <div style={{ padding:"16px 24px", borderBottom:`1px solid ${T.border1}`, display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0 }}>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <button onClick={handleBack} style={{ background:"none", border:"none", color:T.text3, cursor:"pointer", fontSize:SZ.small, ...MONO, letterSpacing:"0.08em", padding:"4px 8px" }}>← BACK</button>
          <div style={{ width:1, height:16, background:T.border1 }}/>
          <div>
            <div style={{ fontSize:SZ.micro, color:T.blue, ...MONO, letterSpacing:"0.12em" }}>BUILD NEW FORM</div>
            <div style={{ fontSize:SZ.small, color:T.text2 }}>{fields.length} fields · {totalFields} data · {piiFields} PII · {reqFields} required</div>
          </div>
        </div>
        <div style={{ display:"flex", gap:8 }}>
          <Tip text="See exactly what recipients will see">
            <button onClick={() => setShowFormPreview(true)} style={{ padding:"6px 12px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, borderRadius:4, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.06em" }}>👁 PREVIEW FORM</button>
          </Tip>
          <Tip text="See the invitation email">
            <button onClick={() => setShowEmailPreview(true)} style={{ padding:"6px 12px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, borderRadius:4, cursor:"pointer", fontSize:SZ.micro, ...MONO, letterSpacing:"0.06em" }}>✉ PREVIEW EMAIL</button>
          </Tip>
          <button onClick={handleBack} style={{ padding:"7px 16px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, borderRadius:4, cursor:"pointer", fontSize:SZ.small, ...MONO, letterSpacing:"0.08em" }}>DISCARD</button>
          <button onClick={handleSave} disabled={saving} style={{ padding:"7px 20px", background:T.blue, border:"none", color:"#0a0e1a", borderRadius:4, cursor:saving?"not-allowed":"pointer", fontSize:SZ.small, fontWeight:700, ...MONO, letterSpacing:"0.1em" }}>
            {saving ? "◌ SAVING…" : "◉ SAVE FORM"}
          </button>
        </div>
      </div>

      {saveError && (
        <div style={{ margin:"12px 24px 0", background:T.redDim, border:`1px solid ${T.red}44`, borderRadius:4, padding:"10px 14px", fontSize:SZ.small, color:T.red, flexShrink:0 }}>{saveError}</div>
      )}

      {/* Meta fields */}
      <div style={{ padding:"20px 24px 0", flexShrink:0 }}>
        <div style={{ display:"flex", gap:16, marginBottom:12 }}>
          <div style={{ flex:2 }}>
            <div style={{ fontSize:SZ.label, color:T.text3, ...MONO, letterSpacing:"0.08em", marginBottom:6 }}>FORM NAME</div>
            <input value={name} onChange={e=>setName(e.target.value)} placeholder="e.g. New Client Onboarding, Annual Review Checklist…"
              style={{ width:"100%", background:T.bg3, border:`1px solid ${T.border2}`, borderRadius:4, color:T.text0, padding:"8px 12px", fontSize:SZ.body, ...INTER, outline:"none", boxSizing:"border-box" }}/>
          </div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:SZ.label, color:T.text3, ...MONO, letterSpacing:"0.08em", marginBottom:6 }}>CATEGORY</div>
            <select value={category} onChange={e=>setCategory(e.target.value)}
              style={{ width:"100%", background:T.bg3, border:`1px solid ${T.border2}`, borderRadius:4, color:T.blue, padding:"8px 12px", fontSize:SZ.small, ...MONO, letterSpacing:"0.06em", outline:"none", cursor:"pointer" }}>
              {FORM_CATEGORIES.map(c => (<option key={c} value={c}>{c.replace(/_/g," ").toUpperCase()}</option>))}
            </select>
          </div>
        </div>
        <div style={{ marginBottom:12 }}>
          <div style={{ fontSize:SZ.label, color:T.text3, ...MONO, letterSpacing:"0.08em", marginBottom:6 }}>DESCRIPTION</div>
          <input value={description} onChange={e=>setDescription(e.target.value)} placeholder="Optional — describe this form's purpose"
            style={{ width:"100%", background:T.bg3, border:`1px solid ${T.border2}`, borderRadius:4, color:T.text1, padding:"8px 12px", fontSize:SZ.small, ...INTER, outline:"none", boxSizing:"border-box" }}/>
        </div>
      </div>

      {/* Fields area */}
      <div style={{ padding:"8px 24px 4px", flexShrink:0, borderBottom:`1px solid ${T.border0}`, background:T.bg1 }}>
        <FieldsToolbar onAddField={addField} onAddSection={addSection}/>
      </div>

      {fields.length === 0 ? (
        <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:14, color:T.text3 }}>
          <div style={{ fontSize:36 }}>◫</div>
          <div style={{ fontSize:SZ.body, color:T.text2 }}>No fields yet</div>
          <div style={{ fontSize:SZ.small, color:T.text3 }}>Use the toolbar above to add your first field or section.</div>
          <div style={{ display:"flex", gap:10, marginTop:4 }}>
            <button onClick={addField} style={{ padding:"8px 18px", background:T.blue, border:"none", color:"#0a0e1a", borderRadius:4, cursor:"pointer", fontSize:SZ.small, fontWeight:700, ...MONO, letterSpacing:"0.1em" }}>+ ADD FIELD</button>
            <button onClick={addSection} style={{ padding:"8px 18px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, borderRadius:4, cursor:"pointer", fontSize:SZ.small, ...MONO, letterSpacing:"0.08em" }}>+ ADD SECTION</button>
          </div>
        </div>
      ) : (
        <div style={{ flex:1, overflowY:"auto", padding:"8px 24px 24px" }}>
          <FieldsList fields={fields} editor={editor}/>
        </div>
      )}
    </div>
  );
};

