// ── FORM DETAIL VIEW ───────────────────────────────────────────
// Opened when clicking a saved form in the library.
// Loads live fields from Supabase, supports full editing + archive.
const FORM_HELP_ITEMS = [
  { icon:"▣", title:"Field Types", body:"Text — short answers. Long Text — paragraphs. Dropdown — pick one from a list. Multi-Select — pick multiple. Yes/No — boolean toggle. Date — date picker. File Upload — document or image. Signature — sign in browser. Address — structured address entry." },
  { icon:"◈", title:"Section Headers", body:"Divide your form into named sections. Recipients see section names as visual dividers. Sections don't collect data — they only organize the layout." },
  { icon:"⚑", title:"Required Fields", body:"Recipients cannot submit the form until all required fields are filled in. Use sparingly — too many required fields increases abandon rate." },
  { icon:"🔒", title:"PII / Sensitive", body:"Mark fields containing personal data: name, date of birth, SSN, address, phone, email, financial info. PII fields are encrypted at rest in the database. Required for compliance." },
  { icon:"▲▼", title:"Reordering", body:"Use the ▲▼ arrows on any field or section to change the order. Order is saved when you click Save Changes." },
  { icon:"✕", title:"Deleting Fields", body:"Individual fields show a confirmation step before deleting. Section headers delete immediately — be careful, this cannot be undone." },
  { icon:"◫", title:"Saving", body:"Changes are not saved automatically. Click Save Changes in the top right when you're done editing. Navigating away without saving will prompt a warning." },
  { icon:"👁", title:"Preview", body:"Use Preview Form to see exactly what recipients will see. Use Preview Email to see the invitation email. Always preview before sending." },
];

// Form preview modal — renders form exactly as recipient sees it
const FormPreviewModal = ({ fields, formName, firmName, firmLogoUrl, onClose }) => {
  const [responses, setResponses] = useState({});
  const setValue = (key, val) => setResponses(p => ({...p, [key]: val}));

  const isFieldVisible = (f) => {
    if (!f.show_if?.field_key) return true;
    const { field_key, condition, value } = f.show_if;
    const sourceVal = responses[field_key];
    switch (condition) {
      case "is": return String(sourceVal||"") === String(value||"");
      case "is_not": return String(sourceVal||"") !== String(value||"");
      case "includes": return Array.isArray(sourceVal) ? sourceVal.includes(value) : String(sourceVal||"").includes(value||"");
      case "is_answered": return sourceVal !== undefined && sourceVal !== null && sourceVal !== "" && !(Array.isArray(sourceVal) && sourceVal.length === 0);
      case "is_not_answered": return sourceVal === undefined || sourceVal === null || sourceVal === "" || (Array.isArray(sourceVal) && sourceVal.length === 0);
      default: return true;
    }
  };

  const base = { width:"100%", background:"#141518", border:"1px solid #282b30", borderRadius:6, color:"#c8cacf", padding:"10px 14px", fontSize:"0.9375rem", fontFamily:"'Inter',system-ui,sans-serif", outline:"none", boxSizing:"border-box", transition:"border-color 0.15s" };
  const focusStyle = (e) => e.target.style.borderColor = "#5b9fd4";
  const blurStyle  = (e) => e.target.style.borderColor = "#282b30";

  const renderField = (f) => {
    const val = responses[f.field_key] ?? "";
    switch(f.field_type) {
      case "textarea": return <textarea value={val} onChange={e=>setValue(f.field_key,e.target.value)} onFocus={focusStyle} onBlur={blurStyle} rows={3} style={{...base,resize:"vertical"}}/>;
      case "boolean": return (
        <div style={{ display:"flex", gap:10 }}>
          {["Yes","No"].map(opt=>(
            <button key={opt} onClick={()=>setValue(f.field_key,opt)} style={{ flex:1, padding:"10px", background:val===opt?"#0f2233":"#141518", border:`1px solid ${val===opt?"#5b9fd4":"#282b30"}`, borderRadius:6, color:val===opt?"#5b9fd4":"#888b92", cursor:"pointer", fontSize:"0.9375rem", fontFamily:"'Inter',system-ui,sans-serif", transition:"all 0.15s" }}>{opt}</button>
          ))}
        </div>
      );
      case "radio": return (
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          {(f.options||[]).map(o=>(
            <label key={o.value} style={{ display:"flex", alignItems:"center", gap:10, cursor:"pointer", padding:"10px 14px", background:val===o.value?"#0f2233":"#141518", border:`1px solid ${val===o.value?"#5b9fd4":"#282b30"}`, borderRadius:6, transition:"all 0.15s" }}>
              <div style={{ width:16, height:16, borderRadius:"50%", border:`2px solid ${val===o.value?"#5b9fd4":"#3a3d42"}`, background:val===o.value?"#5b9fd4":"transparent", flexShrink:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
                {val===o.value && <div style={{ width:6, height:6, borderRadius:"50%", background:"#0a0e1a" }}/>}
              </div>
              <input type="radio" name={f.field_key} value={o.value} checked={val===o.value} onChange={()=>setValue(f.field_key,o.value)} style={{ display:"none" }}/>
              <span style={{ fontSize:"0.9375rem", color:val===o.value?"#c8cacf":"#888b92", fontFamily:"'Inter',system-ui,sans-serif" }}>{o.label}</span>
            </label>
          ))}
        </div>
      );
      case "select": return (
        <div>
          <select value={val} onChange={e=>setValue(f.field_key,e.target.value)} onFocus={focusStyle} onBlur={blurStyle} style={{...base,cursor:"pointer"}}>
            <option value="">Select an option...</option>
            {(f.options||[]).map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
            {f.include_other && <option value="other">Other</option>}
          </select>
          {f.include_other && val==="other" && <input value={responses[f.field_key+"_other"]||""} onChange={e=>setValue(f.field_key+"_other",e.target.value)} placeholder="Please specify..." onFocus={focusStyle} onBlur={blurStyle} style={{...base,marginTop:8}}/>}
        </div>
      );
      case "multiselect": return (
        <div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
            {(f.options||[]).map(o=>{ const sel=(val||[]).includes(o.value); return <button key={o.value} onClick={()=>{ const cur=val||[]; setValue(f.field_key,sel?cur.filter(v=>v!==o.value):[...cur,o.value]); }} style={{ padding:"8px 16px", background:sel?"#0f2233":"#141518", border:`1px solid ${sel?"#5b9fd4":"#282b30"}`, borderRadius:20, color:sel?"#5b9fd4":"#888b92", cursor:"pointer", fontSize:"0.875rem", fontFamily:"'Inter',system-ui,sans-serif", transition:"all 0.15s" }}>{o.label}</button>; })}
            {f.include_other && (()=>{ const sel=(val||[]).includes("other"); return <button onClick={()=>{ const cur=val||[]; setValue(f.field_key,sel?cur.filter(v=>v!=="other"):[...cur,"other"]); }} style={{ padding:"8px 16px", background:sel?"#0f2233":"#141518", border:`1px solid ${sel?"#5b9fd4":"#282b30"}`, borderRadius:20, color:sel?"#5b9fd4":"#888b92", cursor:"pointer", fontSize:"0.875rem", fontFamily:"'Inter',system-ui,sans-serif", transition:"all 0.15s" }}>Other</button>; })()}
          </div>
          {f.include_other && (val||[]).includes("other") && <input value={responses[f.field_key+"_other"]||""} onChange={e=>setValue(f.field_key+"_other",e.target.value)} placeholder="Please specify..." onFocus={focusStyle} onBlur={blurStyle} style={{...base,marginTop:8}}/>}
        </div>
      );
      case "repeating_group": {
        const entries = (Array.isArray(val) && val.length > 0) ? val : [Object.fromEntries((f.sub_fields||[]).map(sf=>[sf.field_key,""]))];
        const subFields = f.sub_fields || [];
        if (!subFields.length) return <div style={{ color:"#555860", fontSize:"0.875rem" }}>No sub-fields configured.</div>;
        return (
          <div>
            {entries.map((entry,ei)=>(
              <div key={ei} style={{ background:"#0e1218", border:"1px solid #1e2228", borderRadius:6, padding:"12px 14px", marginBottom:10 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
                  <span style={{ fontSize:"0.8125rem", color:"#5b9fd4", fontFamily:"'JetBrains Mono',monospace", fontWeight:700, letterSpacing:"0.08em" }}>ENTRY {ei+1}</span>
                  <button onClick={()=>{ const e2=entries.filter((_,i)=>i!==ei); setValue(f.field_key,e2); }} style={{ background:"none", border:"1px solid #2a2d32", borderRadius:3, color:"#888b92", cursor:"pointer", fontSize:"0.75rem", padding:"2px 8px" }}>Remove</button>
                </div>
                {subFields.map((sf,sfi)=>(
                  <div key={sfi} style={{ marginBottom:sfi<subFields.length-1?10:0 }}>
                    <label style={{ display:"block", fontSize:"0.875rem", color:"#c8cacf", fontWeight:500, marginBottom:6 }}>{sf.label}</label>
                    {(sf.field_type==="select"||sf.field_type==="radio") && (sf.options||[]).length > 0
                      ? <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
                          {(sf.options||[]).map(o=>{ const sel=entry[sf.field_key]===o.value; return <button key={o.value} onClick={()=>{ const ne=[...entries]; ne[ei]={...ne[ei],[sf.field_key]:o.value}; setValue(f.field_key,ne); }} style={{ padding:"6px 14px", background:sel?"#0f2233":"#141518", border:`1px solid ${sel?"#5b9fd4":"#282b30"}`, borderRadius:sf.field_type==="radio"?20:4, color:sel?"#5b9fd4":"#888b92", cursor:"pointer", fontSize:"0.875rem", fontFamily:"'Inter',system-ui,sans-serif", transition:"all 0.15s" }}>{o.label}</button>; })}
                        </div>
                      : <input type={sf.field_type==="date"?"date":sf.field_type==="number"?"number":sf.field_type==="email"?"email":sf.field_type==="phone"?"tel":"text"} value={entry[sf.field_key]||""} onChange={e=>{ const ne=[...entries]; ne[ei]={...ne[ei],[sf.field_key]:e.target.value}; setValue(f.field_key,ne); }} onFocus={focusStyle} onBlur={blurStyle} style={base}/>
                    }
                  </div>
                ))}
              </div>
            ))}
            <button
              onClick={()=>{ const ne={}; (f.sub_fields||[]).forEach(sf=>{ne[sf.field_key]="";}); setValue(f.field_key,[...entries,ne]); }}
              style={{ width:"100%", padding:"10px", background:"transparent", border:"1px dashed #282b30", borderRadius:6, color:"#5b9fd4", cursor:"pointer", fontSize:"0.875rem", fontFamily:"'Inter',system-ui,sans-serif" }}
              onMouseEnter={e=>{e.target.style.borderColor="#5b9fd4";e.target.style.background="#0f1a24";}}
              onMouseLeave={e=>{e.target.style.borderColor="#282b30";e.target.style.background="transparent";}}>
              + {f.add_button_label || ("Add " + (f.label || "entry"))}
            </button>
          </div>
        );
      }
      case "file": return <div style={{...base,color:"#555860",cursor:"pointer",textAlign:"center"}}>File upload</div>;
      case "signature": return <div style={{...base,height:80,display:"flex",alignItems:"center",justifyContent:"center",color:"#555860"}}>Signature area</div>;
      case "address": return (
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          <input placeholder="Street address" onFocus={focusStyle} onBlur={blurStyle} style={base}/>
          <div style={{ display:"flex", gap:8 }}>
            <input placeholder="City" onFocus={focusStyle} onBlur={blurStyle} style={{...base,flex:2}}/>
            <input placeholder="State" onFocus={focusStyle} onBlur={blurStyle} style={{...base,flex:1}}/>
            <input placeholder="ZIP" onFocus={focusStyle} onBlur={blurStyle} style={{...base,flex:1}}/>
          </div>
        </div>
      );
      default: return <input type={f.field_type==="email"?"email":f.field_type==="phone"?"tel":f.field_type==="date"?"date":f.field_type==="number"?"number":"text"} value={val} onChange={e=>setValue(f.field_key,e.target.value)} onFocus={focusStyle} onBlur={blurStyle} placeholder={f.placeholder||""} style={base}/>;
    }
  };

  const sections = [];
  let cur = null;
  for(const f of (fields||[])) {
    if(f.field_type==="section_header"){ cur={header:f,fields:[]}; sections.push(cur); }
    else { if(!cur){cur={header:null,fields:[]};sections.push(cur);} cur.fields.push(f); }
  }

  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(7,8,10,0.9)", zIndex:2000, display:"flex", alignItems:"flex-start", justifyContent:"center", padding:"24px 24px 48px", overflowY:"auto" }}>
      <div style={{ width:"100%", maxWidth:680, background:"#07080a", border:"1px solid #1a1c20", borderRadius:8, overflow:"hidden" }}>
        <div style={{ background:"#0a0e14", borderBottom:"1px solid #1a1c20", padding:"12px 24px", display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <span style={{ fontSize:"0.6875rem", color:"#ffaa00", fontFamily:"'JetBrains Mono',monospace", letterSpacing:"0.12em", background:"rgba(255,170,0,0.08)", border:"1px solid rgba(255,170,0,0.25)", borderRadius:3, padding:"2px 8px" }}>PREVIEW MODE</span>
            <span style={{ fontSize:"0.8125rem", color:"#5a7a8a" }}>Conditional logic is live — interact to test</span>
          </div>
          <button onClick={onClose} style={{ background:"none", border:"none", color:"#5a7a8a", cursor:"pointer", fontSize:18 }}>x</button>
        </div>
        <div style={{ padding:"40px 48px", minHeight:400 }}>
          <div style={{ marginBottom:32 }}>
            {firmLogoUrl ? <img src={firmLogoUrl} alt={firmName} style={{ maxHeight:48, maxWidth:200, objectFit:"contain", marginBottom:16, display:"block" }}/> : <div style={{ fontSize:"0.6875rem", color:"#555860", fontFamily:"'JetBrains Mono',monospace", letterSpacing:"0.12em", marginBottom:8 }}>{firmName}</div>}
            <div style={{ fontSize:"1.5rem", color:"#f0f1f3", fontWeight:600, marginBottom:12 }}>{formName}</div>
            <div style={{ width:40, height:2, background:"#5b9fd4", borderRadius:1 }}/>
          </div>
          {sections.map((sec,si)=>(
            <div key={si} style={{ marginBottom:32 }}>
              {sec.header && <div style={{ fontSize:"0.8125rem", color:"#5b9fd4", fontFamily:"'JetBrains Mono',monospace", fontWeight:700, letterSpacing:"0.1em", marginBottom:16, paddingBottom:8, borderBottom:"1px solid #1e2024" }}>{sec.header.label}</div>}
              {sec.fields.map((f,fi)=>{
                if (!isFieldVisible(f)) return null;
                return (
                  <div key={fi} style={{ marginBottom:20 }}>
                    <div style={{ fontSize:"0.9375rem", color:"#c8cacf", fontWeight:500, marginBottom:6 }}>
                      {f.label}{f.is_required && <span style={{ color:"#d44f42", marginLeft:4 }}>*</span>}
                    </div>
                    {f.help_text && <div style={{ fontSize:"0.8125rem", color:"#555860", marginBottom:6 }}>{f.help_text}</div>}
                    {renderField(f)}
                  </div>
                );
              })}
            </div>
          ))}
          <button style={{ width:"100%", padding:"14px", background:"#5b9fd4", border:"none", color:"#0a0e1a", borderRadius:4, cursor:"not-allowed", fontSize:"0.9375rem", fontWeight:700, fontFamily:"'Inter',system-ui,sans-serif", marginTop:8, opacity:0.6 }}>
            Submit Form (Preview Only)
          </button>
        </div>
      </div>
    </div>
  );
};

