// Main SetupWizard component
const SetupWizard = ({ currentUser, firmId, firmName, onComplete }) => {
  const [step, setStep] = useState(1);
  const [firmConfig, setFirmConfig] = useState({});
  const [advisorPipeline, setAdvisorPipeline] = useState(null);
  const [clientPipeline, setClientPipeline] = useState(null);
  const [saving, setSaving] = useState(false);

  const commitAndFinish = async () => {
    setSaving(true);
    try {
      // Save firm knowledge base to firm settings
      const existing = await api.getFirmSettings(firmId).catch(()=>({settings:{}}));
      const settings = {
        ...(existing?.settings||{}),
        setup_completed: true,
        bd_name: firmConfig.bd_name || null,
        custodians: firmConfig.custodians || [],
        location: firmConfig.location || null,
        specialty: firmConfig.specialty || null,
        workflow_context: null,
      };
      await api.updateFirmSettings(firmId, settings);

      // Commit advisor pipeline if configured
      if (advisorPipeline?.stages?.length) {
        const pipe = await pipelineApi.createPipeline(firmId, currentUser.id, advisorPipeline.pipeline_name||"Advisor Pipeline", "prospect", null);
        const stageRows = advisorPipeline.stages.map((s,i) => ({
          pipeline_id:pipe.id, firm_id:firmId,
          name:s.name, sequence_order:i+1, color:s.color||PIPELINE_STAGE_COLORS[i%PIPELINE_STAGE_COLORS.length],
          default_waiting_on:s.default_waiting_on||"advisor", sla_days:s.sla_days||null,
          is_won:s.is_won||false, is_lost:s.is_lost||false,
        }));
        await pipelineApi.createStages(stageRows);
      }

      // Commit client pipeline if configured
      if (clientPipeline?.stages?.length) {
        const pipe = await pipelineApi.createPipeline(firmId, currentUser.id, clientPipeline.pipeline_name||"Client Pipeline", "client", null);
        const stageRows = clientPipeline.stages.map((s,i) => ({
          pipeline_id:pipe.id, firm_id:firmId,
          name:s.name, sequence_order:i+1, color:s.color||PIPELINE_STAGE_COLORS[i%PIPELINE_STAGE_COLORS.length],
          default_waiting_on:s.default_waiting_on||"advisor", sla_days:s.sla_days||null,
          is_won:s.is_won||false, is_lost:s.is_lost||false,
        }));
        await pipelineApi.createStages(stageRows);
      }
    } catch(e) { console.error("Setup commit error:", e); }
    finally { setSaving(false); }
    onComplete(firmConfig);
  };

  return (
    <div style={{ position:"fixed", inset:0, background:T.bg0, zIndex:10000, display:"flex", flexDirection:"column", overflow:"hidden" }}>
      {/* Subtle grid background */}
      <div style={{ position:"absolute", inset:0, backgroundImage:`linear-gradient(${T.border0}66 1px, transparent 1px), linear-gradient(90deg, ${T.border0}66 1px, transparent 1px)`, backgroundSize:"48px 48px", pointerEvents:"none" }}/>

      {/* Header */}
      <div style={{ position:"relative", zIndex:1, padding:"20px 32px", borderBottom:`1px solid ${T.border1}`, display:"flex", alignItems:"center", justifyContent:"space-between", flexShrink:0 }}>
        <div style={{ display:"flex", alignItems:"center", gap:12 }}>
          <F22Mark size={22} color={T.blue}/>
          <span style={{ fontSize:SZ.small, fontWeight:700, color:T.blue, ...MONO, letterSpacing:"0.16em" }}>ADVISORHUD · FIRM SETUP</span>
        </div>
        <div style={{ fontSize:SZ.label, color:T.text3, ...MONO }}>Step {step} of {SETUP_STEPS.length}</div>
      </div>

      {/* Body */}
      <div style={{ position:"relative", zIndex:1, flex:1, overflow:"auto", padding:"40px 60px 40px" }}>
        <SetupStepBar currentStep={step}/>

        {step === 1 && (
          <StepFirm
            onComplete={cfg => { setFirmConfig(cfg); setStep(2); }}
            onSkip={() => setStep(2)}
          />
        )}
        {step === 2 && (
          <div style={{ maxWidth:600 }}>
            <h2 style={{ fontSize:SZ.title, fontWeight:700, color:T.text0, ...INTER, marginBottom:8 }}>Your team.</h2>
            <p style={{ fontSize:SZ.body, color:T.text2, ...INTER, lineHeight:1.7, marginBottom:28 }}>
              You can add team members now or after setup. Anyone you invite will get an email to set their password and access AdvisorHUD based on their role.
            </p>
            <div style={{ background:T.bg2, border:`1px solid ${T.border1}`, borderLeft:`3px solid ${T.blue}`, padding:"14px 18px", marginBottom:24 }}>
              <div style={{ fontSize:SZ.small, color:T.text1, ...INTER, lineHeight:1.6 }}>
                You can invite your team from <strong style={{color:T.text0}}>Firm Admin → Users</strong> at any time. Role descriptions are there too — so you can think through who gets what access before sending invites.
              </div>
            </div>
            <div style={{ display:"flex", gap:12 }}>
              <button onClick={()=>setStep(3)}
                style={{ padding:"10px 28px", background:T.blue, border:"none", color:"#000", fontSize:SZ.small, fontWeight:700, ...INTER, cursor:"pointer" }}>
                Continue →
              </button>
              <button onClick={()=>setStep(3)}
                style={{ padding:"10px 20px", background:"transparent", border:`1px solid ${T.border2}`, color:T.text2, cursor:"pointer", fontSize:SZ.small, ...INTER }}>
                Skip
              </button>
            </div>
          </div>
        )}
        {step === 3 && (
          <StepPipeline
            type="advisor"
            onComplete={cfg => { setAdvisorPipeline(cfg); setStep(4); }}
            onSkip={() => setStep(4)}
          />
        )}
        {step === 4 && (
          <StepPipeline
            type="client"
            onComplete={cfg => { setClientPipeline(cfg); setStep(5); }}
            onSkip={() => setStep(5)}
          />
        )}
        {step === 5 && (
          <StepLaunch
            firmConfig={firmConfig}
            onComplete={commitAndFinish}
          />
        )}
      </div>

      {/* Privacy notice when voice is likely active */}
      <div style={{ position:"relative", zIndex:1, padding:"10px 32px", borderTop:`1px solid ${T.border0}`, textAlign:"center" }}>
        <span style={{ fontSize:SZ.micro, color:T.text3, ...INTER }}>
          🎙 Voice is processed locally in your browser and never recorded or stored by AdvisorHUD.
        </span>
      </div>
    </div>
  );
};

