// ── HUD COMMAND — SOURCE HELPERS ────────────────────────────────
const SRC_META = {
  pdl:      { label:'PDL',      color:'#5b9fd4', bg:'rgba(91,159,212,0.10)',  title:'People Data Labs — confirmed professional data' },
  google:   { label:'GOOGLE',   color:'#7ba7e0', bg:'rgba(123,167,224,0.10)', title:'Google search — web presence & public record' },
  news:     { label:'NEWS',     color:'#9b7dc8', bg:'rgba(155,125,200,0.10)', title:'News article — public record' },
  sec:      { label:'SEC',      color:'#3dba7a', bg:'rgba(61,186,122,0.10)',  title:'SEC EDGAR filing — regulatory record' },
  finra:    { label:'FINRA',    color:'#38b8b0', bg:'rgba(56,184,176,0.10)',  title:'FINRA BrokerCheck — registration & disclosure record' },
  website:  { label:'WEBSITE',  color:'#c8b840', bg:'rgba(200,184,64,0.10)',  title:"Company's own website — primary source" },
  attom:    { label:'ATTOM',    color:'#e07b5b', bg:'rgba(224,123,91,0.10)',  title:'ATTOM property records — ownership, assessed value, sale price' },
  court:    { label:'COURT',    color:'#c45c8a', bg:'rgba(196,92,138,0.10)',  title:'CourtListener — federal court record (PACER-indexed)' },
  inferred: { label:'INFERRED', color:'#e09d3a', bg:'rgba(224,157,58,0.10)',  title:'Logically derived — treat as hypothesis' },
  unknown:  { label:'UNKNOWN',  color:'#555860', bg:'rgba(85,88,96,0.10)',    title:'Insufficient data to source this claim' },
};

const SrcChip = ({ src, style={} }) => {
  const m = SRC_META[src] || SRC_META.unknown;
  return (
    <span title={m.title} style={{
      display:'inline-flex', alignItems:'center',
      fontSize:'8px', fontWeight:700, letterSpacing:'0.08em',
      color:m.color, background:m.bg, border:`1px solid ${m.color}30`,
      padding:'1px 5px', marginLeft:5, verticalAlign:'middle',
      fontFamily:"'JetBrains Mono',monospace",
      cursor:'default', whiteSpace:'nowrap', flexShrink:0, ...style,
    }}>{m.label}</span>
  );
};

const stripSrc = (s) => typeof s === 'string' ? s.replace(/\[src:[a-z]+\]/g, '').replace(/\s{2,}/g,' ').trim() : s;
const fieldVal = (f) => { if (!f) return null; if (typeof f === 'object' && 'value' in f) return f.value; return f; };
const fieldSrc = (f) => (f && typeof f === 'object') ? f.source : null;
const cleanField = (f) => { const raw = fieldVal(f); if (!raw || typeof raw !== 'string') return '—'; return stripSrc(raw); };

// AnnotatedText: strips inline src tags, collects unique sources,
// emits clean prose with a single compound chip at the end per paragraph.
const CompoundSrcChip = ({ sources }) => {
  if (!sources || sources.length === 0) return null;
  const unique = [...new Set(sources)].filter(s => SRC_META[s]);
  if (!unique.length) return null;
  return (
    <span style={{ display:'inline-flex', alignItems:'center', gap:3, marginLeft:6, verticalAlign:'middle' }}>
      {unique.map(s => {
        const m = SRC_META[s];
        return (
          <span key={s} title={m.title} style={{
            fontSize:'7px', fontWeight:700, letterSpacing:'0.07em',
            color:m.color, background:m.bg, border:`1px solid ${m.color}28`,
            padding:'1px 4px', fontFamily:"'JetBrains Mono',monospace",
            cursor:'default', whiteSpace:'nowrap',
          }}>{m.label}</span>
        );
      })}
    </span>
  );
};

// Extract all [src:xxx] tags from a string as an array of source keys
const extractSrcs = (s) => {
  if (!s || typeof s !== 'string') return [];
  const matches = [...s.matchAll(/\[src:([a-z]+)\]/g)];
  return matches.map(m => m[1]);
};

// Render a narrative field: clean prose, compound chip at end of each paragraph
const AnnotatedText = ({ text, fontSize='13px', color, lineHeight=1.75 }) => {
  if (!text || typeof text !== 'string') return <span style={{ color:color||T.text1 }}>—</span>;
  // Split into paragraphs (double newline) or treat as single block
  const paras = text.split(/\n{2,}/).filter(Boolean);
  if (paras.length <= 1) {
    // Single block: strip tags, emit compound chip at end
    const srcs = extractSrcs(text);
    const clean = text.replace(/\[src:[a-z]+\]/g, '').replace(/\s{2,}/g, ' ').trim();
    return (
      <span style={{ fontSize, color:color||T.text1, lineHeight, fontFamily:'Inter,system-ui,sans-serif' }}>
        {clean}<CompoundSrcChip sources={srcs}/>
      </span>
    );
  }
  return (
    <span style={{ fontSize, color:color||T.text1, lineHeight, fontFamily:'Inter,system-ui,sans-serif' }}>
      {paras.map((para, i) => {
        const srcs = extractSrcs(para);
        const clean = para.replace(/\[src:[a-z]+\]/g, '').replace(/\s{2,}/g, ' ').trim();
        return (
          <span key={i} style={{ display:'block', marginBottom: i < paras.length-1 ? '0.75em' : 0 }}>
            {clean}<CompoundSrcChip sources={srcs}/>
          </span>
        );
      })}
    </span>
  );
};

